export const questions: Question[] = [
  // =============================================
  // TECIDO EPITELIAL (1-50)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 1, topic: "Tecido Epitelial", question: "Qual tipo de epitélio reveste a traqueia?", options: ["Epitélio simples pavimentoso", "Epitélio pseudoestratificado cilíndrico ciliado", "Epitélio estratificado pavimentoso queratinizado", "Epitélio de transição"], correctIndex: 1, explanation: "A traqueia é revestida por epitélio pseudoestratificado cilíndrico ciliado com células caliciformes, fundamental para a defesa mucociliar das vias aéreas." },
  { id: 2, topic: "Tecido Epitelial", question: "Qual epitélio reveste os alvéolos pulmonares?", options: ["Epitélio simples pavimentoso", "Epitélio simples cúbico", "Epitélio pseudoestratificado", "Epitélio estratificado pavimentoso"], correctIndex: 0, explanation: "Os alvéolos são revestidos por epitélio simples pavimentoso (pneumócitos tipo I), extremamente delgado para facilitar as trocas gasosas." },
  { id: 3, topic: "Tecido Epitelial", question: "O epitélio de transição (urotélio) é encontrado em qual estrutura?", options: ["Esôfago", "Bexiga urinária", "Intestino delgado", "Pele"], correctIndex: 1, explanation: "O urotélio reveste a bexiga urinária e vias urinárias, possuindo células em guarda-chuva que permitem distensão sem comprometer a barreira." },
  { id: 4, topic: "Tecido Epitelial", question: "Qual especialização apical aumenta a superfície de absorção no intestino delgado?", options: ["Cílios", "Estereocílios", "Microvilosidades", "Flagelos"], correctIndex: 2, explanation: "As microvilosidades formam a borda em escova do intestino delgado, aumentando enormemente a superfície de absorção dos enterócitos." },
  { id: 5, topic: "Tecido Epitelial", question: "As junções tight (zônulas de oclusão) estão localizadas em qual posição no epitélio?", options: ["Basal", "Lateral intermediária", "Apical (mais luminal)", "Entre epitélio e lâmina basal"], correctIndex: 2, explanation: "As tight junctions localizam-se na porção mais apical da membrana lateral, vedando o espaço intercelular e regulando a permeabilidade paracelular." },
  { id: 6, topic: "Tecido Epitelial", question: "Qual tipo de secreção glandular envolve a liberação total da célula?", options: ["Merócrina", "Apócrina", "Holócrina", "Parácrina"], correctIndex: 2, explanation: "Na secreção holócrina, a célula inteira se desintegra para liberar seu conteúdo. O exemplo clássico é a glândula sebácea da pele." },
  { id: 7, topic: "Tecido Epitelial", question: "Os estereocílios diferem dos cílios verdadeiros porque:", options: ["Possuem axonema 9+2", "São prolongamentos longos e imóveis de microvilosidades", "Contêm dineína", "São mais curtos que microvilosidades"], correctIndex: 1, explanation: "Estereocílios são microvilosidades longas e ramificadas, imóveis, sem axonema. São encontrados no epidídimo e células ciliadas do ouvido interno." },
  { id: 8, topic: "Tecido Epitelial", question: "Qual proteína forma a base estrutural dos hemidesmossomos?", options: ["Caderinas", "Integrinas", "Conexinas", "Claudinas"], correctIndex: 1, explanation: "Os hemidesmossomos utilizam integrinas (α6β4) para ancorar a célula epitelial à lâmina basal, conectando-se a filamentos intermediários de queratina." },
  { id: 9, topic: "Tecido Epitelial", question: "Na classificação dos epitélios estratificados, a denominação se baseia na camada:", options: ["Basal", "Intermediária", "Superficial", "Mais espessa"], correctIndex: 2, explanation: "A classificação dos epitélios estratificados é baseada na morfologia das células da camada mais superficial (pavimentoso, cúbico ou cilíndrico)." },
  { id: 10, topic: "Tecido Epitelial", question: "As células caliciformes secretam qual tipo de substância?", options: ["Enzimas proteolíticas", "Mucinas (glicoproteínas)", "Hormônios peptídicos", "Surfactante"], correctIndex: 1, explanation: "As células caliciformes são glândulas unicelulares que secretam mucinas por exocitose (secreção merócrina), formando o muco que protege as mucosas." },
  { id: 11, topic: "Tecido Epitelial", question: "A lâmina basal é composta principalmente por:", options: ["Colágeno tipo I e fibronectina", "Colágeno tipo IV, laminina e proteoglicanos", "Elastina e fibrilina", "Colágeno tipo III e reticulina"], correctIndex: 1, explanation: "A lâmina basal contém colágeno tipo IV (rede), laminina (glicoproteína de adesão), entactina/nidogênio e proteoglicanos (perlecano)." },
  { id: 12, topic: "Tecido Epitelial", question: "Qual epitélio reveste a superfície do ovário?", options: ["Estratificado pavimentoso", "Simples cúbico (mesotélio modificado)", "Pseudoestratificado", "Simples cilíndrico"], correctIndex: 1, explanation: "O ovário é revestido por epitélio simples cúbico, antigamente chamado de 'epitélio germinativo', embora não participe da formação de gametas." },
  { id: 13, topic: "Tecido Epitelial", question: "O mesotélio reveste:", options: ["Vasos sanguíneos", "Cavidades serosas (pleura, peritônio, pericárdio)", "Vias urinárias", "Tubo digestivo"], correctIndex: 1, explanation: "O mesotélio é um epitélio simples pavimentoso de origem mesodérmica que reveste as cavidades serosas, secretando líquido seroso lubrificante." },
  { id: 14, topic: "Tecido Epitelial", question: "A E-caderina é a proteína de adesão presente em qual junção?", options: ["Tight junction", "Zônula de adesão", "Hemidesmossomo", "Gap junction"], correctIndex: 1, explanation: "A E-caderina é a proteína transmembranar da zônula de adesão, conectada intracelularmente a filamentos de actina via cateninas. Sua perda é marcador de carcinomas invasivos." },
  { id: 15, topic: "Tecido Epitelial", question: "As gap junctions são formadas por:", options: ["Claudinas", "Conexinas (formando conexons)", "Integrinas", "Desmogleínas"], correctIndex: 1, explanation: "As gap junctions são formadas por conexinas que se organizam em hexâmeros (conexons), criando canais entre células vizinhas para passagem de íons e moléculas pequenas." },
  { id: 16, topic: "Tecido Epitelial", question: "Qual epitélio reveste a córnea?", options: ["Simples pavimentoso", "Estratificado pavimentoso não-queratinizado", "Pseudoestratificado", "Simples cúbico"], correctIndex: 1, explanation: "A córnea é revestida por epitélio estratificado pavimentoso não-queratinizado, que mantém transparência e se renova rapidamente a partir de células-tronco do limbo." },
  { id: 17, topic: "Tecido Epitelial", question: "O neuroepitélio olfatório contém qual tipo celular receptor?", options: ["Células caliciformes", "Neurônios bipolares olfatórios", "Melanócitos", "Células de Merkel"], correctIndex: 1, explanation: "O epitélio olfatório contém neurônios bipolares cujos cílios imóveis possuem receptores olfatórios. São os únicos neurônios que se regeneram continuamente ao longo da vida." },
  { id: 18, topic: "Tecido Epitelial", question: "As células de Merkel na epiderme funcionam como:", options: ["Células imunológicas", "Mecanorreceptores de toque leve", "Produtoras de melanina", "Células-tronco"], correctIndex: 1, explanation: "As células de Merkel são mecanorreceptores de adaptação lenta localizados no estrato basal, fazendo sinapse com fibras nervosas aferentes para detecção de pressão sustentada." },
  { id: 19, topic: "Tecido Epitelial", question: "A renovação do epitélio intestinal ocorre a cada:", options: ["24 horas", "3-5 dias", "14 dias", "28 dias"], correctIndex: 1, explanation: "O epitélio intestinal renova-se completamente a cada 3-5 dias a partir de células-tronco Lgr5+ no fundo das criptas de Lieberkühn." },
  { id: 20, topic: "Tecido Epitelial", question: "O pênfigo vulgar é causado por autoanticorpos contra:", options: ["Colágeno tipo IV", "Desmogleínas (desmossomos)", "Integrinas", "Conexinas"], correctIndex: 1, explanation: "O pênfigo vulgar resulta de autoanticorpos IgG contra desmogleína 3, rompendo desmossomos intercelulares e causando acantólise com bolhas intraepiteliais." },
  { id: 21, topic: "Tecido Epitelial", question: "A queratinização completa ocorre em qual tipo de epitélio?", options: ["Simples cúbico", "Estratificado pavimentoso da pele (epiderme)", "Pseudoestratificado", "De transição"], correctIndex: 1, explanation: "A queratinização completa ocorre na epiderme, onde queratinócitos acumulam queratina progressivamente até formarem corneócitos anucleados no estrato córneo." },
  { id: 22, topic: "Tecido Epitelial", question: "A citoqueratina é o filamento intermediário característico de células:", options: ["Musculares", "Epiteliais", "Nervosas", "Conjuntivas"], correctIndex: 1, explanation: "As citoqueratinas são filamentos intermediários específicos de células epiteliais, usadas como marcadores imuno-histoquímicos para identificar carcinomas." },
  { id: 23, topic: "Tecido Epitelial", question: "O epitélio do esôfago é do tipo:", options: ["Simples cilíndrico", "Estratificado pavimentoso não-queratinizado", "Pseudoestratificado", "De transição"], correctIndex: 1, explanation: "O esôfago é revestido por epitélio estratificado pavimentoso não-queratinizado, adaptado à abrasão mecânica do bolo alimentar." },
  { id: 24, topic: "Tecido Epitelial", question: "Os cílios verdadeiros possuem qual arranjo microtubular?", options: ["9+0", "9+2", "9+3", "8+2"], correctIndex: 1, explanation: "Os cílios móveis possuem axonema com arranjo 9+2 (9 pares de microtúbulos periféricos + 2 centrais), movidos por dineína ciliar. O arranjo 9+0 é dos cílios primários (sensoriais)." },
  { id: 25, topic: "Tecido Epitelial", question: "O endotélio vascular é classificado como:", options: ["Epitélio estratificado pavimentoso", "Epitélio simples pavimentoso", "Tecido conjuntivo", "Mesênquima"], correctIndex: 1, explanation: "O endotélio é um epitélio simples pavimentoso de origem mesodérmica que reveste a superfície interna de todos os vasos sanguíneos e linfáticos." },
  { id: 26, topic: "Tecido Epitelial", question: "As glândulas exócrinas se diferenciam das endócrinas pela presença de:", options: ["Células secretoras", "Ductos excretores", "Cápsula conjuntiva", "Vascularização"], correctIndex: 1, explanation: "As glândulas exócrinas possuem ductos que conduzem a secreção para uma superfície (externa ou cavidade), enquanto as endócrinas secretam hormônios diretamente no sangue." },
  { id: 27, topic: "Tecido Epitelial", question: "A tuba uterina é revestida por epitélio:", options: ["Estratificado pavimentoso", "Simples cilíndrico com células ciliadas e secretoras", "De transição", "Pseudoestratificado"], correctIndex: 1, explanation: "A tuba uterina possui epitélio simples cilíndrico com células ciliadas (transporte do oócito) e células secretoras (nutrição), especialmente na ampola onde ocorre a fecundação." },
  { id: 28, topic: "Tecido Epitelial", question: "A metaplasia escamosa da traqueia em fumantes envolve:", options: ["Transformação de células ciliadas em caliciformes", "Substituição do epitélio pseudoestratificado por estratificado pavimentoso", "Hiperplasia de células basais apenas", "Apoptose de todas as células"], correctIndex: 1, explanation: "A irritação crônica pelo tabaco induz metaplasia escamosa: o epitélio respiratório é substituído por estratificado pavimentoso, perdendo a função mucociliar." },
  { id: 29, topic: "Tecido Epitelial", question: "As claudinas e ocludinas são proteínas componentes de:", options: ["Gap junctions", "Zônulas de oclusão (tight junctions)", "Desmossomos", "Hemidesmossomos"], correctIndex: 1, explanation: "Claudinas e ocludinas são proteínas transmembranares das tight junctions que formam o selo entre células epiteliais, regulando a permeabilidade paracelular." },
  { id: 30, topic: "Tecido Epitelial", question: "O epitélio dos túbulos contorcidos proximais do rim é:", options: ["Simples pavimentoso", "Simples cúbico com borda em escova", "Estratificado cúbico", "De transição"], correctIndex: 1, explanation: "O TCP possui epitélio simples cúbico com extensa borda em escova (microvilosidades PAS+), adaptado à grande capacidade de reabsorção (glicose, aminoácidos, íons)." },
  { id: 31, topic: "Tecido Epitelial", question: "A displasia epitelial é caracterizada por:", options: ["Aumento do tamanho celular apenas", "Alterações de maturação e diferenciação com atipias celulares", "Redução do número de células", "Hipertrofia glandular"], correctIndex: 1, explanation: "A displasia envolve alterações de maturação, diferenciação e arquitetura epitelial com atipias citológicas. É uma lesão pré-neoplásica que pode progredir para carcinoma in situ." },
  { id: 32, topic: "Tecido Epitelial", question: "O epitélio gástrico superficial é do tipo:", options: ["Estratificado pavimentoso", "Simples cilíndrico mucossecretor", "Pseudoestratificado", "Simples cúbico"], correctIndex: 1, explanation: "Todo o epitélio de superfície do estômago é simples cilíndrico mucossecretor, produzindo muco alcalino que protege a mucosa contra o HCl e enzimas digestivas." },
  { id: 33, topic: "Tecido Epitelial", question: "As glândulas sudoríparas écrinas possuem secreção do tipo:", options: ["Holócrina", "Apócrina", "Merócrina (écrina)", "Endócrina"], correctIndex: 2, explanation: "As glândulas sudoríparas écrinas secretam suor por exocitose (mecanismo merócrino), sem perda de parte da célula. São as mais numerosas e distribuídas amplamente pelo corpo." },
  { id: 34, topic: "Tecido Epitelial", question: "O epitélio simples cúbico é encontrado em qual estrutura?", options: ["Esôfago", "Ductos de glândulas e superfície do ovário", "Bexiga urinária", "Traqueia"], correctIndex: 1, explanation: "O epitélio simples cúbico reveste ductos de diversas glândulas, a superfície do ovário, folículos tireoidianos e túbulos renais." },
  { id: 35, topic: "Tecido Epitelial", question: "Na junção esofagogástrica, ocorre transição abrupta entre:", options: ["Epitélio de transição e simples cúbico", "Epitélio estratificado pavimentoso e simples cilíndrico", "Epitélio pseudoestratificado e estratificado cúbico", "Epitélio simples pavimentoso e de transição"], correctIndex: 1, explanation: "Na junção esofagogástrica (linha Z), o epitélio estratificado pavimentoso não-queratinizado do esôfago transiciona abruptamente para o epitélio simples cilíndrico mucossecretor do estômago." },
  { id: 36, topic: "Tecido Epitelial", question: "O complexo juncional apical é composto, de apical para basal, por:", options: ["Gap junction → desmossomo → tight junction", "Tight junction → zônula de adesão → desmossomo", "Hemidesmossomo → gap junction → tight junction", "Desmossomo → tight junction → zônula de adesão"], correctIndex: 1, explanation: "O complexo juncional ordena-se: zônula de oclusão (tight) mais apical → zônula de adesão → desmossomo (mácula de adesão). Gap junctions e hemidesmossomos estão dispersos." },
  { id: 37, topic: "Tecido Epitelial", question: "A glândula parótida é classificada como:", options: ["Tubular simples mucosa", "Acinosa composta serosa", "Tubuloacinar mista", "Tubular composta mucosa"], correctIndex: 1, explanation: "A parótida é uma glândula acinosa composta exclusivamente serosa, produzindo secreção aquosa rica em amilase salivar (ptialina)." },
  { id: 38, topic: "Tecido Epitelial", question: "As células-tronco do epitélio intestinal localizam-se:", options: ["No topo das vilosidades", "Na base das criptas de Lieberkühn", "Na submucosa", "Na muscular da mucosa"], correctIndex: 1, explanation: "As células-tronco intestinais (marcador Lgr5) residem na base das criptas, onde se dividem assimetricamente gerando células que migram e se diferenciam ao longo do eixo cripta-vilosidade." },
  { id: 39, topic: "Tecido Epitelial", question: "O epitélio pseudoestratificado é classificado assim porque:", options: ["Possui várias camadas de células", "Todas as células tocam a lâmina basal, mas nem todas atingem a superfície", "As células estão dispostas em paliçada", "Possui células em guarda-chuva"], correctIndex: 1, explanation: "No epitélio pseudoestratificado, todas as células estão em contato com a lâmina basal, mas possuem alturas diferentes, dando falsa impressão de estratificação." },
  { id: 40, topic: "Tecido Epitelial", question: "A zona pelúcida do oócito é composta por:", options: ["Colágeno tipo IV", "Glicoproteínas ZP1, ZP2, ZP3 e ZP4", "Elastina", "Queratina"], correctIndex: 1, explanation: "A zona pelúcida é uma camada glicoproteica entre o oócito e as células da granulosa. ZP3 é o receptor para o espermatozoide que desencadeia a reação acrossômica." },
  { id: 41, topic: "Tecido Epitelial", question: "O penfigoide bolhoso difere do pênfigo por apresentar bolhas:", options: ["Intraepiteliais (acantólise)", "Subepiteliais (separação na junção dermoepidérmica)", "Apenas no estrato córneo", "Apenas na mucosa oral"], correctIndex: 1, explanation: "No penfigoide bolhoso, anticorpos anti-BP180/BP230 atacam os hemidesmossomos, causando separação subepitelial. No pênfigo, a acantólise é intraepitelial por anti-desmogleína." },
  { id: 42, topic: "Tecido Epitelial", question: "As glândulas sublinguais são classificadas como:", options: ["Serosas puras", "Predominantemente mucosas com semiluas serosas", "Endócrinas", "Holócrinas"], correctIndex: 1, explanation: "As glândulas sublinguais são predominantemente mucosas com semiluas serosas, produzindo secreção viscosa rica em mucinas." },
  { id: 43, topic: "Tecido Epitelial", question: "O epitélio que reveste as cordas vocais verdadeiras é:", options: ["Pseudoestratificado ciliado", "Estratificado pavimentoso não-queratinizado", "Simples cúbico", "De transição"], correctIndex: 1, explanation: "As cordas vocais verdadeiras são revestidas por epitélio estratificado pavimentoso não-queratinizado, adaptado ao atrito mecânico da fonação." },
  { id: 44, topic: "Tecido Epitelial", question: "A glândula submandibular é classificada como:", options: ["Serosa pura", "Mista (serosa e mucosa) com predomínio seroso", "Mucosa pura", "Endócrina"], correctIndex: 1, explanation: "A submandibular é uma glândula mista tubuloacinar com predomínio seroso (~60% serosa, ~40% mucosa com semiluas serosas de von Ebner)." },
  { id: 45, topic: "Tecido Epitelial", question: "O componente principal do glicocálice é:", options: ["Colágeno", "Glicoproteínas e glicolipídios da membrana plasmática", "Queratina", "Elastina"], correctIndex: 1, explanation: "O glicocálice é formado por oligossacarídeos das glicoproteínas e glicolipídios da membrana, participando na proteção, adesão celular e reconhecimento." },
  { id: 46, topic: "Tecido Epitelial", question: "As células basais do epitélio pseudoestratificado funcionam como:", options: ["Células secretoras", "Células-tronco/progenitoras", "Receptores sensoriais", "Células imunológicas"], correctIndex: 1, explanation: "As células basais são células indiferenciadas que atuam como progenitoras, capazes de se dividir e diferenciar em células ciliadas ou secretoras." },
  { id: 47, topic: "Tecido Epitelial", question: "A membrana basal ao microscópio óptico é melhor evidenciada pela coloração:", options: ["H&E", "PAS (ácido periódico de Schiff)", "Tricrômico de Masson", "Verhoeff"], correctIndex: 1, explanation: "A reação do PAS cora glicoproteínas e proteoglicanos da membrana basal em magenta, sendo a melhor técnica histológica para sua visualização ao microscópio óptico." },
  { id: 48, topic: "Tecido Epitelial", question: "A síndrome de Kartagener está associada a defeito em:", options: ["Microvilosidades", "Dineína ciliar (imobilidade ciliar)", "Conexinas", "Integrinas"], correctIndex: 1, explanation: "A síndrome de Kartagener (discinesia ciliar primária) resulta de defeitos na dineína dos cílios, causando imobilidade ciliar, situs inversus, bronquiectasias e infertilidade masculina." },
  { id: 49, topic: "Tecido Epitelial", question: "O epitélio da vagina é do tipo:", options: ["Simples cilíndrico", "Estratificado pavimentoso não-queratinizado", "De transição", "Pseudoestratificado"], correctIndex: 1, explanation: "A vagina é revestida por epitélio estratificado pavimentoso não-queratinizado, rico em glicogênio (metabolizado por Lactobacillus → ácido láctico → pH ácido protetor)." },
  { id: 50, topic: "Tecido Epitelial", question: "O carcinoma in situ é definido como:", options: ["Tumor benigno", "Neoplasia maligna confinada ao epitélio sem invasão da lâmina basal", "Metástase linfonodal", "Displasia leve"], correctIndex: 1, explanation: "O carcinoma in situ possui todas as alterações citológicas de malignidade, mas está confinado ao epitélio acima da membrana basal, sem invasão estromal." },

  // =============================================
  // TECIDO CONJUNTIVO (51-100)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 51, topic: "Tecido Conjuntivo", question: "Qual é a principal célula residente do tecido conjuntivo propriamente dito?", options: ["Macrófago", "Mastócito", "Fibroblasto", "Plasmócito"], correctIndex: 2, explanation: "O fibroblasto é a célula mais abundante do TC propriamente dito, responsável pela síntese de fibras colágenas, elásticas e da substância fundamental amorfa." },
  { id: 52, topic: "Tecido Conjuntivo", question: "Qual tipo de colágeno é o mais abundante no corpo humano?", options: ["Tipo II", "Tipo I", "Tipo III", "Tipo IV"], correctIndex: 1, explanation: "O colágeno tipo I é o mais abundante (~90% do colágeno corporal), encontrado na derme, tendões, ossos e fáscias. Forma fibras espessas com grande resistência à tração." },
  { id: 53, topic: "Tecido Conjuntivo", question: "Os mastócitos são conhecidos por liberar qual mediador inflamatório?", options: ["Colágeno", "Histamina", "Elastina", "Fibronectina"], correctIndex: 1, explanation: "Os mastócitos contêm grânulos ricos em histamina, heparina e proteases. A degranulação mediada por IgE é central nas reações alérgicas e inflamação aguda." },
  { id: 54, topic: "Tecido Conjuntivo", question: "O colágeno tipo IV é encontrado exclusivamente em qual estrutura?", options: ["Tendões", "Lâmina basal", "Cartilagem hialina", "Fibras reticulares"], correctIndex: 1, explanation: "O colágeno tipo IV não forma fibras, mas uma rede tridimensional que constitui a armação estrutural da lâmina basal." },
  { id: 55, topic: "Tecido Conjuntivo", question: "Os plasmócitos são responsáveis pela produção de:", options: ["Histamina", "Anticorpos (imunoglobulinas)", "Colágeno", "Heparina"], correctIndex: 1, explanation: "Os plasmócitos são linfócitos B diferenciados com REG abundante (imagem de 'roda de carroça' no núcleo), especializados na produção maciça de anticorpos." },
  { id: 56, topic: "Tecido Conjuntivo", question: "O tecido conjuntivo denso modelado é encontrado em:", options: ["Derme reticular", "Tendões e ligamentos", "Cápsulas de órgãos", "Lâmina própria"], correctIndex: 1, explanation: "No TC denso modelado, as fibras colágenas estão orientadas paralelamente, conferindo resistência unidirecional, como em tendões e ligamentos." },
  { id: 57, topic: "Tecido Conjuntivo", question: "A proteína UCP1, responsável pela termogênese, é encontrada em qual tecido?", options: ["Tecido adiposo unilocular", "Tecido adiposo multilocular (marrom)", "Músculo esquelético", "Fígado"], correctIndex: 1, explanation: "A UCP1 (termogenina) está nas mitocôndrias do tecido adiposo marrom, desacoplando a cadeia respiratória para gerar calor ao invés de ATP." },
  { id: 58, topic: "Tecido Conjuntivo", question: "Os GAGs da substância fundamental possuem carga:", options: ["Positiva, atraindo ânions", "Negativa, atraindo água e cátions", "Neutra", "Variável conforme pH"], correctIndex: 1, explanation: "Os GAGs possuem carga negativa devido a grupos sulfato e carboxila, atraindo água e conferindo turgidez e resistência à compressão ao tecido." },
  { id: 59, topic: "Tecido Conjuntivo", question: "A síndrome de Marfan é causada por mutação em qual proteína?", options: ["Colágeno tipo I", "Elastina", "Fibrilina-1", "Laminina"], correctIndex: 2, explanation: "A síndrome de Marfan resulta de mutação no gene FBN1 (fibrilina-1), proteína essencial para formação de fibras elásticas, afetando olhos, esqueleto e sistema cardiovascular." },
  { id: 60, topic: "Tecido Conjuntivo", question: "A osteogênese imperfeita é causada por defeito em qual proteína?", options: ["Fibrilina", "Colágeno tipo I", "Colágeno tipo IV", "Elastina"], correctIndex: 1, explanation: "A osteogênese imperfeita resulta de mutações nos genes COL1A1/COL1A2 do colágeno tipo I, causando fragilidade óssea extrema, escleras azuladas e dentinogênese imperfeita." },
  { id: 61, topic: "Tecido Conjuntivo", question: "As fibras reticulares são compostas por colágeno tipo:", options: ["Tipo I", "Tipo II", "Tipo III", "Tipo IV"], correctIndex: 2, explanation: "As fibras reticulares são compostas por colágeno tipo III e formam o arcabouço de suporte de órgãos hematopoiéticos e linfoides (baço, linfonodos, medula óssea)." },
  { id: 62, topic: "Tecido Conjuntivo", question: "A vitamina C é essencial na síntese de colágeno porque participa da:", options: ["Transcrição gênica", "Hidroxilação de prolina e lisina", "Glicosilação terminal", "Clivagem de pró-colágeno"], correctIndex: 1, explanation: "A vitamina C é cofator das prolil-hidroxilase e lisil-hidroxilase, essenciais para a estabilidade da tripla hélice do colágeno. Deficiência causa escorbuto." },
  { id: 63, topic: "Tecido Conjuntivo", question: "O ácido hialurônico difere dos outros GAGs porque:", options: ["É sulfatado", "Não é sulfatado e não está ligado a proteínas centrais", "Forma fibras visíveis", "Está presente apenas nos ossos"], correctIndex: 1, explanation: "O ácido hialurônico é o único GAG não sulfatado e não se liga covalentemente a uma proteína central. É sintetizado na membrana plasmática, não no Golgi." },
  { id: 64, topic: "Tecido Conjuntivo", question: "Os pericitos são células encontradas:", options: ["Na matriz óssea", "Ao redor de capilares e vênulas", "Nos tendões", "Na epiderme"], correctIndex: 1, explanation: "Os pericitos são células contráteis com propriedades de células-tronco mesenquimais que envolvem capilares e vênulas, regulando fluxo sanguíneo e participando da angiogênese." },
  { id: 65, topic: "Tecido Conjuntivo", question: "A leptina é um hormônio produzido por:", options: ["Hepatócitos", "Adipócitos do tecido adiposo branco", "Fibroblastos", "Mastócitos"], correctIndex: 1, explanation: "A leptina é produzida pelo tecido adiposo branco e atua no hipotálamo inibindo o apetite e aumentando o gasto energético, sinalizando o status de reserva energética." },
  { id: 66, topic: "Tecido Conjuntivo", question: "A fibronectina é uma glicoproteína que promove:", options: ["Contração muscular", "Adesão celular à matriz extracelular", "Digestão enzimática", "Transmissão nervosa"], correctIndex: 1, explanation: "A fibronectina liga-se a integrinas na superfície celular e a componentes da MEC (colágeno, fibrina), mediando adesão, migração e diferenciação celular." },
  { id: 67, topic: "Tecido Conjuntivo", question: "O tecido conjuntivo mucoso é encontrado no adulto em qual estrutura?", options: ["Cordão umbilical (geleia de Wharton)", "Tendões", "Polpa dentária", "Derme reticular"], correctIndex: 0, explanation: "O TC mucoso (geleia de Wharton) é abundante no cordão umbilical, com substância fundamental gelatinosa rica em ácido hialurônico e poucos fibroblastos." },
  { id: 68, topic: "Tecido Conjuntivo", question: "Os macrófagos teciduais no fígado são chamados de:", options: ["Osteoclastos", "Células de Kupffer", "Microglia", "Células de Langerhans"], correctIndex: 1, explanation: "As células de Kupffer são macrófagos residentes dos sinusoides hepáticos. Outros exemplos: microglia (SNC), osteoclastos (osso), células de Langerhans (pele)." },
  { id: 69, topic: "Tecido Conjuntivo", question: "As metaloproteinases de matriz (MMPs) são enzimas que degradam:", options: ["DNA nuclear", "Componentes da matriz extracelular", "Hemoglobina", "Neurotransmissores"], correctIndex: 1, explanation: "As MMPs são endopeptidases zinco-dependentes que degradam colágenos e outros componentes da MEC, essenciais na remodelação tecidual, cicatrização e invasão tumoral." },
  { id: 70, topic: "Tecido Conjuntivo", question: "O tecido adiposo bege é caracterizado por:", options: ["Única gota lipídica grande", "Adipócitos brancos que adquirem fenótipo termogênico sob estímulo", "Ausência de mitocôndrias", "Localização exclusiva no feto"], correctIndex: 1, explanation: "Adipócitos bege são células do tecido adiposo branco que, sob estímulo (frio, exercício), expressam UCP1 e adquirem capacidade termogênica." },
  { id: 71, topic: "Tecido Conjuntivo", question: "O TC reticular é abundante em:", options: ["Tendões", "Órgãos linfoides e hematopoiéticos", "Cartilagem", "Osso compacto"], correctIndex: 1, explanation: "O TC reticular, com fibras de colágeno tipo III formando redes delicadas, constitui o arcabouço do baço, linfonodos, medula óssea e fígado." },
  { id: 72, topic: "Tecido Conjuntivo", question: "A vimentina é o filamento intermediário de:", options: ["Células epiteliais", "Células de origem mesenquimal", "Neurônios", "Músculo esquelético"], correctIndex: 1, explanation: "A vimentina é marcador de células mesenquimais (fibroblastos, células endoteliais). Na IHQ, é positiva em sarcomas e tumores mesenquimais." },
  { id: 73, topic: "Tecido Conjuntivo", question: "O TCPD denso não-modelado é encontrado em:", options: ["Tendões", "Derme reticular e cápsulas de órgãos", "Lâmina própria", "Cartilagem articular"], correctIndex: 1, explanation: "No TC denso não-modelado, fibras colágenas dispõem-se em várias direções, conferindo resistência multidirecional. É encontrado na derme reticular, cápsulas e septos de órgãos." },
  { id: 74, topic: "Tecido Conjuntivo", question: "Na cicatrização, o colágeno tipo III é gradualmente substituído por:", options: ["Colágeno tipo IV", "Colágeno tipo I", "Elastina", "Colágeno tipo II"], correctIndex: 1, explanation: "No tecido de granulação, fibroblastos produzem inicialmente colágeno tipo III, que é remodelado e substituído por colágeno tipo I mais resistente durante a maturação cicatricial." },
  { id: 75, topic: "Tecido Conjuntivo", question: "A síndrome de Ehlers-Danlos tipo clássico é causada por defeito em:", options: ["Fibrilina-1", "Colágeno tipo V", "Elastina", "Laminina"], correctIndex: 1, explanation: "A EDS clássica resulta de mutações no colágeno tipo V (COL5A1/A2), causando hipermobilidade articular, pele hiperelástica e fragilidade vascular." },
  { id: 76, topic: "Tecido Conjuntivo", question: "O agrecano é o principal proteoglicano encontrado em:", options: ["Osso", "Cartilagem hialina", "Tendões", "Músculo"], correctIndex: 1, explanation: "O agrecano é o principal proteoglicano da cartilagem hialina, ligando-se ao ácido hialurônico formando agregados que retêm água e conferem resistência à compressão." },
  { id: 77, topic: "Tecido Conjuntivo", question: "O colágeno tipo VII forma:", options: ["Fibrilas na cartilagem", "Fibrilas de ancoragem na junção dermoepidérmica", "Rede na lâmina basal", "Fibras em tendões"], correctIndex: 1, explanation: "O colágeno tipo VII forma fibrilas de ancoragem que conectam a lâmina basal ao tecido conjuntivo da derme, essencial na adesão dermoepidérmica. Defeito: epidermólise bolhosa distrófica." },
  { id: 78, topic: "Tecido Conjuntivo", question: "As fibras elásticas são compostas por:", options: ["Colágeno tipo I e fibrilina", "Elastina (core) e fibrilina (microfibrilas)", "Queratina e actina", "Laminina e integrinas"], correctIndex: 1, explanation: "As fibras elásticas possuem um core amorfo de elastina circundado por microfibrilas de fibrilina. Conferem distensibilidade a artérias, pulmões e pele." },
  { id: 79, topic: "Tecido Conjuntivo", question: "O TCPD frouxo é encontrado em:", options: ["Tendões", "Lâmina própria de mucosas e ao redor de vasos", "Interior de ossos longos", "Cartilagem articular"], correctIndex: 1, explanation: "O TCPD frouxo (areolar) localiza-se sob epitélios (lâmina própria), ao redor de vasos e nervos, provendo suporte, nutrição e defesa." },
  { id: 80, topic: "Tecido Conjuntivo", question: "Os TIMPs são:", options: ["Enzimas que degradam colágeno", "Inibidores teciduais das metaloproteinases", "Tipos de colágeno", "Proteínas de adesão"], correctIndex: 1, explanation: "Os TIMPs (Tissue Inhibitors of Metalloproteinases) regulam negativamente a atividade das MMPs, mantendo o equilíbrio entre síntese e degradação da MEC." },
  { id: 81, topic: "Tecido Conjuntivo", question: "As células estreladas hepáticas (de Ito) armazenam:", options: ["Glicogênio", "Vitamina A (retinol)", "Bile", "Ferro"], correctIndex: 1, explanation: "As células de Ito no espaço de Disse armazenam vitamina A em gotículas lipídicas. Quando ativadas por lesão, transformam-se em miofibroblastos produtores de colágeno (fibrose hepática)." },
  { id: 82, topic: "Tecido Conjuntivo", question: "O colágeno tipo II é o principal tipo encontrado em:", options: ["Pele e tendões", "Cartilagem hialina e elástica", "Lâmina basal", "Cordão umbilical"], correctIndex: 1, explanation: "O colágeno tipo II é o principal colágeno das cartilagens hialina e elástica, assim como do humor vítreo do olho." },
  { id: 83, topic: "Tecido Conjuntivo", question: "A adiponectina é produzida pelo tecido adiposo e atua:", options: ["Estimulando o apetite", "Aumentando sensibilidade à insulina e possuindo efeito anti-inflamatório", "Promovendo lipogênese", "Estimulando a termogênese"], correctIndex: 1, explanation: "A adiponectina é uma adipocina com efeitos sensibilizadores de insulina e anti-inflamatórios. Seus níveis estão reduzidos na obesidade e resistência insulínica." },
  { id: 84, topic: "Tecido Conjuntivo", question: "A síntese de colágeno tipo I segue a sequência:", options: ["Golgi → REG → secreção", "REG (pró-colágeno) → Golgi → secreção → clivagem → fibrilas", "Núcleo → citosol → membrana", "Mitocôndria → citosol → MEC"], correctIndex: 1, explanation: "O pró-colágeno é sintetizado no REG, modificado (hidroxilação, glicosilação), empacotado no Golgi, secretado e clivado extracelularmente em tropocolágeno, que se auto-organiza em fibrilas." },
  { id: 85, topic: "Tecido Conjuntivo", question: "Os eosinófilos que migram para o tecido conjuntivo são importantes na defesa contra:", options: ["Bactérias gram-negativas", "Parasitas helmínticos", "Vírus respiratórios", "Fungos"], correctIndex: 1, explanation: "Os eosinófilos são células transitórias do TC, com grânulos ricos em MBP e peroxidase, particularmente eficazes na destruição de parasitas helmínticos e nas reações alérgicas." },
  { id: 86, topic: "Tecido Conjuntivo", question: "A tenascina é uma glicoproteína da MEC que:", options: ["Promove adesão celular forte", "Possui propriedades anti-adesivas e é abundante em tecidos embrionários e cicatrização", "Forma fibras visíveis", "Compõe a lâmina basal"], correctIndex: 1, explanation: "A tenascina-C é uma glicoproteína com propriedades anti-adesivas, expressa em tecidos embrionários, cicatrização e estroma tumoral, modulando migração celular." },
  { id: 87, topic: "Tecido Conjuntivo", question: "O tecido adiposo unilocular (branco) é caracterizado por:", options: ["Múltiplas gotículas lipídicas pequenas", "Uma única gota lipídica grande que ocupa quase toda a célula", "Abundância de mitocôndrias", "Cor marrom à macroscopia"], correctIndex: 1, explanation: "O adipócito branco possui uma única gota lipídica grande que desloca o núcleo e organelas para a periferia, dando aspecto de 'anel de sinete'." },
  { id: 88, topic: "Tecido Conjuntivo", question: "O heparan sulfato é um GAG encontrado principalmente em:", options: ["Cartilagem articular", "Lâminas basais e superfície celular", "Tendões", "Osso compacto"], correctIndex: 1, explanation: "O heparan sulfato é abundante nas lâminas basais (como perlecano) e na superfície celular (como sindecanos e glipicanos), participando na filtração glomerular e sinalização." },
  { id: 89, topic: "Tecido Conjuntivo", question: "A lisil-oxidase é uma enzima essencial para:", options: ["Degradação de colágeno", "Formação de ligações cruzadas covalentes entre moléculas de colágeno e elastina", "Síntese de GAGs", "Produção de ácido hialurônico"], correctIndex: 1, explanation: "A lisil-oxidase é uma enzima cobre-dependente que catalisa a formação de ligações cruzadas entre fibrilas de colágeno e entre moléculas de elastina, essencial para resistência mecânica." },
  { id: 90, topic: "Tecido Conjuntivo", question: "O queloide difere da cicatriz hipertrófica porque:", options: ["Contém menos colágeno", "Ultrapassa os limites da ferida original", "É reversível espontaneamente", "Contém mais vasos"], correctIndex: 1, explanation: "O queloide é uma cicatriz patológica que se estende além dos limites da lesão original, com colágeno tipo I e III hipertróficos. Não regride espontaneamente." },
  { id: 91, topic: "Tecido Conjuntivo", question: "O condroitina sulfato é encontrado abundantemente em:", options: ["Músculo esquelético", "Cartilagem, osso e pele", "Epitélio pulmonar", "Eritrócitos"], correctIndex: 1, explanation: "O condroitina sulfato é um GAG amplamente distribuído, particularmente abundante na cartilagem, osso, pele e córnea, onde contribui para resistência à compressão." },
  { id: 92, topic: "Tecido Conjuntivo", question: "As integrinas são proteínas de adesão que conectam:", options: ["Células epiteliais entre si", "Células à matriz extracelular (e vice-versa)", "Filamentos de actina à miosina", "Microtúbulos aos centrossomos"], correctIndex: 1, explanation: "As integrinas são receptores transmembranares heterodímeros (α/β) que conectam componentes da MEC (fibronectina, laminina, colágeno) ao citoesqueleto intracelular." },
  { id: 93, topic: "Tecido Conjuntivo", question: "Na inflamação aguda, os neutrófilos migram do sangue para o TC por:", options: ["Osmose", "Diapedese através das vênulas pós-capilares", "Transporte ativo pela adventícia", "Divisão celular in situ"], correctIndex: 1, explanation: "A diapedese leucocitária ocorre predominantemente nas vênulas pós-capilares, mediada por selectinas (rolamento), integrinas (adesão firme) e quimiocinas (migração)." },
  { id: 94, topic: "Tecido Conjuntivo", question: "As fibras oxitalânicas são componentes do sistema:", options: ["Colágeno", "Elástico (fibras imaturas)", "Reticular", "Muscular"], correctIndex: 1, explanation: "As fibras oxitalânicas são componentes imaturos do sistema elástico, compostas apenas por microfibrilas de fibrilina, sem elastina. São encontradas na derme papilar e ligamento periodontal." },
  { id: 95, topic: "Tecido Conjuntivo", question: "Os macrófagos M1 são caracterizados por:", options: ["Função anti-inflamatória", "Perfil pró-inflamatório com produção de TNF-α, IL-1, IL-6 e óxido nítrico", "Promoção de fibrose", "Supressão imune"], correctIndex: 1, explanation: "Os macrófagos M1 (ativados classicamente por IFN-γ) são pró-inflamatórios e microbicidas. Os M2 (ativados alternativamente por IL-4/IL-13) são anti-inflamatórios e promovem reparo tecidual." },
  { id: 96, topic: "Tecido Conjuntivo", question: "A elastase neutrofílica degrada principalmente:", options: ["Colágeno tipo IV", "Elastina e outros componentes da MEC", "DNA nuclear", "Queratina"], correctIndex: 1, explanation: "A elastase neutrofílica é uma serina protease que degrada elastina e outros componentes da MEC. É inibida pela α1-antitripsina; desequilíbrio causa enfisema pulmonar." },
  { id: 97, topic: "Tecido Conjuntivo", question: "As células mesenquimais são células-tronco que podem se diferenciar em:", options: ["Apenas fibroblastos", "Fibroblastos, condrócitos, osteócitos, adipócitos e outros", "Apenas neurônios", "Apenas células epiteliais"], correctIndex: 1, explanation: "As células mesenquimais são multipotentes, capazes de originar diversos tipos celulares do TC: fibroblastos, condroblastos, osteoblastos, adipócitos, células musculares lisas." },
  { id: 98, topic: "Tecido Conjuntivo", question: "A laminina é a principal glicoproteína de adesão da:", options: ["Matriz extracelular intersticial", "Lâmina basal", "Substância fundamental amorfa", "Fibras elásticas"], correctIndex: 1, explanation: "A laminina é a glicoproteína mais abundante da lâmina basal, mediando a adesão das células epiteliais e endoteliais à membrana basal via integrinas." },
  { id: 99, topic: "Tecido Conjuntivo", question: "O tecido de granulação é composto por:", options: ["Epitélio regenerado e osso", "Capilares neoformados, fibroblastos e matriz provisória", "Cartilagem hialina", "Tecido nervoso"], correctIndex: 1, explanation: "O tecido de granulação é altamente vascularizado (angiogênese), com fibroblastos produzindo colágeno tipo III e matriz provisória durante a cicatrização." },
  { id: 100, topic: "Tecido Conjuntivo", question: "O dermatossulfato é um GAG abundante em:", options: ["Cartilagem articular", "Pele, tendões, vasos sanguíneos e válvulas cardíacas", "Humor vítreo", "Líquido sinovial"], correctIndex: 1, explanation: "O dermatan sulfato (condroitina sulfato B) é abundante na pele, tendões, vasos e válvulas cardíacas, contribuindo para as propriedades mecânicas desses tecidos." },

  // =============================================
  // TECIDO MUSCULAR (101-150)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 101, topic: "Tecido Muscular", question: "Qual característica diferencia o músculo cardíaco do esquelético?", options: ["Presença de estriações transversais", "Discos intercalares e ramificações celulares", "Multinucleação das fibras", "Ausência de mitocôndrias"], correctIndex: 1, explanation: "O músculo cardíaco possui discos intercalares (gap junctions + desmossomos) e células ramificadas com 1-2 núcleos centrais, diferenciando-o do esquelético." },
  { id: 102, topic: "Tecido Muscular", question: "Qual proteína contrátil possui atividade ATPásica no sarcômero?", options: ["Actina", "Tropomiosina", "Miosina", "Troponina"], correctIndex: 2, explanation: "A miosina possui cabeças globulares com atividade ATPásica, gerando força para o deslizamento dos filamentos de actina durante a contração." },
  { id: 103, topic: "Tecido Muscular", question: "O músculo liso está presente em qual das seguintes estruturas?", options: ["Língua", "Parede do intestino", "Diafragma", "Músculos intercostais"], correctIndex: 1, explanation: "O músculo liso forma as camadas musculares da parede do intestino (e de vasos, útero, brônquios), responsáveis pelos movimentos peristálticos." },
  { id: 104, topic: "Tecido Muscular", question: "No sarcômero, a banda I é composta por:", options: ["Filamentos grossos de miosina", "Filamentos finos de actina", "Sobreposição de actina e miosina", "Titina exclusivamente"], correctIndex: 1, explanation: "A banda I contém apenas filamentos finos de actina. Durante a contração, a banda I encurta enquanto a banda A permanece constante." },
  { id: 105, topic: "Tecido Muscular", question: "As células satélites do músculo esquelético são responsáveis por:", options: ["Contração involuntária", "Regeneração e reparo muscular", "Condução nervosa", "Produção de mielina"], correctIndex: 1, explanation: "As células satélites são células-tronco quiescentes localizadas entre o sarcolema e a lâmina basal da fibra muscular, essenciais para regeneração." },
  { id: 106, topic: "Tecido Muscular", question: "Nos discos intercalares do músculo cardíaco, qual junção permite a propagação elétrica?", options: ["Desmossomo", "Tight junction", "Gap junction (junção comunicante)", "Hemidesmossomo"], correctIndex: 2, explanation: "As gap junctions nos discos intercalares permitem passagem de íons entre cardiomiócitos adjacentes, possibilitando contração sincronizada (sincício funcional)." },
  { id: 107, topic: "Tecido Muscular", question: "A contração do músculo liso é regulada principalmente pela:", options: ["Troponina C", "Calmodulina e MLCK", "Distrofina", "Titina"], correctIndex: 1, explanation: "No músculo liso, Ca²⁺ liga-se à calmodulina, que ativa a MLCK (quinase da cadeia leve da miosina), fosforilando a miosina e permitindo a interação com actina." },
  { id: 108, topic: "Tecido Muscular", question: "As fibras musculares tipo I são caracterizadas por:", options: ["Contração rápida e glicolítica", "Contração lenta, oxidativa e resistente à fadiga", "Ausência de mitocôndrias", "Diâmetro grande e pouca mioglobina"], correctIndex: 1, explanation: "As fibras tipo I (vermelhas) possuem muitas mitocôndrias, mioglobina abundante e metabolismo oxidativo, sendo resistentes à fadiga." },
  { id: 109, topic: "Tecido Muscular", question: "A titina é uma proteína do sarcômero responsável por:", options: ["Contração ativa", "Elasticidade passiva e manutenção do arranjo sarcomérico", "Transmissão do impulso nervoso", "Ligação ao cálcio"], correctIndex: 1, explanation: "A titina é a maior proteína do corpo, estendendo-se da linha Z à linha M, funcionando como mola molecular que mantém a organização do sarcômero." },
  { id: 110, topic: "Tecido Muscular", question: "A tríade do músculo esquelético é formada por:", options: ["Três sarcômeros adjacentes", "Um túbulo T flanqueado por duas cisternas terminais do RS", "Três fibras musculares", "Núcleo + mitocôndria + REG"], correctIndex: 1, explanation: "A tríade consiste em um túbulo T (invaginação do sarcolema) flanqueado por duas cisternas terminais do retículo sarcoplasmático, essencial para o acoplamento excitação-contração." },
  { id: 111, topic: "Tecido Muscular", question: "No músculo cardíaco, a díade é formada por:", options: ["Dois túbulos T", "Um túbulo T associado a uma cisterna do RS", "Dois sarcômeros", "Dois discos intercalares"], correctIndex: 1, explanation: "Diferentemente do músculo esquelético (tríade na linha A-I), o cardíaco possui díades: um túbulo T associado a apenas uma cisterna do RS, localizados na linha Z." },
  { id: 112, topic: "Tecido Muscular", question: "O receptor de rianodina (RyR) está localizado em:", options: ["Sarcolema", "Membrana do retículo sarcoplasmático", "Membrana mitocondrial", "Disco intercalar"], correctIndex: 1, explanation: "Os receptores de rianodina são canais de Ca²⁺ na membrana do RS. No músculo esquelético (RyR1), são ativados mecanicamente pelo receptor de dihidropiridina dos túbulos T." },
  { id: 113, topic: "Tecido Muscular", question: "A distrofina é uma proteína que conecta:", options: ["Actina a miosina", "Citoesqueleto de actina à MEC via complexo distroglicano", "Túbulo T ao RS", "Troponina à tropomiosina"], correctIndex: 1, explanation: "A distrofina ancora filamentos de actina subsarcolemais ao complexo distroglicano-sarcoglicano na membrana. Sua ausência causa distrofia muscular de Duchenne." },
  { id: 114, topic: "Tecido Muscular", question: "O endomísio envolve:", options: ["O músculo inteiro", "Cada fascículo muscular", "Cada fibra muscular individual", "Cada miofibrila"], correctIndex: 2, explanation: "O endomísio é a camada de TC frouxo que envolve cada fibra muscular individual, contendo capilares e fibras nervosas. O perimísio envolve fascículos e o epimísio, o músculo todo." },
  { id: 115, topic: "Tecido Muscular", question: "A rigor mortis ocorre porque:", options: ["Excesso de ATP", "Falta de ATP impede o desligamento das pontes cruzadas de miosina-actina", "Excesso de Ca²⁺ extracelular", "Desnaturação da troponina"], correctIndex: 1, explanation: "Após a morte, a queda de ATP impede que as cabeças de miosina se desacoplem da actina, resultando em rigidez muscular até a degradação proteica post-mortem." },
  { id: 116, topic: "Tecido Muscular", question: "O sarcômero é delimitado por:", options: ["Bandas A", "Linhas Z", "Zonas H", "Linhas M"], correctIndex: 1, explanation: "O sarcômero é a unidade contrátil, delimitado por duas linhas Z consecutivas. Contém banda A (filamentos grossos ± finos), banda I (apenas finos), zona H (apenas grossos) e linha M." },
  { id: 117, topic: "Tecido Muscular", question: "A troponina cardíaca I (cTnI) é utilizada como biomarcador de:", options: ["Insuficiência renal", "Necrose miocárdica (infarto)", "Lesão hepática", "Lesão muscular esquelética"], correctIndex: 1, explanation: "A troponina I cardíaca é altamente específica para o miocárdio, elevando-se 3-6h após o infarto e permanecendo alta por 7-14 dias. É o biomarcador preferido para IAM." },
  { id: 118, topic: "Tecido Muscular", question: "A desmina é o filamento intermediário específico de:", options: ["Neurônios", "Células epiteliais", "Células musculares (esquelética, cardíaca e lisa)", "Astrócitos"], correctIndex: 2, explanation: "A desmina é o filamento intermediário de todas as células musculares, conectando sarcômeros, membrana e organelas. Na IHQ, é marcador de tumores de músculo." },
  { id: 119, topic: "Tecido Muscular", question: "No acoplamento excitação-contração, o Ca²⁺ liberado liga-se a:", options: ["Miosina", "Troponina C", "Actina", "Tropomiosina"], correctIndex: 1, explanation: "No músculo esquelético e cardíaco, Ca²⁺ liga-se à troponina C, causando mudança conformacional que desloca a tropomiosina e expõe os sítios de ligação da miosina na actina." },
  { id: 120, topic: "Tecido Muscular", question: "As fibras de Purkinje no coração são:", options: ["Fibras nervosas", "Cardiomiócitos modificados para condução elétrica rápida", "Fibras de colágeno", "Músculo liso vascular"], correctIndex: 1, explanation: "As fibras de Purkinje são cardiomiócitos modificados, maiores e mais claros (ricos em glicogênio), que conduzem rapidamente o impulso elétrico do feixe de His aos ventrículos." },
  { id: 121, topic: "Tecido Muscular", question: "O músculo liso possui qual característica morfológica?", options: ["Estriações transversais", "Células fusiformes com núcleo central único, sem estriações", "Multinucleação", "Discos intercalares"], correctIndex: 1, explanation: "O músculo liso é composto por células fusiformes com um núcleo central, sem estriações visíveis. Contrai-se de forma involuntária, lenta e sustentada." },
  { id: 122, topic: "Tecido Muscular", question: "A nebulina é uma proteína do sarcômero que:", options: ["Gera força contrátil", "Regula o comprimento dos filamentos de actina", "Forma os túbulos T", "Compõe os discos intercalares"], correctIndex: 1, explanation: "A nebulina é uma proteína longa que se estende ao longo dos filamentos finos, regulando seu comprimento e estabilizando sua ancoragem na linha Z." },
  { id: 123, topic: "Tecido Muscular", question: "A hipertermia maligna está associada a mutação em:", options: ["Receptor de dihidropiridina", "Receptor de rianodina (RyR1)", "Canal de potássio", "Troponina I"], correctIndex: 1, explanation: "A hipertermia maligna resulta de mutação no RyR1, causando liberação descontrolada de Ca²⁺ do RS sob anestésicos halogenados → contração sustentada → hipertermia." },
  { id: 124, topic: "Tecido Muscular", question: "A miastenia gravis é causada por anticorpos contra:", options: ["Receptores de rianodina", "Receptores de acetilcolina na placa motora", "Canais de cálcio", "Distrofina"], correctIndex: 1, explanation: "Na miastenia gravis, autoanticorpos anti-receptor de ACh bloqueiam a transmissão neuromuscular, causando fraqueza flutuante. Frequentemente associada a hiperplasia tímica ou timoma." },
  { id: 125, topic: "Tecido Muscular", question: "A placa motora (junção neuromuscular) contém receptores:", options: ["Muscarínicos", "Nicotínicos de acetilcolina", "Adrenérgicos α1", "Dopaminérgicos D2"], correctIndex: 1, explanation: "A placa motora possui receptores nicotínicos de ACh no sarcolema da fibra muscular esquelética, concentrados nas pregas juncionais." },
  { id: 126, topic: "Tecido Muscular", question: "O músculo esquelético da língua possui fibras orientadas:", options: ["Apenas longitudinalmente", "Em múltiplas direções (longitudinal, transversal e vertical)", "Apenas circularmente", "Apenas radialmente"], correctIndex: 1, explanation: "A língua possui feixes musculares em três planos (longitudinal, transversal e vertical), permitindo movimentos complexos na fala, mastigação e deglutição." },
  { id: 127, topic: "Tecido Muscular", question: "Os corpos densos no músculo liso são funcionalmente análogos a:", options: ["Bandas A do sarcômero", "Linhas Z do músculo estriado", "Discos intercalares", "Túbulos T"], correctIndex: 1, explanation: "Os corpos densos (citoplasmáticos e de membrana) ancoram filamentos de actina e intermediários no músculo liso, funcionando como equivalentes das linhas Z do músculo estriado." },
  { id: 128, topic: "Tecido Muscular", question: "A regeneração do músculo cardíaco após infarto é:", options: ["Completa por células satélites", "Muito limitada, com formação de cicatriz fibrosa", "Rápida e eficiente", "Mediada por células de Schwann"], correctIndex: 1, explanation: "O músculo cardíaco tem capacidade regenerativa muito limitada. Após infarto, a área necrótica é substituída por cicatriz fibrosa de colágeno, sem recuperação funcional significativa." },
  { id: 129, topic: "Tecido Muscular", question: "A banda A do sarcômero:", options: ["Encurta durante a contração", "Permanece com comprimento constante durante a contração", "Contém apenas actina", "Está entre duas linhas Z"], correctIndex: 1, explanation: "A banda A contém filamentos grossos (miosina) com sobreposição parcial dos finos (actina). Seu comprimento permanece constante durante a contração (teoria do deslizamento)." },
  { id: 130, topic: "Tecido Muscular", question: "O músculo liso vascular é regulado pelo óxido nítrico (NO) que causa:", options: ["Vasoconstrição", "Vasodilatação via aumento de cGMP", "Contração sustentada", "Apoptose celular"], correctIndex: 1, explanation: "O NO difunde-se do endotélio para o músculo liso vascular, ativando a guanilato ciclase → aumento de cGMP → relaxamento do músculo liso → vasodilatação." },
  { id: 131, topic: "Tecido Muscular", question: "O fuso neuromuscular detecta:", options: ["Força de contração", "Comprimento e velocidade de estiramento do músculo", "Temperatura muscular", "Concentração de ATP"], correctIndex: 1, explanation: "O fuso neuromuscular contém fibras intrafusais inervadas por neurônios sensoriais (Ia e II), detectando comprimento e velocidade de estiramento do músculo (propriocepção)." },
  { id: 132, topic: "Tecido Muscular", question: "O órgão tendinoso de Golgi detecta:", options: ["Comprimento muscular", "Tensão no tendão (força de contração)", "Temperatura", "Dor muscular"], correctIndex: 1, explanation: "O órgão tendinoso de Golgi localiza-se na junção miotendínea e detecta mudanças na tensão do tendão, protegendo contra contração excessiva (reflexo inibitório)." },
  { id: 133, topic: "Tecido Muscular", question: "A calsequestrina é uma proteína encontrada em:", options: ["Sarcolema", "Interior do retículo sarcoplasmático (armazena Ca²⁺)", "Mitocôndrias", "Linha Z"], correctIndex: 1, explanation: "A calsequestrina é uma proteína de alta capacidade de ligação ao Ca²⁺ localizada no interior das cisternas do RS, permitindo o armazenamento de grandes quantidades de Ca²⁺." },
  { id: 134, topic: "Tecido Muscular", question: "A α-actinina é a principal proteína estrutural da:", options: ["Banda A", "Linha Z (ancora filamentos de actina)", "Zona H", "Linha M"], correctIndex: 1, explanation: "A α-actinina é a principal proteína da linha Z, ancorando os filamentos finos de actina e a titina, conferindo estabilidade ao sarcômero." },
  { id: 135, topic: "Tecido Muscular", question: "O leiomioma é o tumor benigno mais comum do:", options: ["Estômago", "Útero", "Esôfago", "Bexiga"], correctIndex: 1, explanation: "O leiomioma uterino (mioma) é o tumor benigno mais comum em mulheres, originando-se do músculo liso do miométrio. É estrógeno-dependente." },
  { id: 136, topic: "Tecido Muscular", question: "A tropomiosina no músculo esquelético em repouso:", options: ["Liga-se ao Ca²⁺", "Bloqueia os sítios de ligação da miosina na actina", "Promove a contração", "Ancora filamentos à linha Z"], correctIndex: 1, explanation: "Em repouso, a tropomiosina cobre os sítios de ligação da miosina nos filamentos de actina. Quando Ca²⁺ liga-se à troponina C, a tropomiosina se desloca, permitindo a contração." },
  { id: 137, topic: "Tecido Muscular", question: "As cavéolas no músculo liso são análogas a:", options: ["Retículo sarcoplasmático", "Túbulos T do músculo esquelético", "Desmossomos", "Corpos densos"], correctIndex: 1, explanation: "As cavéolas são invaginações da membrana do músculo liso que aumentam a área de superfície e podem funcionar como equivalentes dos túbulos T na transdução de sinais." },
  { id: 138, topic: "Tecido Muscular", question: "O ciclo das pontes cruzadas requer:", options: ["Apenas Ca²⁺", "ATP para desligamento da miosina da actina", "Apenas calmodulina", "Apenas troponina"], correctIndex: 1, explanation: "O ATP liga-se à cabeça da miosina para promover o desligamento da actina. A hidrólise do ATP (ADP+Pi) energiza a cabeça para o próximo power stroke." },
  { id: 139, topic: "Tecido Muscular", question: "As fibras tipo IIb (rápidas glicolíticas) são caracterizadas por:", options: ["Alta resistência à fadiga", "Contração rápida, diâmetro grande e metabolismo predominantemente glicolítico", "Cor vermelha intensa", "Abundância de mioglobina"], correctIndex: 1, explanation: "As fibras tipo IIb (ou IIx) possuem alta velocidade de contração, grande diâmetro, poucas mitocôndrias e mioglobina, dependendo principalmente de glicólise anaeróbia. Fatigam-se rapidamente." },
  { id: 140, topic: "Tecido Muscular", question: "A hipertrofia muscular envolve:", options: ["Aumento do número de fibras", "Aumento do diâmetro das fibras existentes", "Divisão das miofibrilas", "Perda de núcleos"], correctIndex: 1, explanation: "A hipertrofia muscular resulta do aumento do diâmetro das fibras por síntese adicional de miofibrilas e sarcômeros, não pelo aumento do número de fibras (hiperplasia é mínima)." },
  { id: 141, topic: "Tecido Muscular", question: "O músculo liso pode se contrair de forma:", options: ["Apenas fásica (rápida)", "Tônica (sustentada) e fásica", "Apenas voluntária", "Apenas reflexa"], correctIndex: 1, explanation: "O músculo liso pode manter contração tônica sustentada (como em esfíncteres e vasos) ou fásica rítmica (como no peristaltismo intestinal), com gasto energético relativamente baixo." },
  { id: 142, topic: "Tecido Muscular", question: "A junção miotendínea é caracterizada por:", options: ["Separação abrupta entre músculo e tendão", "Interdigitações entre sarcômero terminal e colágeno do tendão", "Cartilagem interposta", "Tecido ósseo de transição"], correctIndex: 1, explanation: "Na junção miotendínea, a membrana da fibra muscular apresenta dobras profundas que se interdigitam com fibrilas de colágeno do tendão, maximizando a área de transmissão de força." },
  { id: 143, topic: "Tecido Muscular", question: "Os discos intercalares possuem componentes transversais compostos por:", options: ["Gap junctions apenas", "Fascia adherens (zônula de adesão) e desmossomos", "Tight junctions", "Hemidesmossomos"], correctIndex: 1, explanation: "A porção transversal dos discos intercalares contém fascia adherens (transmite força contrátil via actina) e desmossomos (adesão mecânica). As gap junctions estão na porção lateral." },
  { id: 144, topic: "Tecido Muscular", question: "A mioglobina no músculo esquelético serve para:", options: ["Contração", "Armazenar e transportar O₂ dentro da fibra muscular", "Produzir ATP", "Regular o Ca²⁺"], correctIndex: 1, explanation: "A mioglobina é uma proteína globular com grupo heme que armazena O₂ no sarcoplasma e facilita sua difusão para as mitocôndrias, sendo abundante nas fibras tipo I." },
  { id: 145, topic: "Tecido Muscular", question: "O músculo esquelético do esôfago superior é:", options: ["Liso", "Estriado esquelético (voluntário na deglutição)", "Cardíaco", "Misto liso e cardíaco"], correctIndex: 1, explanation: "O terço superior do esôfago possui músculo esquelético (controle voluntário da deglutição), o terço médio é misto, e o terço inferior possui músculo liso." },
  { id: 146, topic: "Tecido Muscular", question: "A actina G (globular) polimeriza-se para formar:", options: ["Filamentos grossos", "Filamentos finos (actina F)", "Túbulos T", "Corpos densos"], correctIndex: 1, explanation: "Monômeros de actina G polimerizam-se em filamentos helicoidais duplos de actina F (filamentar), que constituem a espinha dorsal dos filamentos finos do sarcômero." },
  { id: 147, topic: "Tecido Muscular", question: "O receptor de dihidropiridina (DHPR) está localizado em:", options: ["Retículo sarcoplasmático", "Membrana dos túbulos T", "Linha Z", "Disco intercalar"], correctIndex: 1, explanation: "O DHPR é um canal de Ca²⁺ voltagem-dependente na membrana dos túbulos T. No músculo esquelético, funciona como sensor de voltagem que ativa mecanicamente o RyR1 no RS." },
  { id: 148, topic: "Tecido Muscular", question: "A síndrome de Duchenne é uma distrofia muscular ligada ao:", options: ["Cromossomo 21", "Cromossomo X (recessiva)", "Cromossomo 7", "Autossômica dominante"], correctIndex: 1, explanation: "A distrofia de Duchenne é X-linked recessiva, causada por mutação/deleção no gene da distrofina (Xp21), afetando meninos com fraqueza progressiva a partir dos 2-5 anos." },
  { id: 149, topic: "Tecido Muscular", question: "O músculo cremaster é do tipo:", options: ["Liso", "Esquelético estriado", "Cardíaco", "Misto"], correctIndex: 1, explanation: "O músculo cremaster é estriado esquelético, derivado do músculo oblíquo interno, responsável pelo reflexo cremastérico (elevação do testículo)." },
  { id: 150, topic: "Tecido Muscular", question: "A SERCA (Ca²⁺-ATPase do RS) é responsável por:", options: ["Liberar Ca²⁺ do RS", "Recaptar Ca²⁺ do citosol para o interior do RS (relaxamento)", "Degradar ATP", "Transportar K⁺"], correctIndex: 1, explanation: "A SERCA bombeia ativamente Ca²⁺ do sarcoplasma de volta ao RS, reduzindo a [Ca²⁺] citoplasmática e promovendo o relaxamento muscular. É regulada pelo fosfolambano no músculo cardíaco." },

  // =============================================
  // TECIDO NERVOSO (151-200)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 151, topic: "Tecido Nervoso", question: "Qual célula da glia é responsável pela formação da bainha de mielina no SNC?", options: ["Células de Schwann", "Oligodendrócitos", "Astrócitos", "Microglia"], correctIndex: 1, explanation: "No SNC, os oligodendrócitos formam a bainha de mielina (1 oligodendrócito mieliniza vários axônios). No SNP, essa função é exercida pelas células de Schwann (1:1)." },
  { id: 152, topic: "Tecido Nervoso", question: "Qual célula glial atua como macrófago residente do SNC?", options: ["Astrócito", "Oligodendrócito", "Microglia", "Célula ependimária"], correctIndex: 2, explanation: "A microglia é derivada de monócitos/precursores mieloides e representa o sistema de defesa imunológica do SNC, ativando-se em lesões e doenças neurodegenerativas." },
  { id: 153, topic: "Tecido Nervoso", question: "Os nodos de Ranvier são responsáveis por qual fenômeno?", options: ["Produção de neurotransmissores", "Condução saltatória do impulso nervoso", "Síntese de mielina", "Formação de sinapses"], correctIndex: 1, explanation: "Os nodos de Ranvier são interrupções na bainha de mielina onde se concentram canais de Na⁺ voltagem-dependentes, permitindo a condução saltatória rápida do potencial de ação." },
  { id: 154, topic: "Tecido Nervoso", question: "A substância de Nissl corresponde a qual organela?", options: ["Aparelho de Golgi", "Retículo endoplasmático rugoso (REG)", "Mitocôndrias", "Lisossomos"], correctIndex: 1, explanation: "A substância de Nissl é REG abundante nos neurônios, refletindo intensa síntese proteica. Presente no pericário e dendritos, ausente no cone de implantação e axônio." },
  { id: 155, topic: "Tecido Nervoso", question: "Os astrócitos participam da barreira hematoencefálica através de:", options: ["Formação de mielina", "Pés vasculares que envolvem capilares cerebrais", "Fagocitose de patógenos", "Produção de LCR"], correctIndex: 1, explanation: "Os astrócitos emitem prolongamentos (pés vasculares) que envolvem capilares cerebrais, induzindo propriedades de barreira nas células endoteliais (tight junctions contínuas)." },
  { id: 156, topic: "Tecido Nervoso", question: "As células ependimárias revestem:", options: ["Nervos periféricos", "Ventrículos cerebrais e canal central da medula", "Gânglios do SNP", "Meninges"], correctIndex: 1, explanation: "As células ependimárias são células ciliadas que revestem os ventrículos cerebrais e canal central, participando da circulação e produção do LCR." },
  { id: 157, topic: "Tecido Nervoso", question: "No transporte axonal anterógrado, qual proteína motora é utilizada?", options: ["Dineína", "Cinesina", "Actina", "Tubulina"], correctIndex: 1, explanation: "A cinesina transporta vesículas, mitocôndrias e organelas do corpo celular para o terminal axônico (anterógrado), enquanto a dineína realiza o transporte retrógrado." },
  { id: 158, topic: "Tecido Nervoso", question: "A esclerose múltipla é uma doença que afeta primariamente:", options: ["Neurônios do SNP", "Bainha de mielina no SNC (oligodendrócitos)", "Células de Schwann", "Astrócitos apenas"], correctIndex: 1, explanation: "A esclerose múltipla é uma doença autoimune desmielinizante do SNC, onde o sistema imune ataca a mielina produzida pelos oligodendrócitos, causando placas de desmielinização." },
  { id: 159, topic: "Tecido Nervoso", question: "A cromatólise (dispersão do Nissl) ocorre após:", options: ["Formação de sinapses", "Lesão axonal", "Mielinização normal", "Apoptose programada"], correctIndex: 1, explanation: "A cromatólise é a dispersão dos corpúsculos de Nissl, com edema do pericário e deslocamento periférico do núcleo, representando a resposta do neurônio à lesão axonal." },
  { id: 160, topic: "Tecido Nervoso", question: "Os gânglios sensitivos contêm neurônios do tipo:", options: ["Multipolar", "Bipolar", "Pseudounipolar", "Anaxônico"], correctIndex: 2, explanation: "Os gânglios da raiz dorsal contêm neurônios pseudounipolares, com um único prolongamento que se bifurca em ramo periférico (receptor) e central (medula)." },
  { id: 161, topic: "Tecido Nervoso", question: "As células satélites do SNP envolvem:", options: ["Axônios mielinizados", "Corpos neuronais nos gânglios", "Terminais sinápticos", "Fibras musculares"], correctIndex: 1, explanation: "As células satélites são análogas aos astrócitos no SNP, envolvendo e suportando os corpos neuronais nos gânglios sensitivos e autonômicos." },
  { id: 162, topic: "Tecido Nervoso", question: "A GFAP é marcador imuno-histoquímico de:", options: ["Neurônios", "Astrócitos", "Oligodendrócitos", "Microglia"], correctIndex: 1, explanation: "A GFAP (proteína ácida fibrilar glial) é um filamento intermediário específico dos astrócitos. Sua expressão aumenta na gliose reativa após lesões do SNC." },
  { id: 163, topic: "Tecido Nervoso", question: "Na sinapse química, os neurotransmissores são liberados por:", options: ["Difusão passiva", "Exocitose dependente de Ca²⁺", "Transporte ativo", "Endocitose"], correctIndex: 1, explanation: "A chegada do PA abre canais de Ca²⁺ voltagem-dependentes no terminal, e o influxo de Ca²⁺ promove a fusão das vesículas sinápticas com a membrana (exocitose)." },
  { id: 164, topic: "Tecido Nervoso", question: "O plexo de Auerbach (mioentérico) está localizado entre:", options: ["Mucosa e submucosa", "Camada circular e longitudinal da muscular externa", "Submucosa e muscular", "Serosa e muscular"], correctIndex: 1, explanation: "O plexo mioentérico localiza-se entre as camadas circular e longitudinal da muscular externa do tubo digestivo, regulando a motilidade (peristalse)." },
  { id: 165, topic: "Tecido Nervoso", question: "Os corpúsculos de Meissner detectam:", options: ["Temperatura", "Pressão profunda", "Toque leve e discriminação tátil", "Dor"], correctIndex: 2, explanation: "Os corpúsculos de Meissner são mecanorreceptores encapsulados de adaptação rápida nas papilas dérmicas da pele glabra, sensíveis ao toque leve." },
  { id: 166, topic: "Tecido Nervoso", question: "A degeneração walleriana ocorre em:", options: ["Proximal ao corpo celular", "Porção distal do axônio lesado", "No corpo celular", "Nos dendritos"], correctIndex: 1, explanation: "A degeneração walleriana ocorre na porção distal do axônio seccionado: a bainha de mielina fragmenta-se e o axônio degenera, sendo fagocitado por Schwann e macrófagos." },
  { id: 167, topic: "Tecido Nervoso", question: "Os neurofilamentos são filamentos intermediários de:", options: ["Astrócitos", "Oligodendrócitos", "Neurônios", "Microglia"], correctIndex: 2, explanation: "Os neurofilamentos (NF-L, NF-M, NF-H) são filamentos intermediários dos neurônios, abundantes nos axônios e importantes para manutenção do calibre axonal." },
  { id: 168, topic: "Tecido Nervoso", question: "Os neurônios multipolares possuem:", options: ["Um único prolongamento", "Vários dendritos e um axônio", "Dois prolongamentos", "Nenhum prolongamento"], correctIndex: 1, explanation: "Os neurônios multipolares são os mais comuns no SNC, possuindo múltiplos dendritos (recepção) e um único axônio (transmissão). Exemplos: neurônios motores, piramidais, de Purkinje." },
  { id: 169, topic: "Tecido Nervoso", question: "O plexo de Meissner (submucoso) regula:", options: ["Peristalse", "Secreção glandular e fluxo sanguíneo na submucosa", "Contração do músculo esquelético", "Respiração"], correctIndex: 1, explanation: "O plexo submucoso (Meissner) está na submucosa do tubo digestivo e regula secreção glandular e fluxo sanguíneo local, enquanto o plexo de Auerbach regula a motilidade." },
  { id: 170, topic: "Tecido Nervoso", question: "As células de Schwann não-mielinizantes envolvem:", options: ["Axônios grossos isoladamente", "Múltiplos axônios finos em sulcos (fibras de Remak)", "Corpos neuronais", "Terminais sinápticos"], correctIndex: 1, explanation: "As células de Schwann não-mielinizantes envolvem vários axônios finos em sulcos de sua membrana, formando as fibras de Remak (tipo C, condução lenta)." },
  { id: 171, topic: "Tecido Nervoso", question: "A barreira hematoencefálica é formada principalmente por:", options: ["Neurônios", "Tight junctions contínuas entre células endoteliais dos capilares cerebrais", "Oligodendrócitos", "Células ependimárias"], correctIndex: 1, explanation: "A BHE é formada por tight junctions contínuas do endotélio capilar cerebral, induzidas pelos pés vasculares dos astrócitos. Impede a passagem de substâncias hidrofílicas e macromoléculas." },
  { id: 172, topic: "Tecido Nervoso", question: "O cone de implantação (segmento inicial do axônio) é importante porque:", options: ["Produz mielina", "É o sítio de geração do potencial de ação", "Contém substância de Nissl", "Armazena neurotransmissores"], correctIndex: 1, explanation: "O cone de implantação possui alta densidade de canais de Na⁺ voltagem-dependentes, sendo o local de menor limiar onde se gera o potencial de ação (zona de gatilho)." },
  { id: 173, topic: "Tecido Nervoso", question: "Os corpúsculos de Pacini detectam:", options: ["Toque leve", "Pressão profunda e vibração", "Temperatura", "Posição articular"], correctIndex: 1, explanation: "Os corpúsculos de Pacini são grandes receptores lamelados na derme profunda e hipoderme, com adaptação rápida, sensíveis a pressão profunda e vibração." },
  { id: 174, topic: "Tecido Nervoso", question: "A regeneração axonal no SNP ocorre a uma velocidade de:", options: ["1 cm/hora", "1 mm/dia", "1 cm/dia", "1 mm/hora"], correctIndex: 1, explanation: "No SNP, axônios lesados podem regenerar-se a ~1 mm/dia, guiados pelas bandas de Büngner (tubos de células de Schwann). No SNC, a regeneração é muito limitada." },
  { id: 175, topic: "Tecido Nervoso", question: "Os neurônios bipolares são encontrados em:", options: ["Córtex cerebral", "Retina, gânglio coclear e epitélio olfatório", "Medula espinhal", "Gânglios simpáticos"], correctIndex: 1, explanation: "Os neurônios bipolares possuem um dendrito e um axônio, encontrados em locais sensoriais específicos: retina (células bipolares), gânglio coclear (VIII par) e epitélio olfatório." },
  { id: 176, topic: "Tecido Nervoso", question: "A sinaptofisina é um marcador de:", options: ["Astrócitos", "Vesículas sinápticas (terminais nervosos e tumores neuroendócrinos)", "Mielina", "Microglia"], correctIndex: 1, explanation: "A sinaptofisina é uma proteína da membrana de vesículas sinápticas, usada como marcador IHQ de diferenciação neuroendócrina em tumores." },
  { id: 177, topic: "Tecido Nervoso", question: "O epineuro, perineuro e endoneuro compõem a organização de:", options: ["Músculos", "Nervos periféricos", "Tendões", "Vasos sanguíneos"], correctIndex: 1, explanation: "O endoneuro envolve cada fibra nervosa, o perineuro envolve fascículos (forma barreira hemato-nervosa) e o epineuro envolve o nervo como um todo." },
  { id: 178, topic: "Tecido Nervoso", question: "Os corpúsculos de Herring na neurohipófise são:", options: ["Neurônios motores", "Acúmulos de neurossecreção (ADH/ocitocina) nos terminais axonais", "Células de Schwann", "Corpos de Nissl"], correctIndex: 1, explanation: "Os corpúsculos de Herring são dilatações dos terminais axonais de neurônios hipotalâmicos na neurohipófise, onde ADH e ocitocina se acumulam antes da liberação." },
  { id: 179, topic: "Tecido Nervoso", question: "O perineuro é composto por:", options: ["Fibroblastos apenas", "Células epitelioides com tight junctions (barreira hemato-nervosa)", "Neurônios", "Oligodendrócitos"], correctIndex: 1, explanation: "O perineuro é formado por camadas de células perineurais achatadas unidas por tight junctions, formando a barreira hemato-nervosa que protege as fibras nervosas." },
  { id: 180, topic: "Tecido Nervoso", question: "Os neurônios de Purkinje do cerebelo são:", options: ["Bipolares", "Pseudounipolares", "Multipolares com grande arborização dendrítica", "Anaxônicos"], correctIndex: 2, explanation: "Os neurônios de Purkinje são multipolares grandes com extensa árvore dendrítica no plano sagital, constituindo a única via eferente do córtex cerebelar (inibitórios, GABAérgicos)." },
  { id: 181, topic: "Tecido Nervoso", question: "As células de Müller na retina funcionam como:", options: ["Fotorreceptores", "Glia radial de suporte (análogas a astrócitos)", "Neurônios motores", "Células pigmentares"], correctIndex: 1, explanation: "As células de Müller são células gliais radiais da retina que se estendem por toda sua espessura, fornecendo suporte estrutural e metabólico aos neurônios retinianos." },
  { id: 182, topic: "Tecido Nervoso", question: "A proteína básica da mielina (MBP) é componente principal de:", options: ["Axônios", "Bainha de mielina", "Neurofilamentos", "Vesículas sinápticas"], correctIndex: 1, explanation: "A MBP é uma das principais proteínas da mielina no SNC, essencial para compactação das lamelas. Autoanticorpos contra MBP estão envolvidos na esclerose múltipla." },
  { id: 183, topic: "Tecido Nervoso", question: "O transporte axoplasmático lento transporta:", options: ["Vesículas sinápticas", "Proteínas do citoesqueleto (tubulina, actina, neurofilamentos)", "Mitocôndrias", "Neurotransmissores"], correctIndex: 1, explanation: "O transporte lento (0,2-5 mm/dia) move proteínas citoesqueléticas e enzimas solúveis do pericário ao longo do axônio. O transporte rápido (até 400 mm/dia) carrega organelas e vesículas." },
  { id: 184, topic: "Tecido Nervoso", question: "O gânglio autônomo difere do sensitivo por conter neurônios:", options: ["Pseudounipolares", "Multipolares (pós-ganglionares)", "Bipolares", "Sem axônio"], correctIndex: 1, explanation: "Os gânglios autônomos (simpáticos e parassimpáticos) contêm neurônios multipolares pós-ganglionares, enquanto os sensitivos contêm pseudounipolares." },
  { id: 185, topic: "Tecido Nervoso", question: "A mielina é composta por aproximadamente:", options: ["90% proteínas e 10% lipídios", "70-80% lipídios e 20-30% proteínas", "50% carboidratos e 50% proteínas", "Apenas proteínas"], correctIndex: 1, explanation: "A mielina é excepcionalmente rica em lipídios (70-80%), incluindo esfingomielina, cerebrósidos e colesterol, o que lhe confere propriedades isolantes e cor branca." },
  { id: 186, topic: "Tecido Nervoso", question: "As terminações nervosas livres na pele detectam:", options: ["Apenas vibração", "Dor, temperatura e toque grosseiro", "Apenas toque fino", "Apenas posição articular"], correctIndex: 1, explanation: "As terminações nervosas livres são os receptores sensoriais mais simples e numerosos da pele, detectando dor (nociceptores), temperatura (termorreceptores) e toque grosseiro." },
  { id: 187, topic: "Tecido Nervoso", question: "O fluxo axoplasmático retrógrado transporta:", options: ["Mielina para o axônio", "Fatores neurotróficos, vírus e receptores endocitados de volta ao corpo celular", "Apenas mitocôndrias", "Neurotransmissores para o terminal"], correctIndex: 1, explanation: "O transporte retrógrado (dineína) carrega fatores de crescimento (NGF, BDNF), receptores endocitados e, patologicamente, vírus (herpes, raiva) e toxinas (tétano) para o pericário." },
  { id: 188, topic: "Tecido Nervoso", question: "Na doença de Alzheimer, os achados histopatológicos incluem:", options: ["Corpos de Lewy", "Placas senis (beta-amiloide) e emaranhados neurofibrilares (tau hiperfosforilada)", "Corpos de Pick", "Inclusões de Negri"], correctIndex: 1, explanation: "O Alzheimer é definido por placas senis (depósitos extracelulares de Aβ42) e emaranhados neurofibrilares (proteína tau hiperfosforilada intracelular) no córtex e hipocampo." },
  { id: 189, topic: "Tecido Nervoso", question: "Os astrócitos fibrosos são encontrados predominantemente em:", options: ["Substância cinzenta", "Substância branca", "Nervos periféricos", "Gânglios"], correctIndex: 1, explanation: "Os astrócitos fibrosos (muitos filamentos de GFAP, poucos prolongamentos longos) predominam na substância branca. Os protoplasmáticos (menos GFAP, muitos prolongamentos curtos e ramificados) na cinzenta." },
  { id: 190, topic: "Tecido Nervoso", question: "As incisuras de Schmidt-Lanterman na bainha de mielina do SNP são:", options: ["Locais de degradação de mielina", "Canais citoplasmáticos entre camadas de mielina da célula de Schwann", "Nodos de Ranvier", "Sinapses"], correctIndex: 1, explanation: "As incisuras de Schmidt-Lanterman são áreas onde o citoplasma da célula de Schwann persiste entre as lamelas de mielina, permitindo transporte de nutrientes e manutenção da bainha." },
  { id: 191, topic: "Tecido Nervoso", question: "A síndrome de Guillain-Barré afeta:", options: ["Mielina do SNC", "Mielina do SNP (desmielinização inflamatória aguda)", "Apenas neurônios motores", "Apenas neurônios sensitivos"], correctIndex: 1, explanation: "A síndrome de Guillain-Barré é uma polirradiculoneuropatia desmielinizante inflamatória aguda do SNP, com fraqueza ascendente simétrica, frequentemente pós-infecciosa." },
  { id: 192, topic: "Tecido Nervoso", question: "O neurópilo é composto por:", options: ["Corpos neuronais", "Emaranhado de prolongamentos neuronais e gliais entre os corpos celulares", "Vasos sanguíneos apenas", "Mielina apenas"], correctIndex: 1, explanation: "O neurópilo é a área entre os corpos celulares no SNC, composta por dendritos, axônios (mielinizados e não), sinapses e prolongamentos gliais, sem corpos celulares." },
  { id: 193, topic: "Tecido Nervoso", question: "A substância cinzenta do SNC contém predominantemente:", options: ["Axônios mielinizados", "Corpos neuronais, dendritos, sinapses e glia", "Apenas vasos sanguíneos", "Apenas células de Schwann"], correctIndex: 1, explanation: "A substância cinzenta contém pericários, dendritos, porções iniciais de axônios, sinapses abundantes e células gliais. A substância branca contém predominantemente axônios mielinizados." },
  { id: 194, topic: "Tecido Nervoso", question: "Os receptores NMDA são canais iônicos ativados por:", options: ["GABA", "Glutamato (e glicina como coagonista)", "Dopamina", "Serotonina"], correctIndex: 1, explanation: "Os receptores NMDA são canais catiônicos (Ca²⁺, Na⁺) ativados por glutamato com glicina/D-serina como coagonista, essenciais para plasticidade sináptica e memória (LTP)." },
  { id: 195, topic: "Tecido Nervoso", question: "A oligodendroglia perisatélite no SNC envolve:", options: ["Axônios", "Corpos neuronais na substância cinzenta", "Vasos sanguíneos", "Ventrículos"], correctIndex: 1, explanation: "Oligodendrócitos perisatélites (ou perineuronais) localizam-se ao redor de corpos neuronais na substância cinzenta, possivelmente fornecendo suporte metabólico." },
  { id: 196, topic: "Tecido Nervoso", question: "Os astrócitos captam qual neurotransmissor excitatório para prevenir excitotoxicidade?", options: ["GABA", "Glutamato", "Dopamina", "Acetilcolina"], correctIndex: 1, explanation: "Os astrócitos captam glutamato da fenda sináptica via transportadores EAAT, convertendo-o em glutamina pela glutamina sintetase. Isso previne excitotoxicidade por excesso de glutamato." },
  { id: 197, topic: "Tecido Nervoso", question: "Os grânulos de lipofuscina nos neurônios indicam:", options: ["Atividade mitótica", "Acúmulo de material não-digerido relacionado ao envelhecimento", "Produção de mielina", "Síntese ativa de neurotransmissores"], correctIndex: 1, explanation: "A lipofuscina é um pigmento de desgaste que se acumula nos lisossomos dos neurônios com a idade, representando resíduos de peroxidação lipídica não completamente degradados." },
  { id: 198, topic: "Tecido Nervoso", question: "A doença de Parkinson está associada à degeneração de neurônios:", options: ["Corticais", "Dopaminérgicos da substância negra pars compacta", "Motores do corno anterior", "Cerebelares"], correctIndex: 1, explanation: "O Parkinson resulta da degeneração dos neurônios dopaminérgicos da substância negra, com corpos de Lewy (α-sinucleína). Causa tremor, rigidez e bradicinesia." },
  { id: 199, topic: "Tecido Nervoso", question: "O plexo coroide é composto por:", options: ["Neurônios motores", "Epitélio cúbico simples sobre estroma vascular (produz LCR)", "Oligodendrócitos", "Células de Schwann"], correctIndex: 1, explanation: "O plexo coroide localiza-se nos ventrículos cerebrais e é formado por epitélio cúbico simples modificado (ependimário) sobre capilares fenestrados, produzindo o LCR por ultrafiltração e secreção ativa." },
  { id: 200, topic: "Tecido Nervoso", question: "Os neurônios de Golgi tipo I possuem:", options: ["Axônio curto (circuitos locais)", "Axônio longo que projeta para regiões distantes", "Nenhum axônio", "Apenas dendritos"], correctIndex: 1, explanation: "Os neurônios Golgi tipo I (projeção) possuem axônio longo (ex: piramidais do córtex, motores do corno anterior). Os Golgi tipo II possuem axônio curto para circuitos locais (interneurônios)." },

  // =============================================
  // TECIDO CARTILAGINOSO (201-250)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 201, topic: "Tecido Cartilaginoso", question: "Qual tipo de cartilagem é encontrado na orelha externa?", options: ["Hialina", "Elástica", "Fibrosa", "Calcificada"], correctIndex: 1, explanation: "A cartilagem elástica possui fibras elásticas abundantes na matriz (visíveis na coloração de Verhoeff), conferindo flexibilidade à orelha externa e à epiglote." },
  { id: 202, topic: "Tecido Cartilaginoso", question: "A cartilagem hialina é encontrada em todas EXCETO:", options: ["Anéis traqueais", "Superfícies articulares", "Discos intervertebrais", "Septo nasal"], correctIndex: 2, explanation: "Os discos intervertebrais contêm fibrocartilagem (anel fibroso) e núcleo pulposo. A cartilagem hialina é encontrada nos demais locais listados." },
  { id: 203, topic: "Tecido Cartilaginoso", question: "Os grupos isógenos na cartilagem representam:", options: ["Células inflamatórias", "Condrócitos derivados de um mesmo condroblasto", "Vasos sanguíneos", "Depósitos de cálcio"], correctIndex: 1, explanation: "Os grupos isógenos são agrupamentos de condrócitos em lacunas derivados de divisões mitóticas de um único condroblasto (crescimento intersticial)." },
  { id: 204, topic: "Tecido Cartilaginoso", question: "A cartilagem articular NÃO possui:", options: ["Colágeno tipo II", "Condrócitos", "Pericôndrio", "Substância fundamental"], correctIndex: 2, explanation: "A cartilagem articular é desprovida de pericôndrio, sendo nutrida pelo líquido sinovial. Isso limita sua capacidade de regeneração após lesões." },
  { id: 205, topic: "Tecido Cartilaginoso", question: "A fibrocartilagem difere das outras cartilagens porque:", options: ["É vascularizada", "Possui colágeno tipo I denso e NÃO tem pericôndrio", "É mais flexível", "Tem fibras elásticas abundantes"], correctIndex: 1, explanation: "A fibrocartilagem tem feixes densos de colágeno tipo I, não possui pericôndrio e resiste a forças de tração e compressão (discos intervertebrais, meniscos, sínfise púbica)." },
  { id: 206, topic: "Tecido Cartilaginoso", question: "O agrecano é um proteoglicano encontrado principalmente em:", options: ["Osso compacto", "Cartilagem hialina", "Tendões", "Músculo esquelético"], correctIndex: 1, explanation: "O agrecano é o principal proteoglicano da cartilagem hialina, ligando-se ao ácido hialurônico formando agregados que retêm água e conferem resistência à compressão." },
  { id: 207, topic: "Tecido Cartilaginoso", question: "O crescimento intersticial da cartilagem ocorre por:", options: ["Divisão de condrócitos dentro da matriz", "Adição de nova cartilagem pelo pericôndrio", "Ossificação endocondral", "Invasão vascular"], correctIndex: 0, explanation: "O crescimento intersticial ocorre pela mitose de condrócitos existentes dentro da matriz, formando grupos isógenos. É mais comum em cartilagens jovens." },
  { id: 208, topic: "Tecido Cartilaginoso", question: "O pericôndrio possui duas camadas:", options: ["Mucosa e serosa", "Fibrosa (externa) e condrogênica (interna)", "Cortical e medular", "Papilar e reticular"], correctIndex: 1, explanation: "O pericôndrio possui camada fibrosa externa (TC denso, proteção e suporte vascular) e camada condrogênica interna (células progenitoras/condroblastos para crescimento aposicional)." },
  { id: 209, topic: "Tecido Cartilaginoso", question: "A cartilagem é AVASCULAR e nutrida por:", options: ["Vasos sanguíneos intrínsecos", "Difusão a partir do pericôndrio ou líquido sinovial", "Capilares linfáticos", "Nervos"], correctIndex: 1, explanation: "A cartilagem não possui vasos sanguíneos, nervos ou vasos linfáticos. Os condrócitos são nutridos por difusão através da matriz a partir do pericôndrio ou líquido sinovial." },
  { id: 210, topic: "Tecido Cartilaginoso", question: "O colágeno predominante na cartilagem hialina é o tipo:", options: ["Tipo I", "Tipo II", "Tipo III", "Tipo IV"], correctIndex: 1, explanation: "O colágeno tipo II é o componente fibrilar principal da cartilagem hialina e elástica. Forma fibrilas finas que, juntamente com proteoglicanos, conferem resistência mecânica." },
  { id: 211, topic: "Tecido Cartilaginoso", question: "A placa epifisária é composta por cartilagem:", options: ["Elástica", "Fibrosa", "Hialina", "Calcificada apenas"], correctIndex: 2, explanation: "A placa epifisária (de crescimento) é cartilagem hialina organizada em zonas (reserva, proliferação, hipertrofia, calcificação, ossificação), responsável pelo crescimento longitudinal dos ossos." },
  { id: 212, topic: "Tecido Cartilaginoso", question: "A regeneração da cartilagem articular é:", options: ["Rápida e completa", "Muito limitada devido à avascularidade e ausência de pericôndrio", "Mediada por osteoblastos", "Dependente de células satélites"], correctIndex: 1, explanation: "A cartilagem articular tem regeneração muito limitada por ser avascular e sem pericôndrio. Lesões são reparadas com fibrocartilagem inferior, com relevância clínica na osteoartrite." },
  { id: 213, topic: "Tecido Cartilaginoso", question: "A cartilagem elástica raramente:", options: ["Possui condrócitos", "Calcifica", "Contém colágeno", "Possui pericôndrio"], correctIndex: 1, explanation: "A cartilagem elástica raramente calcifica, diferentemente da hialina que pode calcificar com a idade. As fibras elásticas abundantes conferem flexibilidade e resiliência." },
  { id: 214, topic: "Tecido Cartilaginoso", question: "O condrossarcoma é um tumor maligno que produz:", options: ["Osteoide", "Matriz cartilaginosa (condroide)", "Tecido adiposo", "Fibras reticulares"], correctIndex: 1, explanation: "O condrossarcoma é a segunda neoplasia maligna primária do osso, com produção de matriz cartilaginosa pela célula neoplásica. É resistente a quimio e radioterapia." },
  { id: 215, topic: "Tecido Cartilaginoso", question: "Na osteoartrite, a degradação da cartilagem articular envolve:", options: ["Excesso de osteoblastos", "Ação de metaloproteinases (MMP-13) e agrecanases", "Mineralização excessiva", "Invasão bacteriana"], correctIndex: 1, explanation: "Na osteoartrite, condrócitos produzem MMPs (especialmente MMP-13/colagenase-3) e agrecanases (ADAMTS-4/5) que degradam colágeno tipo II e agrecano, levando à perda progressiva de cartilagem." },
  { id: 216, topic: "Tecido Cartilaginoso", question: "O crescimento aposicional da cartilagem ocorre a partir de:", options: ["Condrócitos maduros no centro", "Células da camada condrogênica do pericôndrio", "Vasos sanguíneos", "Osso subcondral"], correctIndex: 1, explanation: "No crescimento aposicional, células mesenquimais da camada interna (condrogênica) do pericôndrio diferenciam-se em condroblastos que depositam nova matriz na periferia da cartilagem." },
  { id: 217, topic: "Tecido Cartilaginoso", question: "A matriz territorial (cápsula) ao redor dos condrócitos é rica em:", options: ["Colágeno tipo I", "Proteoglicanos (condroitina e queratan sulfato)", "Elastina", "Fibronectina"], correctIndex: 1, explanation: "A matriz territorial (pericapsular) ao redor das lacunas dos condrócitos é rica em proteoglicanos e pobre em colágeno, corando-se mais intensamente com corantes básicos (basofilia)." },
  { id: 218, topic: "Tecido Cartilaginoso", question: "Os meniscos do joelho são compostos por:", options: ["Cartilagem hialina", "Fibrocartilagem", "Cartilagem elástica", "Osso esponjoso"], correctIndex: 1, explanation: "Os meniscos são estruturas de fibrocartilagem em forma de meia-lua, com fibras de colágeno tipo I orientadas circunferencialmente, que absorvem impacto e distribuem forças no joelho." },
  { id: 219, topic: "Tecido Cartilaginoso", question: "A coloração H&E da cartilagem hialina mostra a matriz com aspecto:", options: ["Preto (como osso)", "Homogêneo azulado (basofílico) vítreo", "Amarelo brilhante", "Vermelho intenso"], correctIndex: 1, explanation: "Em H&E, a matriz da cartilagem hialina apresenta aspecto homogêneo e vítreo (hialino = vidro) com tonalidade basofílica azulada devido à presença de GAGs sulfatados na substância fundamental." },
  { id: 220, topic: "Tecido Cartilaginoso", question: "A epiglote é revestida por cartilagem:", options: ["Hialina", "Elástica", "Fibrosa", "Calcificada"], correctIndex: 1, explanation: "A epiglote contém cartilagem elástica, que permite a flexibilidade necessária para o movimento de abrir e fechar a glote durante a deglutição." },
  { id: 221, topic: "Tecido Cartilaginoso", question: "A sínfise púbica contém:", options: ["Cartilagem hialina pura", "Fibrocartilagem", "Cartilagem elástica", "Osso compacto apenas"], correctIndex: 1, explanation: "A sínfise púbica é uma articulação cartilaginosa secundária (sínfise) contendo fibrocartilagem, que permite leve movimento e resistência a forças de compressão e tração." },
  { id: 222, topic: "Tecido Cartilaginoso", question: "O SOX9 é um fator de transcrição essencial para:", options: ["Diferenciação osteoblástica", "Condrogênese (diferenciação de condrócitos)", "Miogênese", "Neurogênese"], correctIndex: 1, explanation: "O SOX9 é o principal regulador da condrogênese, ativando genes de colágeno tipo II (COL2A1) e agrecano. Mutações causam displasia campomélica." },
  { id: 223, topic: "Tecido Cartilaginoso", question: "Os anéis cartilaginosos da traqueia são em forma de:", options: ["O completo", "C (abertos posteriormente)", "S", "Losango"], correctIndex: 1, explanation: "Os anéis traqueais são de cartilagem hialina em forma de C, com a abertura posterior fechada pelo músculo traqueal (liso), permitindo a distensão do esôfago durante a deglutição." },
  { id: 224, topic: "Tecido Cartilaginoso", question: "Na acondoplasia, a mutação ocorre no gene:", options: ["COL2A1", "FGFR3 (receptor 3 de fator de crescimento fibroblástico)", "SOX9", "Agrecano"], correctIndex: 1, explanation: "A acondroplasia é a causa mais comum de nanismo, resultante de mutação ativadora do FGFR3 que inibe a proliferação de condrócitos na placa epifisária, comprometendo a ossificação endocondral." },
  { id: 225, topic: "Tecido Cartilaginoso", question: "O colágeno tipo IX na cartilagem hialina funciona como:", options: ["Principal componente estrutural", "Molécula de ligação entre fibrilas de colágeno II e proteoglicanos", "Formador de lâmina basal", "Constituinte do pericôndrio"], correctIndex: 1, explanation: "O colágeno tipo IX é um colágeno FACIT que se associa à superfície das fibrilas de colágeno tipo II, mediando interações com proteoglicanos e estabilizando a rede fibrilar da cartilagem." },
  { id: 226, topic: "Tecido Cartilaginoso", question: "O condroma (encondroma) é um tumor benigno composto por:", options: ["Osso maduro", "Cartilagem hialina madura", "Tecido fibroso", "Gordura"], correctIndex: 1, explanation: "O encondroma é um tumor benigno de cartilagem hialina que se desenvolve no interior dos ossos (intramedular), mais comum nas falanges das mãos. Geralmente assintomático." },
  { id: 227, topic: "Tecido Cartilaginoso", question: "A tuba auditiva (de Eustáquio) contém cartilagem:", options: ["Hialina", "Elástica", "Fibrosa", "Mista (hialina e fibrosa)"], correctIndex: 1, explanation: "A tuba auditiva possui cartilagem elástica em sua porção cartilaginosa, proporcionando flexibilidade para abertura e fechamento durante a equalização de pressão no ouvido médio." },
  { id: 228, topic: "Tecido Cartilaginoso", question: "Na zona de proliferação da placa epifisária, os condrócitos:", options: ["Estão em apoptose", "Dividem-se ativamente formando colunas longitudinais", "São hipertróficos", "Estão mineralizados"], correctIndex: 1, explanation: "Na zona de proliferação (seriada), os condrócitos dividem-se ativamente por mitose e se organizam em colunas longitudinais (pilhas de moedas), responsável pelo crescimento longitudinal." },
  { id: 229, topic: "Tecido Cartilaginoso", question: "A cartilagem de Meckel no embrião dá origem a:", options: ["Vértebras", "Estruturas do ouvido médio (martelo e bigorna)", "Costelas", "Clavícula"], correctIndex: 1, explanation: "A cartilagem de Meckel (primeiro arco faríngeo) origina o martelo e a bigorna do ouvido médio por ossificação endocondral, além de servir como guia para a ossificação da mandíbula." },
  { id: 230, topic: "Tecido Cartilaginoso", question: "O líquido sinovial é um ultrafiltrado do plasma enriquecido com:", options: ["Albumina apenas", "Ácido hialurônico (produzido por sinoviócitos tipo B)", "Colágeno tipo I", "Imunoglobulinas"], correctIndex: 1, explanation: "O líquido sinovial contém ácido hialurônico secretado por sinoviócitos tipo B (fibroblast-like), que confere viscosidade e lubricação à articulação, nutrindo a cartilagem articular." },
  { id: 231, topic: "Tecido Cartilaginoso", question: "Na condrocalcinose (pseudogota), depósitos de cristais ocorrem em:", options: ["Osso cortical", "Cartilagem articular (cristais de pirofosfato de cálcio dihidratado)", "Músculo", "Tendões apenas"], correctIndex: 1, explanation: "A pseudogota é causada por depósito de cristais de pirofosfato de cálcio (CPPD) na cartilagem articular. Os cristais têm birrefringência positiva sob luz polarizada, diferente do urato da gota." },
  { id: 232, topic: "Tecido Cartilaginoso", question: "O colágeno tipo XI na cartilagem:", options: ["Forma fibras espessas", "Regula o diâmetro das fibrilas de colágeno tipo II", "Constitui a lâmina basal", "É encontrado apenas na fibrocartilagem"], correctIndex: 1, explanation: "O colágeno tipo XI co-polimeriza com o tipo II e regula o diâmetro das fibrilas colágenas na cartilagem, mantendo fibrilas finas que permitem a transparência e as propriedades biomecânicas." },
  { id: 233, topic: "Tecido Cartilaginoso", question: "A condrodisplasia punctata é caracterizada por:", options: ["Excesso de cartilagem", "Calcificações puntiformes na cartilagem de crescimento", "Ausência de cartilagem", "Hiperplasia do pericôndrio"], correctIndex: 1, explanation: "A condrodisplasia punctata engloba distúrbios genéticos com calcificações puntiformes (stippling) nas epífises e cartilagens, comprometendo o crescimento esquelético." },
  { id: 234, topic: "Tecido Cartilaginoso", question: "A zona de reserva da placa epifisária contém:", options: ["Condrócitos em colunas ativas", "Condrócitos pequenos dispersos em matriz abundante (pool de células-tronco)", "Osteoclastos", "Vasos sanguíneos"], correctIndex: 1, explanation: "A zona de reserva (repouso) contém condrócitos pequenos e dispersos em matriz abundante, servindo como reservatório de células progenitoras e ancoragem da placa à epífise." },
  { id: 235, topic: "Tecido Cartilaginoso", question: "A COMP (cartilage oligomeric matrix protein) é:", options: ["Uma enzima degradativa", "Uma proteína não-colágena importante para organização da MEC cartilaginosa", "Um fator de crescimento", "Uma citocina inflamatória"], correctIndex: 1, explanation: "A COMP (trombospondina-5) é uma glicoproteína pentamérica da MEC cartilaginosa que interage com colágenos e integrinas. Seus níveis séricos podem servir como biomarcador de degradação cartilaginosa." },
  { id: 236, topic: "Tecido Cartilaginoso", question: "A cartilagem hialina em adultos pode calcificar em:", options: ["Nunca calcifica", "Cartilagem costal e placa epifisária com a idade", "Apenas na orelha", "Apenas na epiglote"], correctIndex: 1, explanation: "A cartilagem hialina pode sofrer calcificação distrófica com o envelhecimento, especialmente nas cartilagens costais e na zona de calcificação da placa epifisária (fisiológica)." },
  { id: 237, topic: "Tecido Cartilaginoso", question: "Os condrócitos são responsáveis por:", options: ["Reabsorção óssea", "Síntese e manutenção da matriz cartilaginosa", "Produção de mielina", "Contração muscular"], correctIndex: 1, explanation: "Os condrócitos são as únicas células da cartilagem, residindo em lacunas. São responsáveis pela síntese contínua de colágeno tipo II, proteoglicanos e manutenção da homeostase da matriz." },
  { id: 238, topic: "Tecido Cartilaginoso", question: "Na zona de hipertrofia da placa epifisária, os condrócitos:", options: ["Proliferam ativamente", "Aumentam de volume, secretam VEGF e entram em apoptose", "Formam colágeno tipo I", "Migram para o periósteo"], correctIndex: 1, explanation: "Na zona de hipertrofia, condrócitos aumentam 5-10x de volume, produzem colágeno tipo X, secretam VEGF (induz angiogênese) e entram em apoptose, permitindo a invasão vascular e ossificação." },
  { id: 239, topic: "Tecido Cartilaginoso", question: "O colágeno tipo X é marcador específico de:", options: ["Cartilagem articular normal", "Condrócitos hipertróficos na placa epifisária", "Fibrocartilagem", "Cartilagem elástica"], correctIndex: 1, explanation: "O colágeno tipo X é sintetizado exclusivamente por condrócitos hipertróficos na zona de calcificação da placa epifisária, sendo marcador de diferenciação terminal." },
  { id: 240, topic: "Tecido Cartilaginoso", question: "A policondrite recidivante é uma doença:", options: ["Infecciosa", "Autoimune que destrói cartilagens (auricular, nasal, traqueal)", "Neoplásica", "Degenerativa"], correctIndex: 1, explanation: "A policondrite recidivante é uma doença autoimune rara com inflamação destrutiva de cartilagens (orelha, nariz, vias aéreas, articulações), provavelmente mediada por anticorpos anti-colágeno tipo II." },
  { id: 241, topic: "Tecido Cartilaginoso", question: "As fibras elásticas na cartilagem elástica são melhor visualizadas pela:", options: ["Coloração H&E", "Coloração de Verhoeff ou orceína", "PAS", "Tricrômico de Masson"], correctIndex: 1, explanation: "As fibras elásticas na cartilagem elástica são melhor evidenciadas pela coloração de Verhoeff (elastina em preto) ou orceína (elastina em marrom), pois em H&E são pouco visíveis." },
  { id: 242, topic: "Tecido Cartilaginoso", question: "O Indian hedgehog (Ihh) na placa epifisária regula:", options: ["Apoptose dos osteoclastos", "A taxa de proliferação e hipertrofia dos condrócitos", "A formação de mielina", "A secreção de surfactante"], correctIndex: 1, explanation: "O Ihh é um fator parácrino secretado por condrócitos pré-hipertróficos que estimula a proliferação de condrócitos e regula o PTHrP, controlando a transição entre proliferação e hipertrofia." },
  { id: 243, topic: "Tecido Cartilaginoso", question: "A matriz interterritorial da cartilagem hialina é rica em:", options: ["Proteoglicanos", "Colágeno tipo II (fibrilar)", "Fibras elásticas", "Colágeno tipo I"], correctIndex: 1, explanation: "A matriz interterritorial (entre os grupos isógenos) é proporcionalmente mais rica em colágeno tipo II do que em proteoglicanos, enquanto a territorial é o inverso." },
  { id: 244, topic: "Tecido Cartilaginoso", question: "A tireoideia é uma cartilagem da laringe do tipo:", options: ["Elástica", "Fibrosa", "Hialina", "Mista"], correctIndex: 2, explanation: "As cartilagens tireoide, cricoide e aritenoides da laringe são de cartilagem hialina e podem calcificar com a idade. As cartilagens corniculada, cuneiforme e epiglote são elásticas." },
  { id: 245, topic: "Tecido Cartilaginoso", question: "A enzima agrecanase (ADAMTS-4/5) degrada:", options: ["Colágeno tipo I", "Agrecano na cartilagem articular", "Elastina", "Fibronectina"], correctIndex: 1, explanation: "As agrecanases ADAMTS-4 e ADAMTS-5 são as principais enzimas responsáveis pela clivagem do agrecano na cartilagem articular, tendo papel central na osteoartrite." },
  { id: 246, topic: "Tecido Cartilaginoso", question: "O núcleo pulposo do disco intervertebral origina-se embriologicamente de:", options: ["Mesoderma paraxial", "Notocorda", "Ectoderma", "Endoderma"], correctIndex: 1, explanation: "O núcleo pulposo é remanescente da notocorda embrionária, composto por material gelatinoso rico em água, proteoglicanos e colágeno tipo II, cercado pelo anel fibroso (fibrocartilagem)." },
  { id: 247, topic: "Tecido Cartilaginoso", question: "A osteocondrose é uma condição que envolve:", options: ["Excesso de crescimento cartilaginoso", "Necrose avascular do osso subcondral que afeta a cartilagem sobrejacente", "Infecção da cartilagem", "Calcificação excessiva"], correctIndex: 1, explanation: "A osteocondrose (ex: doença de Legg-Calvé-Perthes, Osgood-Schlatter) envolve necrose avascular do osso subcondral em áreas de crescimento, afetando secundariamente a cartilagem." },
  { id: 248, topic: "Tecido Cartilaginoso", question: "Os condroblastos diferem dos condrócitos porque:", options: ["São maiores", "Estão na periferia da cartilagem (pericôndrio) e secretam ativamente nova matriz", "São multinucleados", "Não possuem REG"], correctIndex: 1, explanation: "Os condroblastos são células jovens e ativas da camada condrogênica do pericôndrio que sintetizam ativamente a matriz. Quando se tornam aprisionados na matriz, passam a ser chamados condrócitos." },
  { id: 249, topic: "Tecido Cartilaginoso", question: "A condromalácia patelar é:", options: ["Um tumor", "Amolecimento e degeneração da cartilagem articular da patela", "Infecção da cartilagem", "Calcificação da patela"], correctIndex: 1, explanation: "A condromalácia patelar é o amolecimento e degeneração progressiva da cartilagem articular da face posterior da patela, comum em jovens, causando dor anterior no joelho." },
  { id: 250, topic: "Tecido Cartilaginoso", question: "A cartilagem de crescimento fecha-se quando:", options: ["A vascularização aumenta na infância", "Os condrócitos param de proliferar e a placa é substituída por osso na maturidade esquelética", "O pericôndrio se espessa", "Ocorre metaplasia muscular"], correctIndex: 1, explanation: "Na maturidade esquelética, a proliferação de condrócitos na placa epifisária cessa (influência hormonal), e toda a cartilagem é substituída por osso (linha epifisária), encerrando o crescimento longitudinal." },

  // =============================================
  // TECIDO ÓSSEO (251-300)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 251, topic: "Tecido Ósseo", question: "Quais são as células responsáveis pela reabsorção óssea?", options: ["Osteoblastos", "Osteócitos", "Osteoclastos", "Condroblastos"], correctIndex: 2, explanation: "Os osteoclastos são células gigantes multinucleadas derivadas de monócitos que promovem a reabsorção óssea através da liberação de enzimas e H⁺ na lacuna de Howship." },
  { id: 252, topic: "Tecido Ósseo", question: "Qual estrutura constitui a unidade funcional do osso compacto?", options: ["Trabécula", "Ósteon (sistema de Havers)", "Periósteo", "Endósteo"], correctIndex: 1, explanation: "O ósteon é formado por lamelas concêntricas ao redor de um canal central (de Havers) contendo vasos sanguíneos e nervos." },
  { id: 253, topic: "Tecido Ósseo", question: "Na ossificação endocondral, qual é a zona da placa epifisária com calcificação da matriz?", options: ["Zona de reserva", "Zona de proliferação", "Zona de hipertrofia/calcificação", "Zona de repouso"], correctIndex: 2, explanation: "Na zona de hipertrofia, os condrócitos aumentam de volume, a matriz calcifica e os condrócitos entram em apoptose, sendo substituídos por tecido ósseo." },
  { id: 254, topic: "Tecido Ósseo", question: "A via RANK/RANKL/OPG regula:", options: ["Formação de cartilagem", "Remodelação óssea (diferenciação e ativação de osteoclastos)", "Hematopoiese", "Contração muscular"], correctIndex: 1, explanation: "RANKL (produzido por osteoblastos/osteócitos) ativa RANK nos precursores de osteoclastos. OPG é um receptor decoy que bloqueia RANKL, protegendo o osso da reabsorção excessiva." },
  { id: 255, topic: "Tecido Ósseo", question: "Os osteócitos comunicam-se entre si através de:", options: ["Gap junctions nos canalículos", "Exocitose de vesículas", "Difusão passiva apenas", "Sinapses químicas"], correctIndex: 0, explanation: "Os osteócitos emitem prolongamentos citoplasmáticos pelos canalículos da matriz óssea, conectando-se por gap junctions para comunicação e troca de nutrientes." },
  { id: 256, topic: "Tecido Ósseo", question: "A ossificação intramembranosa ocorre em quais ossos?", options: ["Fêmur e tíbia", "Ossos chatos do crânio, face e clavícula", "Vértebras", "Costelas"], correctIndex: 1, explanation: "Na ossificação intramembranosa, células mesenquimais diferenciam-se diretamente em osteoblastos sem molde cartilaginoso, formando ossos chatos do crânio, mandíbula e clavícula." },
  { id: 257, topic: "Tecido Ósseo", question: "O periósteo é composto por:", options: ["Cartilagem", "TC denso com camada osteogênica interna", "Tecido epitelial", "Tecido muscular"], correctIndex: 1, explanation: "O periósteo possui camada fibrosa externa (TC denso) e camada osteogênica interna com células osteoprogenitoras, essencial para crescimento aposicional e reparo de fraturas." },
  { id: 258, topic: "Tecido Ósseo", question: "A fosfatase alcalina é marcador de atividade de:", options: ["Osteoclastos", "Osteoblastos", "Osteócitos", "Condrócitos"], correctIndex: 1, explanation: "A fosfatase alcalina é expressa na superfície dos osteoblastos e participa da mineralização da matriz óssea. Seus níveis séricos refletem atividade osteoblástica." },
  { id: 259, topic: "Tecido Ósseo", question: "A TRAP é marcador histoquímico de:", options: ["Osteoblastos", "Osteoclastos", "Fibroblastos", "Condrócitos"], correctIndex: 1, explanation: "A TRAP (fosfatase ácida resistente ao tartarato) é uma enzima expressa pelos osteoclastos, utilizada como marcador histoquímico e sérico de atividade de reabsorção." },
  { id: 260, topic: "Tecido Ósseo", question: "Os canais de Volkmann conectam:", options: ["Osteócitos entre si", "Canais de Havers entre si e com o periósteo/endósteo", "Trabéculas ósseas", "Medula e córtex"], correctIndex: 1, explanation: "Os canais de Volkmann são canais transversais/oblíquos que conectam canais de Havers adjacentes e com a superfície óssea, permitindo passagem de vasos sanguíneos." },
  { id: 261, topic: "Tecido Ósseo", question: "A matriz orgânica do osso (osteoide) é composta por:", options: ["Apenas hidroxiapatita", "~90% colágeno tipo I + glicoproteínas (osteocalcina, osteopontina)", "Colágeno tipo II + agrecano", "Elastina + fibrilina"], correctIndex: 1, explanation: "O osteoide é a fração orgânica (~35% da matriz óssea), composta predominantemente por colágeno tipo I, além de osteocalcina, osteopontina, osteonectina e proteoglicanos." },
  { id: 262, topic: "Tecido Ósseo", question: "A fração mineral do osso é composta por cristais de:", options: ["Carbonato de cálcio", "Hidroxiapatita [Ca₁₀(PO₄)₆(OH)₂]", "Oxalato de cálcio", "Fosfato de magnésio"], correctIndex: 1, explanation: "Os cristais de hidroxiapatita representam ~65% da massa óssea, depositados sobre e entre as fibrilas de colágeno tipo I, conferindo rigidez e resistência à compressão." },
  { id: 263, topic: "Tecido Ósseo", question: "O osso esponjoso (trabecular) é encontrado em:", options: ["Diáfise dos ossos longos", "Epífises de ossos longos e interior de ossos chatos", "Apenas no crânio", "Apenas nos dentes"], correctIndex: 1, explanation: "O osso esponjoso forma uma rede de trabéculas interconectadas nas epífises e no interior de ossos chatos, com espaços medulares preenchidos por medula óssea." },
  { id: 264, topic: "Tecido Ósseo", question: "O endósteo reveste:", options: ["A superfície externa do osso", "As superfícies internas (cavidade medular, canais de Havers e trabéculas)", "Articulações", "Tendões"], correctIndex: 1, explanation: "O endósteo é uma camada fina de células osteoprogenitoras e osteoblastos que reveste todas as superfícies internas do osso, participando na remodelação e reparo." },
  { id: 265, topic: "Tecido Ósseo", question: "A osteoporose é caracterizada por:", options: ["Defeito na mineralização", "Redução da massa óssea com mineralização normal", "Excesso de osteoblastos", "Infecção óssea"], correctIndex: 1, explanation: "Na osteoporose, há redução da massa óssea com composição normal do osso remanescente, diferente da osteomalácia onde há defeito de mineralização do osteoide." },
  { id: 266, topic: "Tecido Ósseo", question: "O PTH aumenta a calcemia por:", options: ["Inibir osteoclastos", "Estimular osteoclastos, aumentar reabsorção renal de Ca²⁺ e ativar vitamina D", "Depositar cálcio no osso", "Estimular tireoide"], correctIndex: 1, explanation: "O PTH eleva calcemia por três mecanismos: estimula osteoclastos (via RANKL dos osteoblastos), aumenta reabsorção tubular renal de Ca²⁺ e ativa 1α-hidroxilase renal (vitamina D ativa)." },
  { id: 267, topic: "Tecido Ósseo", question: "A calcitonina atua:", options: ["Estimulando osteoclastos", "Inibindo osteoclastos e diminuindo calcemia", "Aumentando PTH", "Ativando vitamina D"], correctIndex: 1, explanation: "A calcitonina é produzida pelas células parafoliculares (C) da tireoide e inibe diretamente a atividade dos osteoclastos, reduzindo a reabsorção óssea e a calcemia." },
  { id: 268, topic: "Tecido Ósseo", question: "O raquitismo/osteomalácia resulta de deficiência de:", options: ["Proteína C", "Vitamina D e/ou cálcio (mineralização defeituosa)", "Vitamina C", "Ferro"], correctIndex: 1, explanation: "A deficiência de vitamina D causa mineralização inadequada do osteoide. Em crianças: raquitismo (deformidades). Em adultos: osteomalácia (dor óssea, fraturas)." },
  { id: 269, topic: "Tecido Ósseo", question: "As lamelas intersticiais no osso compacto representam:", options: ["Novo osso em formação", "Remanescentes de ósteons parcialmente remodelados", "Canais vasculares", "Células-tronco"], correctIndex: 1, explanation: "As lamelas intersticiais são restos de ósteons antigos que foram parcialmente reabsorvidos e remodelados, preenchendo os espaços entre ósteons novos (remodelação contínua)." },
  { id: 270, topic: "Tecido Ósseo", question: "As fibras de Sharpey são:", options: ["Fibras nervosas do osso", "Fibras colágenas do periósteo que penetram na cortical óssea", "Fibras elásticas endosteais", "Fibras musculares que se inserem no osso"], correctIndex: 1, explanation: "As fibras de Sharpey são feixes de colágeno do periósteo (ou tendões/ligamentos) que penetram no osso cortical, ancorando firmemente o periósteo e estruturas ao osso." },
  { id: 271, topic: "Tecido Ósseo", question: "A doença de Paget do osso é caracterizada por:", options: ["Mineralização defeituosa", "Remodelação óssea excessiva e desordenada com osso mosaico", "Ausência de osteoclastos", "Escorbuto"], correctIndex: 1, explanation: "Na doença de Paget, há reabsorção e formação óssea aceleradas e desordenadas, resultando em osso mosaico (padrão de linhas cimentantes irregulares) com deformidades." },
  { id: 272, topic: "Tecido Ósseo", question: "O osso primário (imaturo/trançado) difere do lamelar por:", options: ["Ser mais resistente", "Ter fibras colágenas desorganizadas e mais osteócitos", "Ter ósteons regulares", "Possuir menos células"], correctIndex: 1, explanation: "O osso primário (woven) tem colágeno desorganizado, mais osteócitos e menor resistência. É o primeiro osso formado (fetal, fraturas) e é gradualmente substituído por osso lamelar maduro." },
  { id: 273, topic: "Tecido Ósseo", question: "O Runx2/Cbfa1 é um fator de transcrição essencial para:", options: ["Condrogênese", "Diferenciação de osteoblastos", "Miogênese", "Neurogênese"], correctIndex: 1, explanation: "O Runx2 é o principal regulador da diferenciação osteoblástica, ativando genes como osteocalcina, colágeno tipo I e fosfatase alcalina. Sua ausência impede a formação de osso." },
  { id: 274, topic: "Tecido Ósseo", question: "Os osteócitos são as células mais abundantes do osso maduro e funcionam como:", options: ["Células de reabsorção", "Mecanossensores que regulam a remodelação óssea", "Células inflamatórias", "Células de suporte vascular"], correctIndex: 1, explanation: "Os osteócitos são mecanossensores que detectam estresse mecânico e regulam a atividade de osteoblastos e osteoclastos, coordenando a remodelação óssea adaptativa." },
  { id: 275, topic: "Tecido Ósseo", question: "A linha cimentante no osso compacto representa:", options: ["Um vaso sanguíneo", "O limite entre o osso antigo reabsorvido e o novo osso depositado", "Um nervo", "Uma célula osteoblástica"], correctIndex: 1, explanation: "As linhas cimentantes são interfaces entre osso antigo (reabsorvido) e novo (depositado), ricas em proteoglicanos e pobres em colágeno, refletindo ciclos de remodelação." },
  { id: 276, topic: "Tecido Ósseo", question: "O osteossarcoma é o tumor ósseo primário mais comum, com pico de incidência em:", options: ["Crianças < 5 anos", "Adolescentes e adultos jovens (10-20 anos)", "Adultos 40-50 anos", "Idosos > 70 anos"], correctIndex: 1, explanation: "O osteossarcoma é mais comum entre 10-20 anos (período de crescimento rápido), localizado preferencialmente na metáfise de ossos longos (fêmur distal, tíbia proximal)." },
  { id: 277, topic: "Tecido Ósseo", question: "A osteomielite aguda é mais frequentemente causada por:", options: ["E. coli", "Staphylococcus aureus", "Streptococcus mutans", "Pseudomonas"], correctIndex: 1, explanation: "S. aureus é o agente mais comum de osteomielite em todas as faixas etárias, causando necrose óssea (sequestro) com formação de abscesso intraósseo e involucro de osso reativo." },
  { id: 278, topic: "Tecido Ósseo", question: "A vitamina D ativa (1,25-dihidroxivitamina D) promove:", options: ["Reabsorção óssea direta", "Absorção intestinal de Ca²⁺ e PO₄", "Secreção de calcitonina", "Inibição do PTH diretamente no osso"], correctIndex: 1, explanation: "A 1,25(OH)₂D₃ (calcitriol) é a forma ativa que aumenta a absorção intestinal de cálcio e fosfato, essencial para a mineralização óssea adequada." },
  { id: 279, topic: "Tecido Ósseo", question: "O crescimento em espessura dos ossos ocorre por:", options: ["Ossificação endocondral", "Crescimento aposicional a partir do periósteo", "Crescimento intersticial", "Expansão da cavidade medular"], correctIndex: 1, explanation: "O crescimento em espessura (diâmetro) ocorre por aposição óssea periosteal: osteoblastos do periósteo depositam osso na superfície externa enquanto osteoclastos reabsorvem internamente." },
  { id: 280, topic: "Tecido Ósseo", question: "O osso cortical (compacto) compõe aproximadamente:", options: ["20% da massa esquelética", "80% da massa esquelética", "50% da massa esquelética", "10% da massa esquelética"], correctIndex: 1, explanation: "O osso cortical representa ~80% da massa esquelética total, formando a camada externa densa dos ossos. O osso esponjoso (~20%) tem maior área de superfície e metabolismo mais ativo." },
  { id: 281, topic: "Tecido Ósseo", question: "A esclerostina é uma proteína produzida por osteócitos que:", options: ["Estimula formação óssea", "Inibe a via Wnt, suprimindo a formação óssea", "Ativa osteoclastos", "Produz colágeno"], correctIndex: 1, explanation: "A esclerostina (gene SOST) é produzida por osteócitos e inibe a via Wnt nos osteoblastos, suprimindo a formação óssea. Anticorpos anti-esclerostina (romosozumab) são usados no tratamento de osteoporose." },
  { id: 282, topic: "Tecido Ósseo", question: "O calo ósseo na cicatrização de fraturas forma-se por:", options: ["Apenas ossificação intramembranosa", "Ossificação endocondral (calo cartilaginoso → osso) e intramembranosa", "Regeneração de osteócitos", "Apenas deposição mineral"], correctIndex: 1, explanation: "O reparo de fraturas envolve ambos mecanismos: ossificação intramembranosa no periósteo (calo duro) e endocondral na região de instabilidade (calo cartilaginoso que se ossifica)." },
  { id: 283, topic: "Tecido Ósseo", question: "O estrogênio protege contra osteoporose porque:", options: ["Estimula osteoclastos", "Promove apoptose de osteoclastos e estimula OPG nos osteoblastos", "Aumenta PTH", "Diminui absorção de cálcio"], correctIndex: 1, explanation: "O estrogênio inibe a reabsorção óssea promovendo apoptose de osteoclastos, estimulando OPG e inibindo RANKL e citocinas pró-reabsortivas. A menopausa acelera a perda óssea." },
  { id: 284, topic: "Tecido Ósseo", question: "A lacuna de Howship é:", options: ["Uma cavidade onde residem osteócitos", "A depressão na superfície óssea sob o osteoclasto ativo (zona de reabsorção)", "O canal de Havers", "O espaço medular"], correctIndex: 1, explanation: "A lacuna de Howship (ou baía de reabsorção) é a depressão escavada na superfície óssea pelo osteoclasto, onde a borda em escova libera H⁺ e enzimas lisossomais para degradação." },
  { id: 285, topic: "Tecido Ósseo", question: "O denosumab é um anticorpo monoclonal que age:", options: ["Estimulando osteoblastos", "Bloqueando RANKL (inibindo osteoclastos)", "Ativando PTH", "Estimulando vitamina D"], correctIndex: 1, explanation: "O denosumab é um anti-RANKL que mimetiza a ação da OPG, impedindo a ligação RANKL-RANK e inibindo a diferenciação e atividade dos osteoclastos. Usado na osteoporose e metástases ósseas." },
  { id: 286, topic: "Tecido Ósseo", question: "O colágeno tipo I no osso é organizado em:", options: ["Redes tridimensionais", "Lamelas concêntricas ou paralelas no osso maduro", "Feixes paralelos como tendões", "Fibrilas sem organização"], correctIndex: 1, explanation: "No osso lamelar maduro, as fibras de colágeno tipo I estão organizadas em lamelas com orientação alternada, conferindo resistência multidirecional (similar ao compensado de madeira)." },
  { id: 287, topic: "Tecido Ósseo", question: "O sarcoma de Ewing é um tumor ósseo que afeta:", options: ["Idosos", "Crianças e adolescentes, com células pequenas azuis redondas", "Apenas adultos", "Apenas a coluna vertebral"], correctIndex: 1, explanation: "O sarcoma de Ewing afeta crianças/adolescentes com células azuis pequenas redondas. A translocação t(11;22) cria o gene de fusão EWSR1-FLI1 em >85% dos casos." },
  { id: 288, topic: "Tecido Ósseo", question: "A osteocalcina produzida pelos osteoblastos:", options: ["Degrada colágeno", "Regula a mineralização e funciona como hormônio (metabolismo de glicose)", "Reabsorve osso", "Produz ácido clorídrico"], correctIndex: 1, explanation: "A osteocalcina é a proteína não-colágena mais abundante do osso, produzida por osteoblastos. Liga cálcio e regula mineralização; como hormônio, melhora sensibilidade insulínica." },
  { id: 289, topic: "Tecido Ósseo", question: "O osso woven (primário) é encontrado em adultos normalmente apenas em:", options: ["Todo o esqueleto", "Locais de inserção de tendões e alvéolos dentários", "Fêmur", "Crânio inteiro"], correctIndex: 1, explanation: "Em adultos, o osso woven (primário) é encontrado fisiologicamente nos locais de inserção de tendões (fibras de Sharpey) e alvéolos dentários. Sua presença em outros locais é patológica (fratura, Paget, tumor)." },
  { id: 290, topic: "Tecido Ósseo", question: "O bisfosfonato atua no tratamento da osteoporose:", options: ["Estimulando osteoblastos", "Inibindo a atividade de reabsorção dos osteoclastos (incorpora-se à hidroxiapatita)", "Aumentando PTH", "Estimulando absorção de cálcio"], correctIndex: 1, explanation: "Os bisfosfonatos (alendronato, risedronato) incorporam-se à matriz óssea mineralizada e, quando reabsorvidos por osteoclastos, inibem a farnesil-difosfato sintase, causando apoptose do osteoclasto." },
  { id: 291, topic: "Tecido Ósseo", question: "A teriparatida (PTH recombinante) em doses intermitentes:", options: ["Causa reabsorção óssea", "Estimula a formação óssea (efeito anabólico)", "Inibe osteoblastos", "Aumenta o escorbuto"], correctIndex: 1, explanation: "O PTH intermitente (injeções diárias) paradoxalmente estimula osteoblastos e formação óssea (efeito anabólico). O PTH contínuo elevado (hiperparatireoidismo) causa reabsorção." },
  { id: 292, topic: "Tecido Ósseo", question: "A medula óssea vermelha é encontrada no adulto em:", options: ["Diáfise do fêmur", "Ossos chatos (crânio, esterno, costelas), vértebras e epífises proximais", "Apenas no timo", "Apenas na tireoide"], correctIndex: 1, explanation: "No adulto, a medula vermelha hematopoiética concentra-se nos ossos chatos, vértebras, costelas, esterno, ilíaco e epífises proximais do fêmur e úmero. Na diáfise, é substituída por medula amarela (gordura)." },
  { id: 293, topic: "Tecido Ósseo", question: "O escorbuto causa fragilidade óssea porque:", options: ["Há defeito na mineralização", "A deficiência de vitamina C impede a hidroxilação do colágeno (osteoide defeituoso)", "Há excesso de osteoclastos", "Ocorre calcificação excessiva"], correctIndex: 1, explanation: "No escorbuto, a deficiência de vitamina C compromete a prolil/lisil hidroxilação do colágeno, resultando em osteoide defeituoso, fragilidade vascular, hemorragias e má cicatrização." },
  { id: 294, topic: "Tecido Ósseo", question: "A osteoclastogênese requer os fatores:", options: ["Insulina e glucagon", "M-CSF e RANKL (produzidos por osteoblastos/estroma)", "Eritropoetina e trombopoetina", "T3 e T4"], correctIndex: 1, explanation: "A diferenciação de precursores monocíticos em osteoclastos maduros requer M-CSF (proliferação/sobrevida) e RANKL (diferenciação/ativação), ambos produzidos por osteoblastos e células do estroma." },
  { id: 295, topic: "Tecido Ósseo", question: "O sistema de Havers versus sistema circunferencial do osso compacto:", options: ["São idênticos", "Havers = lamelas concêntricas; circunferencial = lamelas na periferia sob periósteo e endósteo", "Circunferencial = canais vasculares", "Havers = trabéculas"], correctIndex: 1, explanation: "As lamelas circunferenciais externas (subperiosteais) e internas (subendosteais) envolvem toda a circunferência do osso cortical, enquanto os ósteons de Havers são unidades cilíndricas internas." },
  { id: 296, topic: "Tecido Ósseo", question: "A osteopetrose (doença dos ossos de mármore) resulta de:", options: ["Excesso de osteoclastos", "Defeito na função dos osteoclastos (incapacidade de reabsorver osso)", "Excesso de vitamina D", "Deficiência de osteoblastos"], correctIndex: 1, explanation: "Na osteopetrose, mutações em genes essenciais para osteoclastos (anidrase carbônica II, bomba de H⁺, ClC-7) resultam em osso denso mas frágil, obliteração medular e pancitopenia." },
  { id: 297, topic: "Tecido Ósseo", question: "A lei de Wolff afirma que:", options: ["O osso cresce apenas na infância", "O osso adapta sua arquitetura em resposta às forças mecânicas", "Os osteoclastos são mais importantes que osteoblastos", "A mineralização é independente da atividade física"], correctIndex: 1, explanation: "A lei de Wolff estabelece que o osso se remodela em resposta às cargas mecânicas: áreas de maior estresse recebem mais osso (formação > reabsorção), e áreas sem carga perdem osso." },
  { id: 298, topic: "Tecido Ósseo", question: "O M-CSF no metabolismo ósseo é produzido por:", options: ["Osteoclastos", "Osteoblastos e células estromais da medula", "Hepatócitos", "Condrócitos"], correctIndex: 1, explanation: "O M-CSF (fator estimulador de colônias de macrófagos) é produzido por osteoblastos e células estromais, sendo essencial para sobrevida, proliferação e diferenciação de precursores osteoclásticos." },
  { id: 299, topic: "Tecido Ósseo", question: "A osteocitólise osteocítica é o processo pelo qual:", options: ["Osteoclastos reabsorvem osso", "Osteócitos podem remover mineral ao redor de suas lacunas para regular a calcemia", "Osteoblastos formam osteoide", "Condrócitos calcificam a matriz"], correctIndex: 1, explanation: "Osteócitos podem mobilizar cálcio da matriz perilacunar e pericanalicular (osteólise osteocítica), respondendo rapidamente ao PTH para regulação fina da calcemia." },
  { id: 300, topic: "Tecido Ósseo", question: "O osso lamelar maduro possui lamelas com fibras colágenas em:", options: ["Orientação aleatória", "Orientação alternada entre lamelas adjacentes (tipo compensado)", "Apenas paralelas", "Apenas perpendiculares"], correctIndex: 1, explanation: "No osso lamelar, as fibras colágenas de cada lamela estão orientadas de forma diferente da lamela adjacente, criando um arranjo tipo 'compensado' que confere máxima resistência multidirecional." },

  // =============================================
  // SANGUE E HEMATOPOIESE (301-350)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 301, topic: "Sangue e Hematopoiese", question: "Qual leucócito é o mais abundante no sangue periférico?", options: ["Linfócito", "Monócito", "Neutrófilo", "Eosinófilo"], correctIndex: 2, explanation: "Os neutrófilos representam 60-70% dos leucócitos circulantes e são a primeira linha de defesa na imunidade inata contra bactérias." },
  { id: 302, topic: "Sangue e Hematopoiese", question: "Qual célula sanguínea é anucleada e tem forma de disco bicôncavo?", options: ["Plaqueta", "Eritrócito", "Monócito", "Basófilo"], correctIndex: 1, explanation: "Os eritrócitos maduros são anucleados e possuem forma bicôncava (7-8 μm), maximizando a área de superfície para trocas gasosas e flexibilidade para capilares." },
  { id: 303, topic: "Sangue e Hematopoiese", question: "Os eosinófilos são importantes na defesa contra:", options: ["Bactérias gram-negativas", "Parasitas helmínticos e reações alérgicas", "Vírus", "Fungos"], correctIndex: 1, explanation: "Os eosinófilos possuem grânulos com MBP (proteína básica principal) e peroxidase, particularmente eficazes contra parasitas helmínticos." },
  { id: 304, topic: "Sangue e Hematopoiese", question: "As plaquetas são fragmentos citoplasmáticos derivados de:", options: ["Monócito", "Megacariócito", "Mieloblasto", "Reticulócito"], correctIndex: 1, explanation: "Os megacariócitos são células gigantes poliploides da medula óssea que fragmentam seu citoplasma para formar 2.000-5.000 plaquetas cada." },
  { id: 305, topic: "Sangue e Hematopoiese", question: "A eritropoetina (EPO) é produzida principalmente por:", options: ["Medula óssea", "Fígado", "Rins (células peritubulares intersticiais)", "Baço"], correctIndex: 2, explanation: "A EPO é produzida pelas células peritubulares intersticiais do córtex renal em resposta à hipóxia, estimulando a eritropoiese na medula óssea." },
  { id: 306, topic: "Sangue e Hematopoiese", question: "Os basófilos contêm grânulos ricos em:", options: ["Peroxidase e MBP", "Histamina e heparina", "Lisozima e lactoferrina", "Granzimas e perforinas"], correctIndex: 1, explanation: "Os basófilos possuem grânulos metacromáticos com histamina, heparina e leucotrienos, similares aos mastócitos teciduais, participando de reações alérgicas." },
  { id: 307, topic: "Sangue e Hematopoiese", question: "Os reticulócitos são:", options: ["Leucócitos imaturos", "Eritrócitos jovens com restos de RNA ribossômico", "Precursores de plaquetas", "Linfócitos ativados"], correctIndex: 1, explanation: "Os reticulócitos são eritrócitos recém-liberados da medula que ainda contêm restos de RNA (corados com azul de cresil brilhante). Representam 0,5-2% dos eritrócitos circulantes." },
  { id: 308, topic: "Sangue e Hematopoiese", question: "As células NK pertencem a qual linhagem?", options: ["Mieloide", "Linfoide", "Eritroide", "Megacariocítica"], correctIndex: 1, explanation: "As células NK são linfócitos da imunidade inata que destroem células infectadas e tumorais via granzimas e perforinas, sem necessidade de MHC-I (reconhecem 'missing self')." },
  { id: 309, topic: "Sangue e Hematopoiese", question: "As NETs são formadas por:", options: ["Anticorpos secretados", "DNA, histonas e proteínas antimicrobianas expulsos pelo neutrófilo", "Fragmentos de plaquetas", "RNA ribossômico"], correctIndex: 1, explanation: "As NETs (neutrophil extracellular traps) são redes de DNA descondensado com histonas e enzimas antimicrobianas que capturam e destroem patógenos extracelulares (NETose)." },
  { id: 310, topic: "Sangue e Hematopoiese", question: "O monócito diferencia-se em macrófago quando:", options: ["Permanece no sangue por muito tempo", "Migra para os tecidos", "É estimulado por EPO", "Sofre meiose"], correctIndex: 1, explanation: "Os monócitos circulam no sangue por 1-3 dias e, ao migrarem para os tecidos, diferenciam-se em macrófagos teciduais (histiócitos, Kupffer, microglia, etc.)." },
  { id: 311, topic: "Sangue e Hematopoiese", question: "A hemostasia primária envolve:", options: ["Cascata de coagulação", "Adesão e agregação plaquetária", "Fibrinólise", "Ativação do complemento"], correctIndex: 1, explanation: "A hemostasia primária envolve adesão plaquetária (GPIb-vWF), ativação (tromboxano A2, ADP) e agregação (GPIIb/IIIa-fibrinogênio), formando o tampão plaquetário." },
  { id: 312, topic: "Sangue e Hematopoiese", question: "A célula-tronco hematopoiética (HSC) é marcada por:", options: ["CD3", "CD34", "CD20", "CD56"], correctIndex: 1, explanation: "As HSCs expressam CD34 e CD117 (c-kit), residindo em nichos da medula óssea. São multipotentes, gerando todas as linhagens sanguíneas (mieloide e linfoide)." },
  { id: 313, topic: "Sangue e Hematopoiese", question: "Os neutrófilos possuem núcleo:", options: ["Redondo central", "Multilobulado (2-5 lobos)", "Em forma de rim", "Bilobulado apenas"], correctIndex: 1, explanation: "Os neutrófilos maduros possuem núcleo segmentado com 2-5 lobos conectados por finos filamentos de cromatina. 'Bastões' (band forms) são neutrófilos imaturos com núcleo em banda." },
  { id: 314, topic: "Sangue e Hematopoiese", question: "A coloração de Wright-Giemsa é utilizada para:", options: ["Fibras colágenas", "Esfregaço sanguíneo (diferenciação de leucócitos)", "Fibras elásticas", "Membrana basal"], correctIndex: 1, explanation: "A coloração de Wright-Giemsa cora o esfregaço sanguíneo: núcleos em azul-roxo e citoplasma em rosa. Permite diferenciação morfológica dos leucócitos e identificação de parasitas." },
  { id: 315, topic: "Sangue e Hematopoiese", question: "O fator de von Willebrand (vWF) é produzido por:", options: ["Hepatócitos apenas", "Endotélio (corpúsculos de Weibel-Palade) e megacariócitos", "Plaquetas apenas", "Eritrócitos"], correctIndex: 1, explanation: "O vWF é sintetizado pelo endotélio (armazenado nos corpúsculos de Weibel-Palade) e megacariócitos (grânulos α). Media adesão plaquetária ao subendotélio lesado (GPIb) e estabiliza fator VIII." },
  { id: 316, topic: "Sangue e Hematopoiese", question: "A eritropoiese segue a sequência:", options: ["HSC → reticulócito → eritrócito", "Proeritroblasto → eritroblasto basófilo → policromático → ortocromático → reticulócito → eritrócito", "Mieloblasto → promielócito → eritrócito", "Megacariócito → eritrócito"], correctIndex: 1, explanation: "A maturação eritroide envolve condensação progressiva do núcleo e acúmulo de hemoglobina: proeritroblasto → basófilo → policromático → ortocromático (expulsão do núcleo) → reticulócito → eritrócito." },
  { id: 317, topic: "Sangue e Hematopoiese", question: "Os grânulos azurófilos (primários) dos neutrófilos contêm:", options: ["Lactoferrina e colagenase", "Mieloperoxidase, lisozima e defensinas", "Histamina e heparina", "Perforinas e granzimas"], correctIndex: 1, explanation: "Os grânulos primários (azurófilos) são lisossomos modificados contendo mieloperoxidase (sistema MPO-H₂O₂-haleto), lisozima, defensinas e elastase." },
  { id: 318, topic: "Sangue e Hematopoiese", question: "O G-CSF (fator estimulador de colônias de granulócitos) estimula:", options: ["Eritropoiese", "Produção e maturação de neutrófilos", "Trombopoiese", "Linfocitopoiese"], correctIndex: 1, explanation: "O G-CSF estimula a proliferação e diferenciação de precursores de neutrófilos na medula óssea, além de mobilizar HSCs para o sangue periférico. Usado clinicamente na neutropenia." },
  { id: 319, topic: "Sangue e Hematopoiese", question: "A hemoglobina fetal (HbF) possui:", options: ["Duas cadeias α e duas β", "Duas cadeias α e duas γ", "Duas cadeias α e duas δ", "Quatro cadeias β"], correctIndex: 1, explanation: "A HbF (α₂γ₂) possui maior afinidade pelo O₂ que a HbA (α₂β₂), facilitando a transferência de O₂ da mãe para o feto. A transição para HbA ocorre nos primeiros 6 meses de vida." },
  { id: 320, topic: "Sangue e Hematopoiese", question: "As plaquetas são anucleadas mas contêm:", options: ["DNA nuclear", "Grânulos α (vWF, fibrinogênio, PDGF), grânulos densos (ADP, Ca²⁺, serotonina) e sistema canalicular", "Ribossomos livres apenas", "Núcleo fragmentado"], correctIndex: 1, explanation: "As plaquetas possuem grânulos α (fibrinogênio, vWF, PDGF, PF4), grânulos densos (ADP, ATP, Ca²⁺, serotonina), sistema canalicular aberto e sistema tubular denso (RS residual)." },
  { id: 321, topic: "Sangue e Hematopoiese", question: "A trombopoietina (TPO) é produzida principalmente pelo:", options: ["Rim", "Fígado", "Baço", "Medula óssea"], correctIndex: 1, explanation: "A TPO é produzida constitutivamente pelo fígado e estimula a produção de plaquetas por megacariócitos. Seus níveis são regulados pela massa plaquetária circulante." },
  { id: 322, topic: "Sangue e Hematopoiese", question: "Os linfócitos T maduros possuem qual marcador?", options: ["CD19", "CD3 (e CD4 ou CD8)", "CD14", "CD34"], correctIndex: 1, explanation: "Os linfócitos T maduros expressam CD3 (complexo TCR). Subdividem-se em T auxiliares (CD4+, reconhecem MHC-II) e T citotóxicos (CD8+, reconhecem MHC-I)." },
  { id: 323, topic: "Sangue e Hematopoiese", question: "Os linfócitos B maduros expressam:", options: ["CD3", "CD19 e CD20 (com IgM/IgD de superfície)", "CD56", "CD14"], correctIndex: 1, explanation: "Os linfócitos B maduros expressam CD19, CD20 e imunoglobulinas de superfície (IgM e IgD no B naïve), sendo responsáveis pela imunidade humoral (produção de anticorpos)." },
  { id: 324, topic: "Sangue e Hematopoiese", question: "O monócito é o maior leucócito circulante e possui núcleo:", options: ["Multilobulado", "Reniforme (em forma de rim ou ferradura)", "Bilobulado", "Redondo central"], correctIndex: 1, explanation: "O monócito (12-20 μm) é o maior leucócito no sangue periférico, com núcleo reniforme ou em ferradura e citoplasma azul-acinzentado com grânulos finos." },
  { id: 325, topic: "Sangue e Hematopoiese", question: "Os grânulos específicos (secundários) dos neutrófilos contêm:", options: ["Mieloperoxidase", "Lactoferrina, colagenase e lisozima", "Histamina", "Granzimas"], correctIndex: 1, explanation: "Os grânulos específicos (secundários) são os mais numerosos nos neutrófilos e contêm lactoferrina (quelante de ferro), colagenase tipo IV, lisozima e receptores de complemento." },
  { id: 326, topic: "Sangue e Hematopoiese", question: "A anemia falciforme resulta de:", options: ["Deficiência de ferro", "Mutação Glu6Val na cadeia β da hemoglobina (HbS)", "Deficiência de B12", "Defeito na membrana eritrocitária"], correctIndex: 1, explanation: "A HbS resulta da substituição de ácido glutâmico por valina na posição 6 da cadeia β, causando polimerização em baixa O₂ com falcização dos eritrócitos e crises vaso-oclusivas." },
  { id: 327, topic: "Sangue e Hematopoiese", question: "A vida média de um eritrócito é de:", options: ["7 dias", "30 dias", "120 dias", "365 dias"], correctIndex: 2, explanation: "Os eritrócitos circulam por ~120 dias antes de serem removidos por macrófagos no baço, fígado e medula óssea (eritrócitos senescentes perdem flexibilidade e externalizam fosfatidilserina)." },
  { id: 328, topic: "Sangue e Hematopoiese", question: "Os eosinófilos possuem grânulos com centro cristaloide que contém:", options: ["Histamina", "MBP (proteína básica principal)", "Mieloperoxidase", "Lactoferrina"], correctIndex: 1, explanation: "Os grânulos específicos dos eosinófilos possuem centro cristaloide contendo MBP (proteína tóxica para parasitas) e uma matriz contendo ECP, EDN e peroxidase eosinofílica." },
  { id: 329, topic: "Sangue e Hematopoiese", question: "A hematopoiese no feto inicia-se em:", options: ["Medula óssea", "Saco vitelino (3ª semana) → fígado (6ª semana) → medula óssea (5º mês)", "Timo", "Baço apenas"], correctIndex: 1, explanation: "A hematopoiese embrionária/fetal segue a sequência: saco vitelino (3ª semana, fase mesoblástica) → fígado e baço (6ª semana) → medula óssea (a partir do 5º mês, tornando-se o sítio definitivo)." },
  { id: 330, topic: "Sangue e Hematopoiese", question: "O plasma sanguíneo difere do soro por conter:", options: ["Mais albumina", "Fibrinogênio (e outros fatores de coagulação)", "Mais imunoglobulinas", "Células sanguíneas"], correctIndex: 1, explanation: "O soro é plasma sem fibrinogênio e fatores de coagulação consumidos na coagulação. O plasma (obtido com anticoagulante) retém todos os fatores, incluindo fibrinogênio." },
  { id: 331, topic: "Sangue e Hematopoiese", question: "A GPIIb/IIIa plaquetária é o receptor para:", options: ["Colágeno", "Fibrinogênio (mediando agregação plaqueta-plaqueta)", "Trombina", "ADP"], correctIndex: 1, explanation: "A GPIIb/IIIa (integrina αIIbβ3) é ativada nas plaquetas estimuladas e liga fibrinogênio, criando pontes entre plaquetas adjacentes (agregação). Abciximab é um antagonista usado clinicamente." },
  { id: 332, topic: "Sangue e Hematopoiese", question: "Os corpúsculos de Howell-Jolly nos eritrócitos indicam:", options: ["Anemia ferropriva", "Asplenia funcional ou cirúrgica (restos nucleares não removidos)", "Talassemia", "Esferocitose"], correctIndex: 1, explanation: "Os corpúsculos de Howell-Jolly são restos de DNA nuclear nos eritrócitos, normalmente removidos pelo baço. Sua presença indica asplenia (funcional ou pós-esplenectomia)." },
  { id: 333, topic: "Sangue e Hematopoiese", question: "O IL-3 é um fator de crescimento hematopoiético que estimula:", options: ["Apenas eritropoiese", "Múltiplas linhagens (multilineage)", "Apenas trombopoiese", "Apenas linfocitopoiese"], correctIndex: 1, explanation: "A IL-3 (multi-CSF) é uma citocina pleiotrópica que estimula proliferação e diferenciação de múltiplas linhagens hematopoiéticas, atuando precocemente na hierarquia." },
  { id: 334, topic: "Sangue e Hematopoiese", question: "As células dendríticas sanguíneas são classificadas como:", options: ["Granulócitos", "Células apresentadoras de antígenos (APCs) profissionais", "Eritrócitos modificados", "Plaquetas gigantes"], correctIndex: 1, explanation: "As células dendríticas são as APCs mais eficientes, captando antígenos na periferia, processando-os e migrando para linfonodos para ativar linfócitos T naïve." },
  { id: 335, topic: "Sangue e Hematopoiese", question: "O nicho hematopoiético na medula óssea é mantido por:", options: ["Osteoclastos apenas", "Células estromais, osteoblastos, endotélio sinusoidal e adipócitos", "Eritrócitos", "Hepatócitos"], correctIndex: 1, explanation: "O nicho hematopoiético é regulado por células estromais reticulares (CXCL12+), osteoblastos (nicho endosteal), endotélio sinusoidal (nicho vascular) e adipócitos, mantendo a quiescência e auto-renovação das HSCs." },
  { id: 336, topic: "Sangue e Hematopoiese", question: "Os grânulos terciários dos neutrófilos contêm:", options: ["Mieloperoxidase", "Gelatinase (MMP-9) e receptores de adesão", "MBP", "Perforinas"], correctIndex: 1, explanation: "Os grânulos terciários (de gelatinase) contêm MMP-9 (gelatinase B) e receptores de membrana que, quando exocitados, facilitam a migração do neutrófilo através da MEC e membrana basal." },
  { id: 337, topic: "Sangue e Hematopoiese", question: "A albumina representa qual fração das proteínas plasmáticas?", options: ["10%", "~60% (a mais abundante)", "5%", "90%"], correctIndex: 1, explanation: "A albumina é a proteína plasmática mais abundante (~60%, ~3,5-5 g/dL), sintetizada pelo fígado. Mantém a pressão oncótica e transporta substâncias (bilirrubina, ácidos graxos, fármacos)." },
  { id: 338, topic: "Sangue e Hematopoiese", question: "O buffy coat (creme leucocitário) é:", options: ["Plasma", "Camada fina de leucócitos e plaquetas entre plasma e eritrócitos após centrifugação", "Eritrócitos sedimentados", "Fibrinogênio precipitado"], correctIndex: 1, explanation: "O buffy coat é a camada esbranquiçada entre o plasma (superior) e eritrócitos (inferior) obtida por centrifugação, contendo leucócitos (<1% do volume) e plaquetas." },
  { id: 339, topic: "Sangue e Hematopoiese", question: "A policitemia vera está associada à mutação:", options: ["BCR-ABL", "JAK2 V617F", "BRAF V600E", "FLT3-ITD"], correctIndex: 1, explanation: "A policitemia vera é uma neoplasia mieloproliferativa com mutação JAK2 V617F em >95% dos casos, causando proliferação clonal de eritrócitos, leucócitos e plaquetas." },
  { id: 340, topic: "Sangue e Hematopoiese", question: "Os corpúsculos de Weibel-Palade nas células endoteliais armazenam:", options: ["Histamina", "Fator de von Willebrand e P-selectina", "Complemento", "Imunoglobulinas"], correctIndex: 1, explanation: "Os corpúsculos de Weibel-Palade são organelas secretórias do endotélio que armazenam vWF (hemostasia) e P-selectina (adesão leucocitária na inflamação), liberados por exocitose regulada." },
  { id: 341, topic: "Sangue e Hematopoiese", question: "Os megacariócitos tornam-se poliploides por:", options: ["Mitose normal", "Endomitose (replicação do DNA sem divisão celular)", "Fusão celular", "Fagocitose de núcleos"], correctIndex: 1, explanation: "Os megacariócitos sofrem endomitose (replicação de DNA sem citocinese), tornando-se poliploides (até 128N). O maior conteúdo de DNA permite produção massiva de plaquetas por fragmentação citoplasmática." },
  { id: 342, topic: "Sangue e Hematopoiese", question: "A leucemia mieloide crônica está associada ao:", options: ["Deleção 5q", "Cromossomo Philadelphia t(9;22) com gene de fusão BCR-ABL", "Trissomia do 21", "Mutação JAK2"], correctIndex: 1, explanation: "A LMC é definida pelo cromossomo Philadelphia, resultado da t(9;22) que cria o gene de fusão BCR-ABL com atividade tirosino-quinase constitutiva. Alvo terapêutico do imatinib." },
  { id: 343, topic: "Sangue e Hematopoiese", question: "O hematócrito normal em homens é de aproximadamente:", options: ["25-30%", "40-54%", "60-70%", "80-90%"], correctIndex: 1, explanation: "O hematócrito (volume de eritrócitos/volume total de sangue) é ~40-54% em homens e ~36-48% em mulheres. Valores alterados indicam anemia (baixo) ou policitemia (alto)." },
  { id: 344, topic: "Sangue e Hematopoiese", question: "Os grânulos α das plaquetas contêm:", options: ["ADP e serotonina", "Fibrinogênio, vWF, PDGF, PF4 e trombospondina", "Peroxidase", "Histamina"], correctIndex: 1, explanation: "Os grânulos α são os mais abundantes e grandes nas plaquetas, contendo proteínas de adesão (fibrinogênio, vWF), fatores de crescimento (PDGF, TGF-β) e quimiocinas (PF4)." },
  { id: 345, topic: "Sangue e Hematopoiese", question: "A formação do tampão hemostático secundário envolve:", options: ["Apenas adesão plaquetária", "Cascata de coagulação com formação de fibrina", "Fibrinólise", "Apenas vasoconstrição"], correctIndex: 1, explanation: "A hemostasia secundária envolve a cascata de coagulação (vias intrínseca e extrínseca → via comum), gerando trombina que converte fibrinogênio em fibrina, estabilizando o tampão plaquetário." },
  { id: 346, topic: "Sangue e Hematopoiese", question: "Os eosinófilos são atraídos por:", options: ["Fator de necrose tumoral apenas", "Eotaxina (CCL11) e IL-5", "G-CSF", "M-CSF"], correctIndex: 1, explanation: "A eotaxina (CCL11) é o principal quimioatraente de eosinófilos, e a IL-5 é o principal fator de diferenciação, ativação e sobrevida eosinofílica." },
  { id: 347, topic: "Sangue e Hematopoiese", question: "A proteína espectrina é importante para:", options: ["Transporte de O₂", "Manutenção da forma bicôncava do eritrócito (citoesqueleto submembranar)", "Coagulação", "Fagocitose"], correctIndex: 1, explanation: "A espectrina (α e β) forma o citoesqueleto cortical do eritrócito, ligada à actina e ancorada à membrana via anquirina-banda 3 e proteína 4.1-glicoforina C. Defeitos causam esferocitose hereditária." },
  { id: 348, topic: "Sangue e Hematopoiese", question: "A hemoglobina adulta predominante (HbA) é composta por:", options: ["Duas cadeias α e duas γ", "Duas cadeias α e duas β", "Quatro cadeias α", "Duas cadeias β e duas δ"], correctIndex: 1, explanation: "A HbA (α₂β₂) representa ~97% da hemoglobina adulta. HbA₂ (α₂δ₂) ~2-3%. HbF (α₂γ₂) <1% no adulto. Cada subunidade contém um grupo heme com Fe²⁺." },
  { id: 349, topic: "Sangue e Hematopoiese", question: "O baço remove eritrócitos senescentes por:", options: ["Hemólise intravascular", "Filtração nos cordões de Billroth e sinusoides esplênicos (hemólise extravascular)", "Ação de anticorpos", "Ação de neutrófilos"], correctIndex: 1, explanation: "Os eritrócitos senescentes (menos flexíveis, perda de ácido siálico, externalização de fosfatidilserina) ficam retidos nos cordões esplênicos e são fagocitados por macrófagos." },
  { id: 350, topic: "Sangue e Hematopoiese", question: "O ferro heme da hemoglobina degradada é:", options: ["Excretado na urina", "Reciclado: transferido ao plasma via ferroportina → transferrina → medula óssea (nova hemoglobina)", "Armazenado nos eritrócitos", "Destruído permanentemente"], correctIndex: 1, explanation: "O ferro é reciclado eficientemente: macrófagos fagocitam eritrócitos velhos, degradam heme (Fe²⁺ + biliverdina → bilirrubina), exportam ferro via ferroportina → transferrina → eritroblastos." },

  // =============================================
  // INTRODUÇÃO À HISTOLOGIA (351-375)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 351, topic: "Introdução à Histologia", question: "Quais são os quatro tecidos fundamentais do corpo humano?", options: ["Epitelial, conjuntivo, muscular e nervoso", "Epitelial, adiposo, cartilaginoso e ósseo", "Muscular, nervoso, linfático e sanguíneo", "Conjuntivo, vascular, glandular e sensorial"], correctIndex: 0, explanation: "Os quatro tecidos fundamentais são: epitelial (revestimento e secreção), conjuntivo (sustentação), muscular (contração) e nervoso (comunicação). Todos os órgãos são formados por combinações desses tecidos." },
  { id: 352, topic: "Introdução à Histologia", question: "Qual folheto embrionário dá origem ao tecido epitelial de revestimento da pele?", options: ["Endoderma", "Mesoderma", "Ectoderma", "Crista neural"], correctIndex: 2, explanation: "O ectoderma origina a epiderme e seus anexos, além do tecido nervoso. O endoderma origina os epitélios do trato gastrointestinal e o mesoderma origina músculos, ossos e tecido conjuntivo." },
  { id: 353, topic: "Introdução à Histologia", question: "O mesoderma dá origem a qual dos seguintes tecidos?", options: ["Epitélio intestinal", "Tecido nervoso", "Tecido conjuntivo, muscular e vascular", "Epiderme"], correctIndex: 2, explanation: "O mesoderma origina tecido conjuntivo (incluindo osso, cartilagem e sangue), tecido muscular e revestimento das cavidades serosas (mesotélio)." },
  { id: 354, topic: "Introdução à Histologia", question: "O endoderma origina o epitélio de qual órgão?", options: ["Pele", "Pulmão", "Rim", "Coração"], correctIndex: 1, explanation: "O endoderma origina os epitélios do trato respiratório, trato gastrointestinal, fígado, pâncreas e tireoide, entre outros." },
  { id: 355, topic: "Introdução à Histologia", question: "Qual componente NÃO faz parte do meio extracelular?", options: ["Fibras colágenas", "Substância fundamental amorfa", "Ribossomos", "Glicosaminoglicanos"], correctIndex: 2, explanation: "Ribossomos são organelas intracelulares responsáveis pela síntese proteica. Fibras colágenas, substância fundamental amorfa e GAGs são componentes da matriz extracelular." },
  { id: 356, topic: "Introdução à Histologia", question: "O conceito de 'órgão' em histologia refere-se a:", options: ["Um único tecido funcionando isoladamente", "Uma estrutura formada pela combinação de dois ou mais tecidos que exercem função integrada", "Apenas tecido epitelial organizado", "Qualquer célula especializada"], correctIndex: 1, explanation: "Órgãos são formados pela associação de diferentes tecidos trabalhando em conjunto para realizar funções específicas. O intestino, por exemplo, combina epitélio, conjuntivo, muscular e nervoso." },
  { id: 357, topic: "Introdução à Histologia", question: "As células-tronco são importantes para os tecidos porque:", options: ["Produzem anticorpos", "São capazes de autorrenovação e diferenciação em células especializadas", "Secretam hormônios exclusivamente", "Não se dividem"], correctIndex: 1, explanation: "Células-tronco possuem capacidade de autorrenovação (manter a população stem) e de gerar células diferenciadas, sendo essenciais para a homeostase e regeneração dos tecidos." },
  { id: 358, topic: "Introdução à Histologia", question: "Qual tipo de tecido é avascular e depende de difusão para nutrição?", options: ["Tecido muscular", "Tecido epitelial", "Tecido conjuntivo frouxo", "Tecido nervoso"], correctIndex: 1, explanation: "O tecido epitelial é avascular, recebendo nutrientes por difusão a partir do tecido conjuntivo subjacente através da membrana basal." },
  { id: 359, topic: "Introdução à Histologia", question: "O tecido conjuntivo é caracterizado por:", options: ["Células justapostas sem matriz extracelular", "Abundante matriz extracelular com fibras e substância fundamental", "Células com capacidade de contração", "Presença de sinapses"], correctIndex: 1, explanation: "O tecido conjuntivo tem abundante matriz extracelular composta por fibras (colágenas, elásticas e reticulares) e substância fundamental amorfa, ao contrário do epitélio, onde células estão justapostas." },
  { id: 360, topic: "Introdução à Histologia", question: "A apoptose difere da necrose porque:", options: ["Causa inflamação intensa", "É uma morte celular programada, sem resposta inflamatória", "Ocorre apenas no tecido nervoso", "Envolve ruptura da membrana plasmática"], correctIndex: 1, explanation: "A apoptose é morte celular programada com condensação celular, fragmentação do DNA e formação de corpos apoptóticos fagocitados sem inflamação. A necrose causa lise celular e inflamação." },
  { id: 361, topic: "Introdução à Histologia", question: "A renovação tecidual é mais rápida em qual dos seguintes tecidos?", options: ["Tecido nervoso central", "Epitélio intestinal", "Músculo cardíaco", "Cartilagem hialina"], correctIndex: 1, explanation: "O epitélio intestinal renova-se a cada 3-5 dias a partir de células-tronco nas criptas de Lieberkühn. Tecido nervoso e músculo cardíaco têm renovação extremamente limitada." },
  { id: 362, topic: "Introdução à Histologia", question: "A matriz extracelular tem qual função principal?", options: ["Apenas preenchimento mecânico", "Sustentação estrutural, sinalização celular e regulação do microambiente", "Produção de energia (ATP)", "Síntese de proteínas"], correctIndex: 1, explanation: "A MEC fornece suporte estrutural, regula comportamento celular (adesão, migração, diferenciação), armazena fatores de crescimento e mantém a hidratação tecidual." },
  { id: 363, topic: "Introdução à Histologia", question: "Qual característica diferencia os tecidos lábeis dos permanentes?", options: ["Tecidos lábeis não possuem células", "Tecidos lábeis se dividem continuamente ao longo da vida", "Tecidos permanentes se dividem rapidamente", "Não há diferença"], correctIndex: 1, explanation: "Tecidos lábeis (epitélios, medula óssea) possuem células em divisão contínua. Tecidos estáveis (fígado) dividem-se quando estimulados. Tecidos permanentes (neurônios, miócitos cardíacos) raramente se dividem." },
  { id: 364, topic: "Introdução à Histologia", question: "O termo 'histologia' significa literalmente:", options: ["Estudo das células", "Estudo dos tecidos", "Estudo dos órgãos", "Estudo dos sistemas"], correctIndex: 1, explanation: "Histologia vem do grego histos (tecido) + logos (estudo). É a ciência que estuda a estrutura microscópica dos tecidos e como eles se organizam para formar os órgãos." },
  { id: 365, topic: "Introdução à Histologia", question: "As células da crista neural originam:", options: ["Epitélio intestinal", "Melanócitos, células de Schwann e medula da suprarrenal", "Tecido muscular esquelético", "Mesotélio"], correctIndex: 1, explanation: "A crista neural é uma população de células migratórias do ectoderma que origina melanócitos, sistema nervoso periférico (células de Schwann, gânglios), medula da suprarrenal e estruturas craniofaciais." },
  { id: 366, topic: "Introdução à Histologia", question: "Qual processo permite que uma célula indiferenciada adquira características especializadas?", options: ["Mitose", "Diferenciação celular", "Necrose", "Osmose"], correctIndex: 1, explanation: "A diferenciação celular é o processo pelo qual células-tronco adquirem características morfológicas e funcionais especializadas, regulado por fatores de transcrição, sinais extracelulares e modificações epigenéticas." },
  { id: 367, topic: "Introdução à Histologia", question: "O tecido nervoso é derivado de qual folheto embrionário?", options: ["Endoderma", "Mesoderma", "Ectoderma", "Mesoderma lateral"], correctIndex: 2, explanation: "O tecido nervoso (tubo neural e crista neural) é derivado do ectoderma. O tubo neural origina o SNC e a crista neural origina parte do SNP." },
  { id: 368, topic: "Introdução à Histologia", question: "Qual processo está envolvido na formação de tecidos durante o desenvolvimento embrionário?", options: ["Histogênese", "Histólise", "Anaplasia", "Metaplasia"], correctIndex: 0, explanation: "Histogênese é o processo de formação e diferenciação dos tecidos a partir dos folhetos embrionários durante o desenvolvimento. Histólise é a destruição de tecidos." },
  { id: 369, topic: "Introdução à Histologia", question: "Metaplasia é:", options: ["Aumento do número de células", "Substituição de um tipo de tecido diferenciado por outro", "Diminuição do tamanho celular", "Morte celular programada"], correctIndex: 1, explanation: "Metaplasia é a substituição adaptativa de um tipo de tecido diferenciado por outro, geralmente em resposta a estresse crônico. Ex.: metaplasia escamosa no epitélio brônquico de fumantes." },
  { id: 370, topic: "Introdução à Histologia", question: "A homeostase tecidual depende do equilíbrio entre:", options: ["Apenas mitose", "Proliferação celular, diferenciação e morte celular (apoptose)", "Apenas apoptose", "Apenas migração celular"], correctIndex: 1, explanation: "A homeostase tecidual é mantida pelo equilíbrio dinâmico entre proliferação de células-tronco/progenitoras, diferenciação em células maduras e eliminação por apoptose." },
  { id: 371, topic: "Introdução à Histologia", question: "Qual é a unidade funcional do tecido nervoso?", options: ["Fibroblasto", "Osteócito", "Neurônio", "Condrócito"], correctIndex: 2, explanation: "O neurônio é a unidade funcional do tecido nervoso, especializado em receber, processar e transmitir impulsos elétricos (potenciais de ação) através de sinapses." },
  { id: 372, topic: "Introdução à Histologia", question: "Os tecidos conjuntivos especializados incluem:", options: ["Apenas tecido conjuntivo frouxo", "Cartilagem, osso, sangue e tecido adiposo", "Apenas tecido muscular", "Epitélio glandular"], correctIndex: 1, explanation: "Os tecidos conjuntivos especializados incluem cartilagem, osso, sangue, tecido adiposo e tecido hematopoiético, cada um com matriz extracelular e células especializadas distintas." },
  { id: 373, topic: "Introdução à Histologia", question: "A hiperplasia é:", options: ["Diminuição do tamanho celular", "Aumento do número de células em um tecido", "Morte celular", "Substituição de um tecido por outro"], correctIndex: 1, explanation: "Hiperplasia é o aumento do número de células em um tecido ou órgão, geralmente em resposta a estímulos hormonais ou fatores de crescimento. Difere de hipertrofia (aumento do tamanho celular)." },
  { id: 374, topic: "Introdução à Histologia", question: "A displasia é caracterizada por:", options: ["Crescimento celular normal", "Alterações no tamanho, forma e organização celular", "Diminuição do volume tecidual", "Necrose completa do tecido"], correctIndex: 1, explanation: "Displasia é uma alteração pré-maligna caracterizada por variação no tamanho e forma celular, aumento de mitoses e perda da organização arquitetural normal do tecido." },
  { id: 375, topic: "Introdução à Histologia", question: "A polaridade celular no tecido epitelial refere-se a:", options: ["Capacidade de divisão rápida", "Diferenças morfológicas e funcionais entre as superfícies apical, lateral e basal da célula", "Ausência de núcleo", "Migração celular contínua"], correctIndex: 1, explanation: "A polaridade epitelial implica em diferenças estruturais e funcionais entre os domínios apical (voltado ao lúmen), lateral (contato celular) e basal (contato com lâmina basal) da célula." },

  // =============================================
  // MICROSCOPIA E TÉCNICAS HISTOLÓGICAS (376-400)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.
  // =============================================
  { id: 376, topic: "Microscopia e Técnicas Histológicas", question: "Qual é a sequência correta do processamento histológico convencional?", options: ["Coloração → fixação → inclusão → microtomia", "Fixação → desidratação → diafanização → inclusão → microtomia → coloração", "Microtomia → fixação → coloração → inclusão", "Inclusão → fixação → desidratação → coloração"], correctIndex: 1, explanation: "O processamento histológico segue: fixação (preservação), desidratação (álcoois crescentes), diafanização (xilol), inclusão (parafina), microtomia (cortes), coloração e montagem." },
  { id: 377, topic: "Microscopia e Técnicas Histológicas", question: "O fixador mais utilizado em histologia de rotina é:", options: ["Ácido acético", "Formaldeído (formol) a 10% tamponado", "Álcool etílico absoluto", "Glutaraldeído"], correctIndex: 1, explanation: "O formaldeído 10% tamponado (pH 7) é o fixador padrão. Age criando pontes de metileno entre proteínas, preservando a morfologia. O glutaraldeído é usado para microscopia eletrônica." },
  { id: 378, topic: "Microscopia e Técnicas Histológicas", question: "A coloração de rotina em histologia é:", options: ["Tricrômico de Masson", "Hematoxilina e Eosina (H&E)", "PAS", "Prata"], correctIndex: 1, explanation: "HE é a coloração de rotina: hematoxilina (básica/azul) cora estruturas ácidas (núcleo, ribossomos = basófilas) e eosina (ácida/rosa) cora estruturas básicas (citoplasma, colágeno = acidófilas)." },
  { id: 379, topic: "Microscopia e Técnicas Histológicas", question: "Estruturas basófilas são coradas por qual corante?", options: ["Eosina", "Hematoxilina", "Xilol", "Parafina"], correctIndex: 1, explanation: "Hematoxilina é um corante básico que cora em azul/roxo estruturas ácidas (basófilas): DNA, RNA, proteoglicanos sulfatados. O núcleo é intensamente basófilo por seu conteúdo de DNA." },
  { id: 380, topic: "Microscopia e Técnicas Histológicas", question: "A eosina cora preferencialmente:", options: ["Ácidos nucleicos", "Proteínas citoplasmáticas e fibras colágenas (estruturas acidófilas)", "Carboidratos", "Lipídios"], correctIndex: 1, explanation: "A eosina é um corante ácido que cora estruturas básicas (acidófilas) em rosa/vermelho: proteínas citoplasmáticas, filamentos, colágeno, mitocôndrias." },
  { id: 381, topic: "Microscopia e Técnicas Histológicas", question: "O PAS (ácido periódico de Schiff) é utilizado para detectar:", options: ["Ácidos nucleicos", "Polissacarídeos neutros e glicoproteínas", "Lipídios", "Proteínas totais"], correctIndex: 1, explanation: "O PAS detecta glicogênio, mucinas neutras, membrana basal e glicocálix. O ácido periódico oxida 1,2-glicóis em aldeídos, que reagem com o reagente de Schiff produzindo cor magenta." },
  { id: 382, topic: "Microscopia e Técnicas Histológicas", question: "A coloração tricrômica de Masson destaca:", options: ["Apenas núcleos", "Fibras colágenas em azul/verde, citoplasma em vermelho, núcleos em preto", "Apenas lipídios", "Glicogênio"], correctIndex: 1, explanation: "O tricrômico de Masson usa três corantes: hematoxilina férrica (núcleos em preto), fucsina ácida/escarlate de Biebrich (citoplasma/músculo em vermelho) e azul de anilina/verde luz (colágeno em azul/verde)." },
  { id: 383, topic: "Microscopia e Técnicas Histológicas", question: "A impregnação por prata é utilizada para evidenciar:", options: ["Colágeno tipo I", "Fibras reticulares (colágeno tipo III)", "Elastina", "Queratina"], correctIndex: 1, explanation: "As fibras reticulares (colágeno tipo III) são argirófilas: reduzem íons prata, aparecendo em preto. Técnicas como a de Gomori são usadas para evidenciar a trama reticular de órgãos." },
  { id: 384, topic: "Microscopia e Técnicas Histológicas", question: "A microscopia eletrônica de transmissão (MET) utiliza como fonte de iluminação:", options: ["Luz visível", "Feixe de elétrons", "Raios ultravioleta", "Raios X"], correctIndex: 1, explanation: "A MET usa feixe de elétrons com comprimento de onda muito menor que a luz visível, permitindo resolução de ~0,1 nm. Os elétrons são focalizados por lentes eletromagnéticas." },
  { id: 385, topic: "Microscopia e Técnicas Histológicas", question: "O poder de resolução do microscópio óptico é de aproximadamente:", options: ["0,1 nm", "0,2 µm (200 nm)", "1 mm", "10 µm"], correctIndex: 1, explanation: "O limite de resolução do microscópio óptico é ~0,2 µm (200 nm), determinado pelo comprimento de onda da luz visível. O MET resolve até ~0,1 nm, mil vezes melhor." },
  { id: 386, topic: "Microscopia e Técnicas Histológicas", question: "A microscopia de fluorescência é baseada em:", options: ["Absorção de calor", "Emissão de luz por fluorocromos após excitação com comprimento de onda específico", "Reflexão de luz branca", "Absorção de elétrons"], correctIndex: 1, explanation: "Fluorocromos absorvem luz de excitação (menor comprimento de onda) e emitem luz fluorescente (maior comprimento de onda). Usada com anticorpos fluorescentes em imuno-histoquímica." },
  { id: 387, topic: "Microscopia e Técnicas Histológicas", question: "A imuno-histoquímica utiliza qual princípio para localizar antígenos teciduais?", options: ["Reação enzimática simples", "Ligação anticorpo-antígeno visualizada por cromógenos ou fluorescência", "Coloração por afinidade iônica", "Impregnação metálica"], correctIndex: 1, explanation: "A imuno-histoquímica usa anticorpos específicos contra antígenos teciduais. A detecção é feita por anticorpos conjugados a enzimas (peroxidase → DAB marrom) ou fluorocromos." },
  { id: 388, topic: "Microscopia e Técnicas Histológicas", question: "O micrótomo produz cortes histológicos com espessura de:", options: ["1-2 mm", "3-7 µm", "50-100 µm", "0,1 nm"], correctIndex: 1, explanation: "O micrótomo produz cortes de parafina com 3-7 µm de espessura (idealmente 5 µm). Para MET, o ultramicrótomo produz cortes ultrafinos de 50-90 nm." },
  { id: 389, topic: "Microscopia e Técnicas Histológicas", question: "A criomicrotomia (cortes de congelação) é indicada quando:", options: ["Se deseja máxima qualidade morfológica", "Se necessita diagnóstico intraoperatório rápido ou preservação de lipídios/enzimas", "Se busca coloração com prata", "Se quer incluir em parafina depois"], correctIndex: 1, explanation: "Cortes de congelação permitem diagnóstico rápido (15-20 min) durante cirurgias e preservam lipídios e atividade enzimática que seriam perdidos no processamento com parafina." },
  { id: 390, topic: "Microscopia e Técnicas Histológicas", question: "A hibridização in situ (ISH) permite detectar:", options: ["Proteínas citoplasmáticas", "Sequências específicas de DNA ou RNA nos tecidos", "Lipídios de membrana", "Íons minerais"], correctIndex: 1, explanation: "A ISH usa sondas de ácidos nucleicos complementares para localizar sequências específicas de DNA/RNA in situ. A FISH (fluorescent ISH) usa sondas fluorescentes para detectar alterações cromossômicas." },
  { id: 391, topic: "Microscopia e Técnicas Histológicas", question: "A desidratação tecidual antes da inclusão em parafina utiliza:", options: ["Água destilada", "Concentrações crescentes de álcool etílico", "Formol", "Ácido periódico"], correctIndex: 1, explanation: "A desidratação utiliza banhos de álcool etílico em concentrações crescentes (70%, 80%, 95%, 100%) para remover a água do tecido gradualmente, evitando distorções." },
  { id: 392, topic: "Microscopia e Técnicas Histológicas", question: "A diafanização (clarificação) utiliza qual substância?", options: ["Formol", "Xilol (ou substitutos)", "Álcool", "Eosina"], correctIndex: 1, explanation: "O xilol é miscível com álcool e parafina, servindo como intermediário. Substitui o álcool no tecido antes da infiltração com parafina. O tecido fica translúcido (daí o nome diafanização)." },
  { id: 393, topic: "Microscopia e Técnicas Histológicas", question: "A microscopia confocal oferece vantagem sobre a fluorescência convencional porque:", options: ["Usa maior comprimento de onda", "Elimina fluorescência fora do plano focal, gerando secções ópticas nítidas", "Não precisa de fluorocromos", "Tem menor resolução"], correctIndex: 1, explanation: "O microscópio confocal usa um pinhole que bloqueia a luz fora do plano focal, permitindo secções ópticas finas e reconstrução 3D. Essencial para imunofluorescência de alta resolução." },
  { id: 394, topic: "Microscopia e Técnicas Histológicas", question: "A coloração de Verhoeff é utilizada para evidenciar:", options: ["Colágeno", "Fibras elásticas", "Fibras reticulares", "Mucinas"], correctIndex: 1, explanation: "A coloração de Verhoeff (hematoxilina férrica) cora fibras elásticas em preto. Utilizada para avaliar a organização de fibras elásticas em vasos sanguíneos, pele e pulmões." },
  { id: 395, topic: "Microscopia e Técnicas Histológicas", question: "O Sudan e o Oil Red O são corantes utilizados para:", options: ["Ácidos nucleicos", "Lipídios em cortes de congelação", "Glicogênio", "Proteínas"], correctIndex: 1, explanation: "Sudan III/IV e Oil Red O são corantes lipossolúveis que detectam lipídios em cortes de congelação (não em parafina, pois a desidratação e xilol removem os lipídios)." },
  { id: 396, topic: "Microscopia e Técnicas Histológicas", question: "A microscopia eletrônica de varredura (MEV) permite visualizar:", options: ["Ultraestrutura interna da célula", "A superfície tridimensional das amostras", "Apenas ácidos nucleicos", "Apenas lipídios"], correctIndex: 1, explanation: "A MEV varre a superfície da amostra metalizada com feixe de elétrons, detectando elétrons secundários emitidos. Produz imagens 3D da topografia superficial com grande profundidade de campo." },
  { id: 397, topic: "Microscopia e Técnicas Histológicas", question: "A autoradiografia é uma técnica que permite:", options: ["Visualizar proteínas fluorescentes", "Detectar moléculas marcadas com isótopos radioativos no tecido", "Corar lipídios", "Medir pH tecidual"], correctIndex: 1, explanation: "A autoradiografia usa precursores marcados com isótopos radioativos (³H-timidina para DNA) que se incorporam às moléculas. A emulsão fotográfica sobre o corte revela a localização por grãos de prata." },
  { id: 398, topic: "Microscopia e Técnicas Histológicas", question: "A fixação tecidual tem como objetivo principal:", options: ["Corar as células", "Preservar a morfologia e composição química o mais próximo do estado in vivo", "Tornar o tecido transparente", "Aumentar o tamanho das células"], correctIndex: 1, explanation: "A fixação preserva a estrutura celular e tecidual, evitando autólise enzimática e decomposição bacteriana. O formol cria cross-links entre proteínas, estabilizando a arquitetura." },
  { id: 399, topic: "Microscopia e Técnicas Histológicas", question: "A citoquímica para fosfatase ácida identifica qual organela?", options: ["Mitocôndrias", "Lisossomos", "Complexo de Golgi", "Retículo endoplasmático"], correctIndex: 1, explanation: "A fosfatase ácida é uma enzima marcadora de lisossomos. A reação citoquímica com substrato adequado (técnica de Gomori) demonstra atividade enzimática nos lisossomos." },
  { id: 400, topic: "Microscopia e Técnicas Histológicas", question: "A microscopia de polarização é útil para identificar:", options: ["Fluorescência", "Estruturas birrefringentes como colágeno, músculo estriado e cristais", "Apenas lipídios", "Apenas carboidratos"], correctIndex: 1, explanation: "A luz polarizada identifica estruturas anisotrópicas (birrefringentes): colágeno tipo I, músculo estriado (bandas A), cristais de urato e amiloide (verde-maçã com vermelho Congo)." },

  // =============================================
  // SISTEMA CARDIOVASCULAR (401-425)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 401, topic: "Sistema Cardiovascular", question: "Quais são as três camadas (túnicas) da parede dos vasos sanguíneos?", options: ["Endotélio, adventícia e serosa", "Íntima, média e adventícia", "Mucosa, submucosa e serosa", "Endocárdio, miocárdio e epicárdio"], correctIndex: 1, explanation: "A parede vascular possui três túnicas: íntima (endotélio + subendotélio), média (músculo liso + fibras elásticas) e adventícia (tecido conjuntivo)." },
  { id: 402, topic: "Sistema Cardiovascular", question: "O endotélio vascular é formado por:", options: ["Epitélio estratificado pavimentoso", "Epitélio simples pavimentoso", "Epitélio cúbico", "Mesênquima"], correctIndex: 1, explanation: "O endotélio é um epitélio simples pavimentoso de origem mesodérmica que reveste todo o sistema cardiovascular. Produz óxido nítrico, prostaciclina e fatores von Willebrand." },
  { id: 403, topic: "Sistema Cardiovascular", question: "As artérias elásticas (de grande calibre) possuem qual característica marcante na túnica média?", options: ["Predomínio de músculo liso", "Múltiplas lâminas elásticas concêntricas", "Ausência de músculo liso", "Presença de valvas"], correctIndex: 1, explanation: "Artérias elásticas (aorta, carótida, subclávia) possuem 40-70 lâminas elásticas na média, permitindo distensão durante a sístole e recuo elástico na diástole (função de condução)." },
  { id: 404, topic: "Sistema Cardiovascular", question: "As artérias musculares (de médio calibre) são caracterizadas por:", options: ["Predomínio de lâminas elásticas", "Túnica média com camadas de músculo liso bem desenvolvidas e lâminas elásticas interna e externa distintas", "Ausência de túnica adventícia", "Presença de valvas"], correctIndex: 1, explanation: "Artérias musculares possuem lâmina elástica interna e externa bem definidas com músculo liso predominante na média (até 40 camadas). Regulam o fluxo sanguíneo por vasoconstrição/vasodilatação." },
  { id: 405, topic: "Sistema Cardiovascular", question: "As arteríolas regulam a pressão arterial principalmente por:", options: ["Aumento da quantidade de sangue", "Contração e relaxamento do músculo liso da túnica média, alterando a resistência periférica", "Produção de eritrócitos", "Ativação da cascata de coagulação"], correctIndex: 1, explanation: "As arteríolas são os principais vasos de resistência. A contração do músculo liso (1-3 camadas) reduz o lúmen, aumentando a resistência periférica e a pressão arterial." },
  { id: 406, topic: "Sistema Cardiovascular", question: "Os capilares contínuos são encontrados em:", options: ["Glomérulo renal", "Fígado", "Músculo, pulmão e tecido nervoso", "Medula óssea"], correctIndex: 2, explanation: "Capilares contínuos possuem endotélio sem fenestras e lâmina basal contínua. Encontrados em músculo, pulmão, SNC (barreira hematoencefálica) e tecido conjuntivo." },
  { id: 407, topic: "Sistema Cardiovascular", question: "Os capilares fenestrados são encontrados em:", options: ["Músculo esquelético", "Glomérulos renais, intestino e glândulas endócrinas", "SNC", "Pele"], correctIndex: 1, explanation: "Capilares fenestrados possuem poros (fenestras) no endotélio, com ou sem diafragma. Facilitam trocas rápidas em glomérulos renais, intestino, glândulas endócrinas e plexos coróideos." },
  { id: 408, topic: "Sistema Cardiovascular", question: "Os capilares sinusoidais (descontínuos) são encontrados em:", options: ["Pulmão", "Fígado, baço e medula óssea", "Rim", "Pele"], correctIndex: 1, explanation: "Sinusoides possuem lúmen amplo e irregular, endotélio descontínuo com lacunas e lâmina basal incompleta. Permitem passagem de macromoléculas e células. Encontrados no fígado, baço e medula óssea." },
  { id: 409, topic: "Sistema Cardiovascular", question: "As veias diferem das artérias pela presença de:", options: ["Mais músculo liso na média", "Valvas, lúmen maior e parede mais fina", "Mais lâminas elásticas", "Endotélio mais espesso"], correctIndex: 1, explanation: "Veias possuem paredes mais finas, lúmen maior, túnica adventícia proporcionalmente mais espessa e presença de valvas (exceto veias cavas e cerebrais) que impedem refluxo." },
  { id: 410, topic: "Sistema Cardiovascular", question: "Os vasa vasorum são:", options: ["Nervos dos vasos", "Pequenos vasos que irrigam a parede de vasos de grande calibre", "Valvas venosas", "Células musculares lisas"], correctIndex: 1, explanation: "Vasa vasorum são arteríolas e vênulas na adventícia e porção externa da média de grandes vasos (aorta, veia cava), nutrindo regiões distantes do lúmen não alcançadas por difusão." },
  { id: 411, topic: "Sistema Cardiovascular", question: "O endocárdio do coração corresponde a qual túnica vascular?", options: ["Túnica média", "Túnica íntima", "Túnica adventícia", "Nenhuma correspondência"], correctIndex: 1, explanation: "O endocárdio é equivalente à túnica íntima dos vasos: endotélio + subendotélio (tecido conjuntivo com fibras elásticas). Reveste internamente as câmaras cardíacas e valvas." },
  { id: 412, topic: "Sistema Cardiovascular", question: "O miocárdio é composto por:", options: ["Músculo esquelético", "Músculo cardíaco com discos intercalares", "Músculo liso", "Tecido conjuntivo denso"], correctIndex: 1, explanation: "O miocárdio é formado por cardiomiócitos ramificados conectados por discos intercalares (junções de adesão + gap junctions) que permitem contração sincicial." },
  { id: 413, topic: "Sistema Cardiovascular", question: "Os discos intercalares contêm quais tipos de junção?", options: ["Apenas tight junctions", "Zônulas de adesão, desmossomos e gap junctions (nexos)", "Apenas hemidesmossomos", "Apenas junções comunicantes"], correctIndex: 1, explanation: "Os discos intercalares possuem: zônulas de adesão e desmossomos (porção transversal - adesão mecânica) e gap junctions (porção lateral - acoplamento elétrico/sincício funcional)." },
  { id: 414, topic: "Sistema Cardiovascular", question: "O sistema de condução cardíaco inclui:", options: ["Apenas nervos vagos", "Nó sinoatrial, nó atrioventricular, feixe de His e fibras de Purkinje", "Apenas arteríolas coronárias", "Fibras musculares esqueléticas"], correctIndex: 1, explanation: "O sistema de condução é formado por cardiomiócitos modificados: nó SA (marca-passo), nó AV, feixe de His (ramos D e E) e fibras de Purkinje. Coordenam a contração rítmica." },
  { id: 415, topic: "Sistema Cardiovascular", question: "As fibras de Purkinje são caracterizadas histologicamente por:", options: ["Menor diâmetro que cardiomiócitos comuns", "Maior diâmetro, citoplasma rico em glicogênio e poucas miofibrilas periféricas", "Presença de estriações idênticas ao músculo esquelético", "Núcleos periféricos"], correctIndex: 1, explanation: "Fibras de Purkinje são cardiomiócitos modificados, maiores, com abundante glicogênio (citoplasma claro em HE), poucas miofibrilas periféricas e 1-2 núcleos centrais." },
  { id: 416, topic: "Sistema Cardiovascular", question: "O epicárdio corresponde a:", options: ["Túnica íntima", "Camada visceral do pericárdio seroso (mesotélio + tecido conjuntivo submesotelial)", "Túnica média dos vasos", "Endocárdio externo"], correctIndex: 1, explanation: "O epicárdio é a camada visceral do pericárdio seroso: mesotélio + tecido conjuntivo com vasos coronários, nervos e tecido adiposo. Equivale funcionalmente à adventícia vascular." },
  { id: 417, topic: "Sistema Cardiovascular", question: "A aterosclerose inicia-se com:", options: ["Proliferação de fibroblastos na adventícia", "Disfunção endotelial e acúmulo de lipoproteínas modificadas (LDL oxidado) na íntima", "Calcificação da média", "Espessamento da adventícia"], correctIndex: 1, explanation: "A aterosclerose inicia com lesão endotelial, acúmulo de LDL oxidado na íntima, recrutamento de monócitos/macrófagos (células espumosas), formação de estria gordurosa e progressão para placa." },
  { id: 418, topic: "Sistema Cardiovascular", question: "O óxido nítrico (NO) produzido pelo endotélio causa:", options: ["Vasoconstrição", "Vasodilatação e inibição da agregação plaquetária", "Coagulação", "Inflamação"], correctIndex: 1, explanation: "O NO é produzido pela eNOS endotelial, difunde-se para o músculo liso causando relaxamento (vasodilatação via GMPc) e inibe adesão/agregação plaquetária. Papel protetor contra aterosclerose." },
  { id: 419, topic: "Sistema Cardiovascular", question: "Os pericitos são células encontradas:", options: ["No endocárdio", "Envolvendo capilares e vênulas, compartilhando a lâmina basal com o endotélio", "Apenas na adventícia de artérias", "No miocárdio"], correctIndex: 1, explanation: "Pericitos são células contráteis com prolongamentos que envolvem capilares e vênulas pós-capilares. Compartilham a lâmina basal endotelial e regulam fluxo, permeabilidade e angiogênese." },
  { id: 420, topic: "Sistema Cardiovascular", question: "As vênulas pós-capilares são o local preferencial de:", options: ["Contração muscular vascular", "Diapedese leucocitária (migração de leucócitos para os tecidos)", "Hematopoiese", "Produção de fatores de coagulação"], correctIndex: 1, explanation: "As vênulas pós-capilares (10-30 µm) são o principal sítio de diapedese. A expressão de selectinas e ICAM/VCAM no endotélio ativado permite rolamento, adesão e transmigração leucocitária." },
  { id: 421, topic: "Sistema Cardiovascular", question: "O peptídeo natriurético atrial (ANP) é secretado por:", options: ["Ventrículo esquerdo", "Cardiomiócitos atriais em resposta à distensão", "Endotélio vascular", "Células de Purkinje"], correctIndex: 1, explanation: "O ANP é produzido e armazenado em grânulos de cardiomiócitos atriais. Liberado em resposta à distensão atrial, causa natriurese, diurese e vasodilatação, reduzindo a pressão arterial." },
  { id: 422, topic: "Sistema Cardiovascular", question: "A lâmina elástica interna separa:", options: ["Média da adventícia", "Íntima da média", "Endotélio da média", "Adventícia do tecido perivascular"], correctIndex: 1, explanation: "A lâmina elástica interna é uma camada de elastina fenestrada que separa a túnica íntima da média. Muito proeminente nas artérias musculares, ondulada em cortes histológicos." },
  { id: 423, topic: "Sistema Cardiovascular", question: "Os corpos de Weibel-Palade no endotélio contêm:", options: ["Histamina", "Fator de von Willebrand (vWF) e P-selectina", "Serotonina", "Colágeno"], correctIndex: 1, explanation: "Os corpos de Weibel-Palade são grânulos específicos do endotélio contendo vWF (hemostasia primária) e P-selectina (adesão leucocitária). Liberados por exocitose após ativação endotelial." },
  { id: 424, topic: "Sistema Cardiovascular", question: "O esqueleto fibroso do coração é composto por:", options: ["Músculo cardíaco", "Tecido conjuntivo denso (colágeno) que sustenta valvas e separa átrios de ventrículos", "Cartilagem hialina", "Osso esponjoso"], correctIndex: 1, explanation: "O esqueleto fibroso é formado por tecido conjuntivo denso (anéis fibrosos das valvas, trígonos e septo membranoso). Serve como inserção para válvulas e miocárdio, e isola eletricamente átrios de ventrículos." },
  { id: 425, topic: "Sistema Cardiovascular", question: "A túnica adventícia é mais desenvolvida em:", options: ["Artérias elásticas", "Veias", "Capilares", "Arteríolas"], correctIndex: 1, explanation: "Nas veias, a adventícia é proporcionalmente mais espessa, podendo conter feixes de músculo liso longitudinal (ex.: veia cava). Nas artérias, a média é mais proeminente." },

  // =============================================
  // SISTEMA RESPIRATÓRIO (426-450)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 426, topic: "Sistema Respiratório", question: "O epitélio respiratório típico é:", options: ["Simples pavimentoso", "Pseudoestratificado cilíndrico ciliado com células caliciformes", "Estratificado cúbico", "Simples cúbico"], correctIndex: 1, explanation: "O epitélio respiratório reveste a maior parte das vias aéreas condutoras (cavidade nasal, traqueia, brônquios). Contém células ciliadas, caliciformes, basais, em escova e neuroendócrinas." },
  { id: 427, topic: "Sistema Respiratório", question: "Os anéis de cartilagem hialina da traqueia são:", options: ["Anéis completos", "Anéis em forma de C, abertos posteriormente", "Anéis de cartilagem elástica", "Anéis de fibrocartilagem"], correctIndex: 1, explanation: "A traqueia possui 16-20 anéis de cartilagem hialina em forma de C. A parede posterior (aberta) é fechada pelo músculo traqueal (liso), permitindo distensão do esôfago posterior durante a deglutição." },
  { id: 428, topic: "Sistema Respiratório", question: "Na árvore brônquica, ao diminuir o calibre, ocorre:", options: ["Aumento da cartilagem e diminuição do músculo liso", "Diminuição da cartilagem e aumento relativo do músculo liso", "Aumento do epitélio", "Aumento das células caliciformes"], correctIndex: 1, explanation: "Dos brônquios aos bronquíolos: cartilagem diminui progressivamente (desaparece nos bronquíolos), músculo liso aumenta proporcionalmente, epitélio diminui de altura e células caliciformes diminuem." },
  { id: 429, topic: "Sistema Respiratório", question: "Os bronquíolos terminais são revestidos por:", options: ["Epitélio pseudoestratificado ciliado", "Epitélio simples cúbico a cilíndrico baixo ciliado, com células de Clara (Club)", "Epitélio simples pavimentoso", "Epitélio estratificado"], correctIndex: 1, explanation: "Os bronquíolos terminais possuem epitélio simples cúbico/cilíndrico baixo com cílios e células de Clara (Club cells), sem cartilagem nem células caliciformes. São a última porção condutora." },
  { id: 430, topic: "Sistema Respiratório", question: "As células de Clara (Club cells) secretam:", options: ["Muco", "Proteína CC16 (secretoglobina) e surfactante-like, além de atuarem como células progenitoras", "Histamina", "Elastase"], correctIndex: 1, explanation: "As células Club (Clara) secretam proteínas protetoras (CC16), componentes do surfactante, e funcionam como células progenitoras do epitélio bronquiolar. Também detoxificam via citocromo P450." },
  { id: 431, topic: "Sistema Respiratório", question: "Os pneumócitos tipo I são responsáveis por:", options: ["Produção de surfactante", "Formação da barreira de trocas gasosas (95% da superfície alveolar)", "Fagocitose", "Secreção de muco"], correctIndex: 1, explanation: "Pneumócitos tipo I são células pavimentosas extremamente finas que cobrem ~95% da superfície alveolar. Junto à lâmina basal fundida com endotélio capilar, formam a barreira hematoaérea (~0,1-0,5 µm)." },
  { id: 432, topic: "Sistema Respiratório", question: "Os pneumócitos tipo II produzem:", options: ["Muco", "Surfactante pulmonar (armazenado em corpos lamelares)", "Elastina", "Colágeno"], correctIndex: 1, explanation: "Pneumócitos tipo II são células cúbicas que produzem surfactante pulmonar (dipalmitoilfosfatidilcolina + proteínas SP-A,B,C,D), armazenado em corpos lamelares. Reduz tensão superficial alveolar e previne colapso." },
  { id: 433, topic: "Sistema Respiratório", question: "A síndrome do desconforto respiratório do recém-nascido (doença da membrana hialina) é causada por:", options: ["Excesso de muco", "Deficiência de surfactante pulmonar por imaturidade dos pneumócitos tipo II", "Excesso de surfactante", "Infecção bacteriana"], correctIndex: 1, explanation: "Prematuros (<34 semanas) não produzem surfactante suficiente, resultando em colapso alveolar (atelectasia), membranas hialinas e insuficiência respiratória. Tratamento: surfactante exógeno e corticoides pré-natais." },
  { id: 434, topic: "Sistema Respiratório", question: "Os macrófagos alveolares (células de poeira) são:", options: ["Pneumócitos tipo I", "Macrófagos derivados de monócitos que fagocitam partículas e patógenos no lúmen alveolar", "Células endoteliais", "Fibroblastos"], correctIndex: 1, explanation: "Macrófagos alveolares são monócitos diferenciados que patrulham a superfície alveolar, fagocitando partículas (poeira, fuligem), bactérias e surfactante degradado. Essenciais para a defesa pulmonar." },
  { id: 435, topic: "Sistema Respiratório", question: "A barreira hematoaérea é composta por:", options: ["Apenas endotélio", "Surfactante, pneumócito tipo I, lâminas basais fundidas e endotélio capilar", "Apenas pneumócito tipo II", "Cartilagem e epitélio"], correctIndex: 1, explanation: "A barreira hematoaérea (~0,1-0,5 µm) compreende: filme de surfactante → citoplasma do pneumócito I → lâmina basal fundida (epitelial + endotelial) → citoplasma da célula endotelial." },
  { id: 436, topic: "Sistema Respiratório", question: "O aparelho mucociliar realiza:", options: ["Trocas gasosas", "Transporte de muco com partículas aprisionadas em direção à faringe (clearance mucociliar)", "Produção de surfactante", "Vasodilatação"], correctIndex: 1, explanation: "O aparelho mucociliar é o principal mecanismo de defesa das vias aéreas: cílios batem coordenadamente (~12-15 Hz) movendo o tapete de muco (com partículas e patógenos aprisionados) em direção à faringe." },
  { id: 437, topic: "Sistema Respiratório", question: "A pleura é formada por:", options: ["Epitélio estratificado", "Mesotélio (simples pavimentoso) sobre tecido conjuntivo", "Endotélio", "Epitélio pseudoestratificado"], correctIndex: 1, explanation: "A pleura (visceral e parietal) é uma membrana serosa revestida por mesotélio apoiado em tecido conjuntivo com fibras elásticas, vasos e nervos. O líquido pleural lubrifica e permite deslizamento." },
  { id: 438, topic: "Sistema Respiratório", question: "O BALT (tecido linfático associado aos brônquios) consiste em:", options: ["Cápsula de tecido conjuntivo denso", "Agregados de tecido linfoide na mucosa brônquica", "Cartilagem modificada", "Células musculares lisas"], correctIndex: 1, explanation: "O BALT é componente do MALT (tecido linfático associado a mucosas), formado por folículos linfoides e linfócitos dispersos na parede brônquica. Participa da defesa imune local das vias aéreas." },
  { id: 439, topic: "Sistema Respiratório", question: "A região olfatória da cavidade nasal é revestida por:", options: ["Epitélio respiratório típico", "Epitélio olfatório pseudoestratificado com neurônios bipolares, células de sustentação e basais", "Epitélio estratificado pavimentoso", "Epitélio simples cúbico"], correctIndex: 1, explanation: "O epitélio olfatório contém neurônios bipolares (receptores olfatórios com cílios quimiosensíveis), células de sustentação e células basais (progenitoras). Localiza-se no teto da cavidade nasal." },
  { id: 440, topic: "Sistema Respiratório", question: "Os poros de Kohn permitem:", options: ["Passagem de sangue entre capilares", "Comunicação aérea entre alvéolos adjacentes (ventilação colateral)", "Secreção de surfactante", "Migração de macrófagos para o sangue"], correctIndex: 1, explanation: "Os poros de Kohn são aberturas nas paredes alveolares que conectam alvéolos adjacentes, permitindo ventilação colateral. Importantes para equalizar pressão e prevenir atelectasia em caso de obstrução bronquiolar." },
  { id: 441, topic: "Sistema Respiratório", question: "A epiglote possui esqueleto de:", options: ["Cartilagem hialina", "Cartilagem elástica", "Osso", "Fibrocartilagem"], correctIndex: 1, explanation: "A epiglote possui esqueleto de cartilagem elástica (flexível), revestida por epitélio estratificado pavimentoso na face lingual e epitélio respiratório na face laríngea." },
  { id: 442, topic: "Sistema Respiratório", question: "As cordas vocais verdadeiras são revestidas por:", options: ["Epitélio pseudoestratificado ciliado", "Epitélio estratificado pavimentoso não-queratinizado", "Epitélio simples cúbico", "Epitélio de transição"], correctIndex: 1, explanation: "As pregas vocais verdadeiras são revestidas por epitélio estratificado pavimentoso não-queratinizado (resistente ao atrito), com o músculo vocal e ligamento vocal subjacentes." },
  { id: 443, topic: "Sistema Respiratório", question: "Os bronquíolos respiratórios diferem dos terminais por:", options: ["Possuírem cartilagem", "Apresentarem alvéolos em suas paredes (início da porção respiratória)", "Terem epitélio mais alto", "Possuírem mais células caliciformes"], correctIndex: 1, explanation: "Os bronquíolos respiratórios são a transição entre porção condutora e respiratória, possuindo alvéolos individuais abrindo-se em suas paredes, onde começam as trocas gasosas." },
  { id: 444, topic: "Sistema Respiratório", question: "Os ductos alveolares são caracterizados por:", options: ["Parede de cartilagem", "Passagens alongadas com múltiplos alvéolos abrindo-se lateralmente, terminando em sacos alveolares", "Epitélio pseudoestratificado", "Presença de músculo estriado"], correctIndex: 1, explanation: "Os ductos alveolares são vias aéreas distais com paredes constituídas quase inteiramente por aberturas de alvéolos. Terminam em sacos alveolares (agrupamentos de alvéolos)." },
  { id: 445, topic: "Sistema Respiratório", question: "As fibras elásticas do parênquima pulmonar são importantes para:", options: ["Produção de surfactante", "Recuo elástico durante a expiração passiva", "Filtração do sangue", "Produção de muco"], correctIndex: 1, explanation: "As fibras elásticas nos septos alveolares são distendidas na inspiração e recolhem durante a expiração passiva. Sua destruição (enfisema/DPOC) causa perda de recuo elástico e hiperinsuflação." },
  { id: 446, topic: "Sistema Respiratório", question: "No enfisema pulmonar ocorre:", options: ["Fibrose dos septos", "Destruição dos septos alveolares com perda de superfície de troca gasosa", "Hiperplasia de células caliciformes sem destruição", "Espessamento da barreira hematoaérea"], correctIndex: 1, explanation: "O enfisema envolve destruição proteolítica (elastase > antiprotease) dos septos alveolares, formando espaços aéreos aumentados, perda de área de troca e perda de recuo elástico." },
  { id: 447, topic: "Sistema Respiratório", question: "As células neuroendócrinas pulmonares (PNEC) secretam:", options: ["Surfactante", "Serotonina, bombesina e calcitonina", "Muco", "Elastina"], correctIndex: 1, explanation: "As PNECs são células neuroendócrinas dispersas no epitélio brônquico que secretam aminas (serotonina) e peptídeos (bombesina, calcitonina). Podem estar isoladas ou em grupos (corpos neuroepiteliais)." },
  { id: 448, topic: "Sistema Respiratório", question: "A asma é caracterizada histologicamente por:", options: ["Destruição dos septos alveolares", "Hiperplasia do músculo liso brônquico, hiperplasia de caliciformes, espessamento da membrana basal e infiltrado eosinofílico", "Fibrose pleural", "Atrofia do epitélio"], correctIndex: 1, explanation: "A asma mostra remodelamento: hipertrofia/hiperplasia de músculo liso, metaplasia mucosa (mais caliciformes), espessamento da membrana basal subepitelial, edema e infiltrado inflamatório eosinofílico." },
  { id: 449, topic: "Sistema Respiratório", question: "As glândulas seromucosas da submucosa traqueal produzem:", options: ["Surfactante", "Muco e fluido seroso que contribuem para o revestimento mucociliar", "Hormônios", "Elastase"], correctIndex: 1, explanation: "As glândulas seromucosas traqueais/brônquicas são glândulas tubuloacinares mistas que secretam muco (porção mucosa) e fluido seroso com lisozima e lactoferrina (porção serosa). Contribuem para defesa mucociliar." },
  { id: 450, topic: "Sistema Respiratório", question: "O seio maxilar é revestido por:", options: ["Epitélio estratificado pavimentoso", "Epitélio respiratório (pseudoestratificado cilíndrico ciliado) mais delgado", "Epitélio olfatório", "Endotélio"], correctIndex: 1, explanation: "Os seios paranasais são revestidos por epitélio respiratório mais fino que o da cavidade nasal, com menos células caliciformes e glândulas. A drenagem mucociliar direciona secreções para os óstios nasais." },

  // =============================================
  // SISTEMA DIGESTÓRIO (451-475)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 451, topic: "Sistema Digestório", question: "A organização geral da parede do tubo digestivo, de dentro para fora, é:", options: ["Serosa, muscular, submucosa, mucosa", "Mucosa, submucosa, muscular e serosa (ou adventícia)", "Mucosa, muscular, submucosa, serosa", "Submucosa, mucosa, serosa, muscular"], correctIndex: 1, explanation: "A parede do tubo digestivo possui: mucosa (epitélio + lâmina própria + muscular da mucosa), submucosa (conjuntivo com plexo de Meissner), muscular (circular interna + longitudinal externa + plexo de Auerbach) e serosa/adventícia." },
  { id: 452, topic: "Sistema Digestório", question: "O esôfago é revestido por:", options: ["Epitélio simples cilíndrico", "Epitélio estratificado pavimentoso não-queratinizado", "Epitélio pseudoestratificado", "Epitélio de transição"], correctIndex: 1, explanation: "O esôfago é revestido por epitélio estratificado pavimentoso não-queratinizado, resistente à abrasão mecânica do bolo alimentar. Na transição esôfago-gástrica há mudança abrupta para epitélio simples cilíndrico." },
  { id: 453, topic: "Sistema Digestório", question: "As glândulas fúndicas gástricas contêm células parietais (oxínticas) que secretam:", options: ["Pepsinogênio", "HCl e fator intrínseco", "Muco", "Gastrina"], correctIndex: 1, explanation: "As células parietais secretam HCl (pela H⁺/K⁺-ATPase no sistema tubulovesicular/canalicular) e fator intrínseco (necessário para absorção de vitamina B12 no íleo). São acidófilas e ricas em mitocôndrias." },
  { id: 454, topic: "Sistema Digestório", question: "As células principais (zimogênicas) do estômago secretam:", options: ["HCl", "Pepsinogênio e lipase gástrica", "Gastrina", "Somatostatina"], correctIndex: 1, explanation: "As células principais estão na base das glândulas fúndicas, são basófilas (RER abundante) e secretam pepsinogênio (convertido em pepsina pelo HCl) e lipase gástrica." },
  { id: 455, topic: "Sistema Digestório", question: "As células G do antro gástrico produzem:", options: ["HCl", "Pepsinogênio", "Gastrina", "Serotonina"], correctIndex: 2, explanation: "As células G são células enteroendócrinas do antro gástrico que secretam gastrina para o sangue, estimulando a secreção de HCl pelas células parietais e a proliferação da mucosa gástrica." },
  { id: 456, topic: "Sistema Digestório", question: "As vilosidades intestinais são encontradas em:", options: ["Esôfago", "Estômago", "Intestino delgado", "Intestino grosso"], correctIndex: 2, explanation: "As vilosidades são projeções digitiformes da mucosa exclusivas do intestino delgado (duodeno, jejuno e íleo), aumentando dramaticamente a superfície de absorção junto às microvilosidades." },
  { id: 457, topic: "Sistema Digestório", question: "As criptas de Lieberkühn contêm células-tronco que renovam o epitélio intestinal a cada:", options: ["30 dias", "3-5 dias", "6 meses", "1 ano"], correctIndex: 1, explanation: "As células-tronco na base das criptas (marcadas por Lgr5+) dividem-se continuamente, gerando células que migram para cima, diferenciam-se (enterócitos, caliciformes, enteroendócrinas) e são descamadas no ápice em 3-5 dias." },
  { id: 458, topic: "Sistema Digestório", question: "As células de Paneth estão localizadas:", options: ["No ápice das vilosidades", "Na base das criptas de Lieberkühn do intestino delgado", "Na mucosa gástrica", "No esôfago"], correctIndex: 1, explanation: "As células de Paneth ocupam a base das criptas do intestino delgado, possuem grânulos apicais eosinofílicos contendo lisozima, defensinas e fosfolipase A2, contribuindo para a defesa antimicrobiana inata." },
  { id: 459, topic: "Sistema Digestório", question: "As placas de Peyer são encontradas em qual região do intestino delgado?", options: ["Duodeno", "Jejuno proximal", "Íleo (borda antimesentérica)", "Cólon"], correctIndex: 2, explanation: "As placas de Peyer são agregados de folículos linfoides na submucosa e lâmina própria do íleo, na borda antimesentérica. As células M no epitélio associado captam antígenos luminais para apresentação imune." },
  { id: 460, topic: "Sistema Digestório", question: "As glândulas de Brunner são encontradas na submucosa do:", options: ["Estômago", "Duodeno", "Jejuno", "Cólon"], correctIndex: 1, explanation: "As glândulas de Brunner são glândulas mucosas tubulares na submucosa do duodeno. Secretam muco alcalino (pH ~9) rico em bicarbonato que protege a mucosa duodenal do quimo ácido gástrico." },
  { id: 461, topic: "Sistema Digestório", question: "O intestino grosso difere do delgado por:", options: ["Possuir vilosidades mais longas", "Ausência de vilosidades, abundância de células caliciformes e criptas retas profundas", "Possuir células de Paneth abundantes", "Ter mucosa com pregas circulares"], correctIndex: 1, explanation: "O intestino grosso não possui vilosidades nem células de Paneth. Possui criptas retas profundas com abundantes células caliciformes (secreção mucosa), epitélio simples cilíndrico com borda estriada." },
  { id: 462, topic: "Sistema Digestório", question: "O plexo de Auerbach (mioentérico) está localizado:", options: ["Na mucosa", "Entre as camadas circular interna e longitudinal externa da muscular própria", "Na submucosa", "Na serosa"], correctIndex: 1, explanation: "O plexo de Auerbach está entre as camadas musculares e controla principalmente a motilidade (peristaltismo). O plexo de Meissner (submucoso) regula secreção e fluxo sanguíneo mucoso." },
  { id: 463, topic: "Sistema Digestório", question: "O fígado possui quais células fagocíticas residentes?", options: ["Células de Ito", "Células de Kupffer (macrófagos sinusoidais)", "Hepatócitos", "Células endoteliais", ], correctIndex: 1, explanation: "As células de Kupffer são macrófagos residentes nos sinusoides hepáticos que fagocitam eritrócitos senescentes, bactérias, debris e endotoxinas do sangue portal." },
  { id: 464, topic: "Sistema Digestório", question: "O espaço de Disse no fígado está localizado entre:", options: ["Hepatócitos adjacentes", "Endotélio sinusoidal e hepatócitos", "Ductos biliares e artéria hepática", "Veia central e veia porta"], correctIndex: 1, explanation: "O espaço de Disse (perissinusoidal) situa-se entre o endotélio fenestrado dos sinusoides e os hepatócitos. Contém plasma filtrado, fibras reticulares e células estreladas hepáticas (de Ito)." },
  { id: 465, topic: "Sistema Digestório", question: "As células estreladas hepáticas (de Ito) armazenam:", options: ["Glicogênio", "Vitamina A (retinol) em gotículas lipídicas", "Bilirrubina", "Ferro"], correctIndex: 1, explanation: "As células de Ito (estreladas) no espaço de Disse armazenam vitamina A. Na lesão hepática crônica, ativam-se em miofibroblastos, produzindo colágeno → fibrose/cirrose hepática." },
  { id: 466, topic: "Sistema Digestório", question: "O pâncreas exócrino é classificado como uma glândula:", options: ["Tubular simples", "Acinosa composta serosa", "Alveolar simples mucosa", "Tubuloacinosa mista"], correctIndex: 1, explanation: "O pâncreas exócrino possui ácinos serosos (enzimas digestivas: tripsina, lipase, amilase) com células centroacinares (início dos ductos) que secretam fluido rico em bicarbonato." },
  { id: 467, topic: "Sistema Digestório", question: "A vesícula biliar é revestida por:", options: ["Epitélio estratificado pavimentoso", "Epitélio simples cilíndrico com microvilosidades", "Epitélio pseudoestratificado", "Epitélio de transição"], correctIndex: 1, explanation: "A vesícula biliar possui epitélio simples cilíndrico alto com microvilosidades que absorvem água e íons, concentrando a bile. Não possui muscular da mucosa nem submucosa verdadeira." },
  { id: 468, topic: "Sistema Digestório", question: "As células M (microfold) do epitélio intestinal estão associadas a:", options: ["Absorção de lipídios", "Captação e transporte de antígenos para o tecido linfoide (placas de Peyer)", "Secreção de muco", "Produção de enzimas digestivas"], correctIndex: 1, explanation: "As células M captam antígenos do lúmen por transcitose e os apresentam a células imunes (linfócitos e macrófagos) no tecido linfático subjacente. Possuem microfolds (pregas) ao invés de microvilosidades." },
  { id: 469, topic: "Sistema Digestório", question: "O apêndice vermiforme é caracterizado por:", options: ["Vilosidades longas", "Abundante tecido linfoide na lâmina própria e submucosa", "Glândulas de Brunner", "Epitélio estratificado"], correctIndex: 1, explanation: "O apêndice possui abundante tecido linfoide (folículos com centros germinativos) na lâmina própria e submucosa. Participa da imunidade local, atuando como reservatório de bactérias comensais." },
  { id: 470, topic: "Sistema Digestório", question: "Os hepatócitos são organizados em:", options: ["Ácinos simples", "Cordões (trabéculas) radiando da veia central, entre sinusoides", "Folículos fechados", "Ductos ramificados"], correctIndex: 1, explanation: "Os hepatócitos organizam-se em cordões (placas) de uma célula de espessura, radiando da veia centrolobular, separados por sinusoides. Formam o lóbulo hepático clássico." },
  { id: 471, topic: "Sistema Digestório", question: "A tríade portal (espaço porta) é composta por:", options: ["Veia central, artéria e nervo", "Ramo da veia porta, ramo da artéria hepática e ducto biliar", "Sinusoides, hepatócitos e células de Kupffer", "Apenas vasos linfáticos"], correctIndex: 1, explanation: "O espaço porta contém: ramo da veia porta (sangue venoso intestinal), ramo da artéria hepática (sangue oxigenado) e ducto biliar interlobular, envoltos em tecido conjuntivo." },
  { id: 472, topic: "Sistema Digestório", question: "A bile flui dos hepatócitos em direção:", options: ["À veia central", "Dos canalículos biliares → dúctulos (canais de Hering) → ductos biliares → espaço porta", "Dos sinusoides para os hepatócitos", "Da veia porta para a veia central"], correctIndex: 1, explanation: "A bile flui em sentido oposto ao sangue: dos canalículos biliares (entre hepatócitos) → dúctulos/canais de Hering → ductos interlobulares → ductos maiores → ducto hepático." },
  { id: 473, topic: "Sistema Digestório", question: "As células enteroendócrinas do intestino delgado secretam:", options: ["Apenas muco", "Hormônios como CCK, secretina, GIP e serotonina", "Apenas enzimas digestivas", "Apenas ácido clorídrico"], correctIndex: 1, explanation: "As células enteroendócrinas são dispersas no epitélio e secretam hormônios para o sangue: CCK (contração da vesícula), secretina (secreção de bicarbonato), GIP (insulina), serotonina (motilidade)." },
  { id: 474, topic: "Sistema Digestório", question: "As pregas circulares (válvulas de Kerckring) são encontradas no:", options: ["Esôfago", "Estômago", "Intestino delgado (especialmente duodeno e jejuno)", "Reto"], correctIndex: 2, explanation: "As pregas circulares são elevações permanentes da submucosa + mucosa no intestino delgado, mais proeminentes no duodeno e jejuno. Juntamente com vilosidades e microvilosidades, ampliam a superfície absortiva." },
  { id: 475, topic: "Sistema Digestório", question: "A doença celíaca é caracterizada histologicamente por:", options: ["Hiperplasia das células de Paneth", "Atrofia vilositária, hiperplasia de criptas e infiltrado linfocitário intraepitelial", "Fibrose da submucosa", "Metaplasia do epitélio gástrico"], correctIndex: 1, explanation: "A doença celíaca (enteropatia por glúten) mostra graus variados de atrofia vilositária, hiperplasia de criptas e aumento de linfócitos intraepiteliais (classificação de Marsh-Oberhuber)." },

  // =============================================
  // SISTEMA URINÁRIO (476-500)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 476, topic: "Sistema Urinário", question: "O néfron é composto por:", options: ["Apenas glomérulo", "Corpúsculo renal (glomérulo + cápsula de Bowman) e túbulos renais (proximal, alça de Henle, distal)", "Apenas túbulo coletor", "Apenas pelve renal"], correctIndex: 1, explanation: "O néfron é a unidade funcional do rim: corpúsculo renal (glomérulo + cápsula de Bowman) + túbulo contorcido proximal + alça de Henle + túbulo contorcido distal. O ducto coletor não é parte do néfron stricto sensu." },
  { id: 477, topic: "Sistema Urinário", question: "A barreira de filtração glomerular é composta por:", options: ["Apenas endotélio", "Endotélio fenestrado, membrana basal glomerular e podócitos com fendas de filtração", "Apenas podócitos", "Epitélio de transição"], correctIndex: 1, explanation: "A barreira de filtração possui três camadas: endotélio fenestrado (sem diafragma), membrana basal glomerular (colágeno IV, laminina, proteoglicanos) e podócitos com fendas de filtração (nefrina/podocina)." },
  { id: 478, topic: "Sistema Urinário", question: "Os podócitos são células:", options: ["Endoteliais", "Epiteliais viscerais da cápsula de Bowman com pedicelos que envolvem os capilares", "Musculares lisas", "Mesangiais"], correctIndex: 1, explanation: "Os podócitos são células epiteliais viscerais da cápsula de Bowman com prolongamentos primários e pedicelos (secundários) que interdigitam, formando fendas de filtração com diafragmas de nefrina." },
  { id: 479, topic: "Sistema Urinário", question: "O túbulo contorcido proximal (TCP) é revestido por:", options: ["Epitélio pavimentoso", "Epitélio simples cúbico com borda em escova (microvilosidades), citoplasma acidófilo e limites celulares indistintos", "Epitélio de transição", "Epitélio estratificado"], correctIndex: 1, explanation: "O TCP tem epitélio cúbico com microvilosidades (borda em escova), muitas mitocôndrias basolaterais (estriações) e interdigitações. Reabsorve ~65-80% do filtrado (glicose, aminoácidos, Na⁺, água)." },
  { id: 480, topic: "Sistema Urinário", question: "O segmento delgado da alça de Henle é revestido por:", options: ["Epitélio cúbico com borda em escova", "Epitélio simples pavimentoso", "Epitélio pseudoestratificado", "Epitélio de transição"], correctIndex: 1, explanation: "O segmento delgado da alça de Henle possui epitélio simples pavimentoso fino, permeável à água (descendente) ou solutos (ascendente), essencial para o mecanismo de contracorrente." },
  { id: 481, topic: "Sistema Urinário", question: "O aparelho justaglomerular é composto por:", options: ["Apenas podócitos", "Células justaglomerulares (granulares), mácula densa e células mesangiais extraglomerulares", "Apenas células endoteliais", "Apenas túbulo proximal"], correctIndex: 1, explanation: "O aparelho justaglomerular inclui: células granulares (músculo liso modificado da arteríola aferente, secretam renina), mácula densa (TCD, sensor de NaCl) e mesângio extraglomerular (lacis cells)." },
  { id: 482, topic: "Sistema Urinário", question: "As células justaglomerulares secretam:", options: ["Eritropoietina", "Renina", "ADH", "Aldosterona"], correctIndex: 1, explanation: "As células justaglomerulares (granulares) são células musculares lisas modificadas da arteríola aferente que secretam renina (protease) em resposta a baixa pressão, baixo NaCl (mácula densa) ou estímulo simpático." },
  { id: 483, topic: "Sistema Urinário", question: "A mácula densa está localizada:", options: ["No glomérulo", "Na parede do túbulo contorcido distal adjacente ao glomérulo", "Na arteríola eferente", "No ducto coletor"], correctIndex: 1, explanation: "A mácula densa é uma placa de células epiteliais especializadas no TCD, junto ao polo vascular do glomérulo. Detecta concentração de NaCl no fluido tubular e regula a secreção de renina e o feedback tubuloglomerular." },
  { id: 484, topic: "Sistema Urinário", question: "As células mesangiais glomerulares possuem função de:", options: ["Secreção de muco", "Suporte estrutural, fagocitose, contração (regulação do fluxo) e produção de matriz", "Produção de surfactante", "Secreção de hormônios"], correctIndex: 1, explanation: "As células mesangiais dão suporte aos capilares glomerulares, fagocitam macromoléculas retidas, contraem-se (regulando fluxo capilar) e produzem matriz mesangial e citocinas." },
  { id: 485, topic: "Sistema Urinário", question: "O túbulo contorcido distal (TCD) difere do proximal por:", options: ["Ter borda em escova mais proeminente", "Ter epitélio cúbico sem borda em escova, lúmen mais amplo e limites celulares mais nítidos", "Ser mais longo", "Ser revestido por epitélio pavimentoso"], correctIndex: 1, explanation: "O TCD tem epitélio cúbico mais baixo, sem borda em escova (poucas microvilosidades), lúmen mais aberto e células menores. Responde à aldosterona (reabsorção de Na⁺) e ao PTH." },
  { id: 486, topic: "Sistema Urinário", question: "Os ductos coletores possuem dois tipos celulares principais:", options: ["Células parietais e principais", "Células principais (claras) e células intercaladas (escuras)", "Podócitos e mesangiais", "Células ciliadas e caliciformes"], correctIndex: 1, explanation: "Células principais (claras, receptores de ADH → aquaporina-2, reabsorção de água; aldosterona → reabsorção Na⁺). Células intercaladas (escuras, H⁺-ATPase, secretam H⁺ ou HCO₃⁻, equilíbrio ácido-base)." },
  { id: 487, topic: "Sistema Urinário", question: "A eritropoietina (EPO) é produzida principalmente por:", options: ["Glomérulo", "Células intersticiais peritubulares do córtex renal (fibroblastos)", "Ductos coletores", "Mácula densa"], correctIndex: 1, explanation: "A EPO é produzida por fibroblastos intersticiais peritubulares do córtex renal em resposta à hipóxia (via HIF). Estimula a eritropoiese na medula óssea. Na insuficiência renal crônica, há anemia por deficiência de EPO." },
  { id: 488, topic: "Sistema Urinário", question: "O urotélio (epitélio de transição) reveste:", options: ["Néfrons", "Cálices, pelve renal, ureteres e bexiga", "Glomérulos", "Uretra peniana"], correctIndex: 1, explanation: "O urotélio reveste as vias urinárias excretoras (cálices → pelve → ureteres → bexiga). Possui células superficiais em guarda-chuva com placas de uroplaquina que formam barreira impermeável à urina." },
  { id: 489, topic: "Sistema Urinário", question: "As uroplaquinas são proteínas encontradas:", options: ["No glomérulo", "Na superfície apical das células em guarda-chuva do urotélio", "No túbulo proximal", "Na cápsula renal"], correctIndex: 1, explanation: "As uroplaquinas formam placas cristalinas rígidas na membrana apical das células em guarda-chuva, conferindo impermeabilidade e protegendo contra componentes tóxicos da urina." },
  { id: 490, topic: "Sistema Urinário", question: "A vitamina D é convertida em sua forma ativa (calcitriol) no:", options: ["Fígado", "Rim (túbulo contorcido proximal, pela 1α-hidroxilase)", "Pele", "Intestino"], correctIndex: 1, explanation: "A 25-OH-vitamina D (do fígado) é convertida em 1,25-(OH)₂-vitamina D₃ (calcitriol, forma ativa) pela 1α-hidroxilase no TCP renal. O PTH estimula essa enzima. O calcitriol aumenta absorção intestinal de Ca²⁺." },
  { id: 491, topic: "Sistema Urinário", question: "O glomérulo renal está localizado no:", options: ["Medula renal", "Córtex renal", "Pelve renal", "Cápsula renal"], correctIndex: 1, explanation: "Todos os glomérulos localizam-se no córtex renal. A medula contém alças de Henle, ductos coletores e vasa recta. A disposição dos néfrons justamedulares é importante para concentração urinária." },
  { id: 492, topic: "Sistema Urinário", question: "A arteríola eferente do glomérulo forma:", options: ["Sinusoides hepáticos", "Capilares peritubulares (córtex) ou vasa recta (medula)", "Capilares pulmonares", "Capilares glomerulares"], correctIndex: 1, explanation: "A arteríola eferente origina capilares peritubulares (néfrons corticais) ou vasa recta (néfrons justamedulares). Os vasa recta são importantes para o mecanismo de contracorrente na medula." },
  { id: 493, topic: "Sistema Urinário", question: "Na nefropatia diabética, a alteração glomerular clássica é:", options: ["Proliferação endotelial", "Espessamento da membrana basal glomerular e expansão mesangial (glomeruloesclerose de Kimmelstiel-Wilson)", "Atrofia dos podócitos sem outras alterações", "Necrose tubular"], correctIndex: 1, explanation: "A nefropatia diabética mostra espessamento da MBG, expansão mesangial difusa e nódulos de Kimmelstiel-Wilson (glomeruloesclerose nodular). Há também hialinose arteriolar aferente e eferente." },
  { id: 494, topic: "Sistema Urinário", question: "A cápsula de Bowman possui:", options: ["Apenas folheto visceral", "Folheto parietal (epitélio simples pavimentoso) e folheto visceral (podócitos)", "Apenas endotélio", "Epitélio de transição"], correctIndex: 1, explanation: "A cápsula de Bowman tem folheto parietal (epitélio simples pavimentoso) delimitando o espaço urinário e folheto visceral formado por podócitos que envolvem os capilares glomerulares." },
  { id: 495, topic: "Sistema Urinário", question: "O mecanismo de contracorrente depende de:", options: ["Apenas dos glomérulos", "Alça de Henle, vasa recta e interstício medular hiperosmolar", "Apenas dos ductos coletores", "Apenas da cápsula renal"], correctIndex: 1, explanation: "O mecanismo de contracorrente envolve: alça de Henle (multiplicador), vasa recta (trocador) e interstício medular hiperosmolar (ureia + NaCl). Permite concentração máxima da urina (~1200 mOsm/kg)." },
  { id: 496, topic: "Sistema Urinário", question: "O ADH (vasopressina) atua nos:", options: ["Glomérulos", "Ductos coletores, inserindo aquaporina-2 na membrana apical", "Túbulos proximais", "Alça ascendente de Henle"], correctIndex: 1, explanation: "O ADH liga-se ao receptor V2 basolateral das células principais → AMPc → inserção de aquaporina-2 na membrana apical → reabsorção de água → urina concentrada. Sem ADH → diabetes insipidus (urina diluída)." },
  { id: 497, topic: "Sistema Urinário", question: "As pirâmides renais estão localizadas na:", options: ["Córtex", "Medula renal", "Cápsula", "Pelve renal"], correctIndex: 1, explanation: "As pirâmides renais (de Malpighi) são estruturas cônicas na medula com bases voltadas ao córtex e ápices (papilas) projetando-se nos cálices menores. Contêm alças de Henle e ductos coletores." },
  { id: 498, topic: "Sistema Urinário", question: "Os raios medulares (de Ferrein) são:", options: ["Estruturas da medula renal", "Prolongamentos de ductos coletores e túbulos retos que se estendem para o córtex", "Artérias arqueadas", "Nervos renais"], correctIndex: 1, explanation: "Os raios medulares são estriações que penetram o córtex a partir das pirâmides, formados por grupos paralelos de túbulos retos e ductos coletores corticais." },
  { id: 499, topic: "Sistema Urinário", question: "A proteinúria na síndrome nefrótica deve-se principalmente a:", options: ["Lesão tubular", "Lesão da barreira de filtração glomerular (podócitos e/ou MBG)", "Obstrução ureteral", "Infecção urinária"], correctIndex: 1, explanation: "A síndrome nefrótica resulta de lesão da barreira de filtração (fusão dos pedicelos, perda da carga negativa da MBG), causando proteinúria maciça (>3,5 g/dia), hipoalbuminemia, edema e hiperlipidemia." },
  { id: 500, topic: "Sistema Urinário", question: "A uretra masculina difere da feminina por:", options: ["Ser mais curta", "Ser mais longa e possuir três segmentos (prostática, membranosa e esponjosa)", "Ser revestida apenas por epitélio de transição", "Não possuir esfíncter"], correctIndex: 1, explanation: "A uretra masculina (~20 cm) tem porção prostática (urotélio), membranosa (estratificado/pseudoestratificado cilíndrico) e esponjosa/peniana (estratificado cilíndrico → estratificado pavimentoso no meato). A feminina (~4 cm)." },

  // =============================================
  // PELE E ANEXOS (501-525)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 501, topic: "Pele e Anexos", question: "As camadas da epiderme, da mais profunda à mais superficial, são:", options: ["Córnea, granulosa, espinhosa, basal", "Basal (germinativa), espinhosa, granulosa, lúcida e córnea", "Espinhosa, basal, granulosa, córnea, lúcida", "Córnea, lúcida, espinhosa, basal, granulosa"], correctIndex: 1, explanation: "A epiderme possui 5 camadas na pele espessa (palmas/plantas): basal → espinhosa → granulosa → lúcida → córnea. A camada lúcida está ausente na pele fina." },
  { id: 502, topic: "Pele e Anexos", question: "Os queratinócitos constituem qual porcentagem das células epidérmicas?", options: ["50%", "65%", "85-90%", "100%"], correctIndex: 2, explanation: "Os queratinócitos representam 85-90% das células da epiderme, produzindo queratina e formando a barreira protetora. Os demais são melanócitos, células de Langerhans e células de Merkel." },
  { id: 503, topic: "Pele e Anexos", question: "Os melanócitos estão localizados em qual camada da epiderme?", options: ["Córnea", "Granulosa", "Basal (germinativa)", "Espinhosa superficial"], correctIndex: 2, explanation: "Os melanócitos são células dendríticas de origem da crista neural localizadas na camada basal. Produzem melanina nos melanossomos e transferem-nos aos queratinócitos vizinhos (unidade melanoepidérmica)." },
  { id: 504, topic: "Pele e Anexos", question: "As células de Langerhans da epiderme são:", options: ["Queratinócitos modificados", "Células apresentadoras de antígeno (dendríticas) derivadas da medula óssea", "Melanócitos", "Fibroblastos"], correctIndex: 1, explanation: "As células de Langerhans são células dendríticas do sistema imune, localizadas na camada espinhosa. Capturam antígenos, migram para linfonodos regionais e apresentam-nos a linfócitos T (resposta adaptativa)." },
  { id: 505, topic: "Pele e Anexos", question: "As células de Merkel estão associadas a:", options: ["Produção de melanina", "Função mecanorreceptora (tato)", "Secreção de suor", "Produção de sebo"], correctIndex: 1, explanation: "As células de Merkel são mecanorreceptores na camada basal, associadas a terminações nervosas aferentes (discos de Merkel). Detectam pressão leve e textura. Contêm grânulos com neuropeptídeos." },
  { id: 506, topic: "Pele e Anexos", question: "A camada granulosa contém:", options: ["Apenas melanina", "Grânulos de querato-hialina (precursores de filagrina) e corpos lamelares", "Fibras elásticas", "Células de Langerhans exclusivamente"], correctIndex: 1, explanation: "A camada granulosa possui grânulos de querato-hialina (basófilos, contêm profilagrina → filagrina que agrega queratina) e corpos lamelares (lipídios que são exocitados formando a barreira impermeável intercelular)." },
  { id: 507, topic: "Pele e Anexos", question: "A derme é dividida em:", options: ["Apenas derme reticular", "Derme papilar (superficial, conjuntivo frouxo) e derme reticular (profunda, conjuntivo denso não-modelado)", "Apenas derme papilar", "Derme, hipoderme e epiderme"], correctIndex: 1, explanation: "A derme papilar é fina (conjuntivo frouxo com fibras finas, papilas dérmicas) e a derme reticular é espessa (conjuntivo denso não-modelado com fibras colágenas grossas e elásticas)." },
  { id: 508, topic: "Pele e Anexos", question: "As glândulas sudoríparas écrinas são:", options: ["Holócrinas", "Merócrinas, tubulares enoveladas simples, presentes em quase toda a pele", "Apócrinas", "Sebáceas"], correctIndex: 1, explanation: "As glândulas écrinas são merócrinas, independentes dos folículos pilosos, presentes em toda a pele (mais densas em palmas/plantas). Secretam suor hipotônico para termorregulação." },
  { id: 509, topic: "Pele e Anexos", question: "As glândulas sudoríparas apócrinas diferem das écrinas por:", options: ["Serem menores", "Estarem associadas a folículos pilosos, desembocarem no infundíbulo e estarem nas axilas e região anogenital", "Serem encontradas em toda a pele", "Produzirem suor incolor e inodoro"], correctIndex: 1, explanation: "As glândulas apócrinas são maiores, têm lúmen amplo, desembocam no infundíbulo do folículo piloso e estão restritas a axilas, aréola, períneo e genitália. Secretam fluido proteico que bactérias decompõem (odor)." },
  { id: 510, topic: "Pele e Anexos", question: "As glândulas sebáceas são classificadas como:", options: ["Merócrinas", "Holócrinas (célula inteira liberada como secreção)", "Apócrinas", "Endócrinas"], correctIndex: 1, explanation: "As glândulas sebáceas são holócrinas: a célula inteira se preenche de lipídios, desintegra-se e libera o sebo no canal do folículo piloso. O sebo lubrifica pele e pelos." },
  { id: 511, topic: "Pele e Anexos", question: "O pelo é formado por:", options: ["Células epiteliais simples", "Queratinócitos altamente queratinizados organizados em medula, córtex e cutícula", "Tecido conjuntivo", "Fibras elásticas"], correctIndex: 1, explanation: "O pelo possui medula (centro, presente em pelos grossos), córtex (queratina dura, principal massa) e cutícula (camada externa de escamas). A melanina no córtex determina a cor." },
  { id: 512, topic: "Pele e Anexos", question: "O músculo eretor do pelo é:", options: ["Músculo estriado esquelético", "Músculo liso que conecta a derme ao folículo piloso", "Músculo cardíaco", "Músculo estriado visceral"], correctIndex: 1, explanation: "O músculo eretor do pelo (arrector pili) é músculo liso que se insere na derme papilar e no folículo piloso. Sua contração (frio, emoção) causa piloereção ('arrepio') e comprime a glândula sebácea." },
  { id: 513, topic: "Pele e Anexos", question: "A hipoderme (tela subcutânea) é formada por:", options: ["Epitélio estratificado", "Tecido conjuntivo frouxo e tecido adiposo (panículo adiposo)", "Osso esponjoso", "Cartilagem"], correctIndex: 1, explanation: "A hipoderme não faz parte da pele propriamente dita. É formada por tecido conjuntivo frouxo e adiposo unilocular (panículo adiposo), funcionando como isolamento térmico, reserva energética e amortecimento." },
  { id: 514, topic: "Pele e Anexos", question: "A queratina dura difere da queratina mole porque:", options: ["Não contém enxofre", "Possui mais pontes dissulfeto, é mais rígida e está nos pelos e unhas", "É encontrada apenas na epiderme", "É produzida por melanócitos"], correctIndex: 1, explanation: "A queratina dura (α-queratina) tem mais pontes dissulfeto (cisteína), é mais compacta e resistente. Encontrada em pelos e unhas. A queratina mole da epiderme descama continuamente." },
  { id: 515, topic: "Pele e Anexos", question: "Os corpúsculos de Meissner são mecanorreceptores encontrados:", options: ["Na hipoderme", "Nas papilas dérmicas, especialmente em polpas digitais e lábios", "Na epiderme", "Na derme reticular profunda"], correctIndex: 1, explanation: "Os corpúsculos de Meissner são mecanorreceptores encapsulados nas papilas dérmicas, sensíveis a toque leve e discriminação de textura. Abundantes em polpas digitais, lábios e mamilos." },
  { id: 516, topic: "Pele e Anexos", question: "Os corpúsculos de Pacini detectam:", options: ["Temperatura", "Pressão profunda e vibração", "Dor", "Luz"], correctIndex: 1, explanation: "Os corpúsculos de Pacini (lamelares) são grandes receptores encapsulados (camadas concêntricas de lamelas) na derme profunda e hipoderme, detectando pressão profunda e vibração de alta frequência." },
  { id: 517, topic: "Pele e Anexos", question: "A unha cresce a partir:", options: ["Do leito ungueal", "Da matriz ungueal (raiz)", "Da cutícula", "Do hiponíquio"], correctIndex: 1, explanation: "A matriz ungueal, na base da unha sob a dobra proximal, contém queratinócitos que proliferam e queratinizam (queratina dura), formando a placa ungueal. A lúnula é a parte visível da matriz." },
  { id: 518, topic: "Pele e Anexos", question: "A melanina é sintetizada a partir de:", options: ["Histidina", "Tirosina (pela enzima tirosinase)", "Triptofano", "Fenilalanina diretamente"], correctIndex: 1, explanation: "A melanina é produzida pela tirosinase nos melanossomos: tirosina → DOPA → dopaquinona → eumelanina (marrom-preta) ou feomelanina (amarelo-vermelha). Mutações na tirosinase causam albinismo." },
  { id: 519, topic: "Pele e Anexos", question: "O ciclo do pelo inclui as fases:", options: ["Apenas crescimento", "Anágena (crescimento), catágena (involução) e telógena (repouso)", "Apenas repouso e queda", "Mitose e meiose"], correctIndex: 1, explanation: "O ciclo piloso: anágena (crescimento ativo, 2-6 anos no couro cabeludo), catágena (regressão/apoptose, 2-3 semanas) e telógena (repouso, 2-3 meses). Queda ocorre na transição telógena → anágena." },
  { id: 520, topic: "Pele e Anexos", question: "A pele espessa difere da pele fina por:", options: ["Ter menos camadas epidérmicas", "Possuir epiderme mais espessa com camada lúcida, sem folículos pilosos", "Ter mais folículos pilosos", "Ter derme mais fina"], correctIndex: 1, explanation: "A pele espessa (palmas/plantas) tem epiderme espessa com 5 camadas (incluindo lúcida), sem folículos pilosos nem glândulas sebáceas, mas com glândulas écrinas abundantes." },
  { id: 521, topic: "Pele e Anexos", question: "A psoríase é caracterizada histologicamente por:", options: ["Atrofia epidérmica", "Hiperproliferação epidérmica com paraqueratose, acantose, papilomatose e microabscessos de Munro", "Perda total de melanócitos", "Fibrose dérmica sem alteração epidérmica"], correctIndex: 1, explanation: "A psoríase mostra hiperproliferação dos queratinócitos, paraqueratose (núcleos na camada córnea), acantose (espessamento epidérmico), papilomatose (papilas alongadas) e microabscessos de Munro (neutrófilos na córnea)." },
  { id: 522, topic: "Pele e Anexos", question: "As linhas de Langer representam:", options: ["Terminações nervosas", "Orientação predominante dos feixes de colágeno na derme reticular", "Distribuição de melanócitos", "Limites entre dermatómos"], correctIndex: 1, explanation: "As linhas de Langer indicam a orientação principal dos feixes de colágeno na derme reticular. Incisões cirúrgicas paralelas a essas linhas cicatrizam melhor com menos tensão." },
  { id: 523, topic: "Pele e Anexos", question: "Os queratinócitos da camada espinhosa aparecem com 'espinhos' porque:", options: ["Possuem projeções reais", "Os desmossomos permanecem enquanto o citoplasma retrai durante o processamento histológico", "Contêm melanina", "Possuem cílios"], correctIndex: 1, explanation: "O aspecto espinhoso é artefato de retração citoplasmática durante a fixação, enquanto os desmossomos (pontes de adesão) permanecem, criando pontes intercelulares visíveis (tonofilamentos de queratina)." },
  { id: 524, topic: "Pele e Anexos", question: "O vitiligo é causado por:", options: ["Excesso de melanina", "Destruição autoimune dos melanócitos", "Hiperplasia de células de Langerhans", "Infecção fúngica"], correctIndex: 1, explanation: "O vitiligo resulta da destruição autoimune dos melanócitos (anticorpos e linfócitos T citotóxicos), causando máculas acrômicas. Histologicamente, há ausência de melanócitos na camada basal." },
  { id: 525, topic: "Pele e Anexos", question: "A cicatrização por segunda intenção difere da primeira intenção por:", options: ["Ser mais rápida", "Envolver maior formação de tecido de granulação, contração da ferida e maior cicatriz", "Não envolver fibroblastos", "Não formar colágeno"], correctIndex: 1, explanation: "Na segunda intenção, a ferida é grande/infectada, não pode ser suturada: abundante tecido de granulação preenche o defeito, miofibroblastos contraem a ferida, e a cicatriz resultante é maior e mais irregular." },

  // =============================================
  // SISTEMA ENDÓCRINO (526-550)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 526, topic: "Sistema Endócrino", question: "A hipófise (pituitária) é dividida em:", options: ["Apenas lobo anterior", "Adeno-hipófise (anterior) e neuro-hipófise (posterior)", "Apenas lobo posterior", "Três lobos iguais"], correctIndex: 1, explanation: "A adeno-hipófise (pars distalis, intermedia e tuberalis) é glandular, de origem ectodérmica (bolsa de Rathke). A neuro-hipófise (pars nervosa, infundíbulo) é neural, extensão do hipotálamo." },
  { id: 527, topic: "Sistema Endócrino", question: "Os somatotrofos da adeno-hipófise secretam:", options: ["ACTH", "GH (hormônio do crescimento)", "TSH", "Prolactina"], correctIndex: 1, explanation: "Os somatotrofos são as células mais abundantes da adeno-hipófise (~50%), acidófilas, secretando GH (somatotropina). Regulados pelo GHRH (+) e somatostatina (-) hipotalâmicos." },
  { id: 528, topic: "Sistema Endócrino", question: "Os hormônios armazenados na neuro-hipófise são:", options: ["GH e prolactina", "Ocitocina e ADH (vasopressina)", "TSH e FSH", "ACTH e MSH"], correctIndex: 1, explanation: "A neuro-hipófise armazena e libera ocitocina e ADH, produzidos nos núcleos supraóptico e paraventricular do hipotálamo. Transportados pelos axônios hipotálamo-hipofisários e armazenados como corpos de Herring." },
  { id: 529, topic: "Sistema Endócrino", question: "A tireoide é composta por unidades funcionais chamadas:", options: ["Ácinos", "Folículos tireoidianos (preenchidos por coloide)", "Ilhotas", "Lóbulos"], correctIndex: 1, explanation: "Os folículos tireoidianos são esferas de epitélio simples (tireócitos) que envolvem coloide (tireoglobulina iodada). O tamanho e a forma dos folículos variam com a atividade funcional." },
  { id: 530, topic: "Sistema Endócrino", question: "As células parafoliculares (C) da tireoide secretam:", options: ["T3 e T4", "Calcitonina", "PTH", "Aldosterona"], correctIndex: 1, explanation: "As células C (parafoliculares) secretam calcitonina, que inibe osteoclastos e reduz calcemia. São maiores, claras, com grânulos secretórios. Originam-se da crista neural (último arco branquial). Seu tumor é o carcinoma medular." },
  { id: 531, topic: "Sistema Endócrino", question: "As paratireoides são compostas por:", options: ["Apenas células foliculares", "Células principais (PTH) e células oxífilas", "Apenas células C", "Tireócitos modificados"], correctIndex: 1, explanation: "As paratireoides possuem células principais (menores, secretam PTH que aumenta calcemia) e células oxífilas (maiores, acidófilas, ricas em mitocôndrias, função incerta, aumentam com idade)." },
  { id: 532, topic: "Sistema Endócrino", question: "A zona glomerulosa do córtex da suprarrenal produz:", options: ["Cortisol", "Aldosterona (mineralocorticoide)", "Andrógenos", "Epinefrina"], correctIndex: 1, explanation: "O córtex suprarrenal: zona glomerulosa → aldosterona (regulação de Na⁺/K⁺), zona fasciculada → cortisol (glicocorticoide), zona reticulada → DHEA/andrógenos. Mnemônico: GFR → Salt, Sugar, Sex." },
  { id: 533, topic: "Sistema Endócrino", question: "A zona fasciculada do córtex suprarrenal é:", options: ["A mais externa", "A mais espessa (~75%), com células claras esponjosas (espongiócitos) produtoras de cortisol", "A mais interna", "Produtora de adrenalina"], correctIndex: 1, explanation: "A zona fasciculada é a mais espessa, com cordões paralelos de células grandes e claras (espongiócitos, ricos em gotículas lipídicas de colesterol) que produzem cortisol sob estímulo do ACTH." },
  { id: 534, topic: "Sistema Endócrino", question: "A medula da suprarrenal é composta por:", options: ["Células corticais modificadas", "Células cromafins (feocromócitos) que secretam catecolaminas (adrenalina e noradrenalina)", "Hepatócitos", "Neurônios motores"], correctIndex: 1, explanation: "A medula suprarrenal contém células cromafins, neurônios simpáticos pós-ganglionares modificados, que secretam adrenalina (~80%) e noradrenalina (~20%). Grânulos cromafins coram com sais de cromo." },
  { id: 535, topic: "Sistema Endócrino", question: "As ilhotas de Langerhans do pâncreas contêm:", options: ["Apenas células α", "Células β (insulina), α (glucagon), δ (somatostatina) e PP (polipeptídeo pancreático)", "Apenas células β", "Células acinosas"], correctIndex: 1, explanation: "As ilhotas têm: células β (~70%, centrais, insulina), α (~20%, periféricas, glucagon), δ (~5-10%, somatostatina) e PP (~1-2%, polipeptídeo pancreático). Ricamente vascularizadas com capilares fenestrados." },
  { id: 536, topic: "Sistema Endócrino", question: "A insulina é produzida pelas células:", options: ["Alfa", "Beta das ilhotas de Langerhans", "Delta", "Acinosas"], correctIndex: 1, explanation: "As células β são as mais abundantes nas ilhotas, produzindo insulina (armazenada em grânulos com cristais de zinco). A insulina reduz glicemia promovendo captação celular de glicose e síntese de glicogênio." },
  { id: 537, topic: "Sistema Endócrino", question: "A glândula pineal produz:", options: ["Cortisol", "Melatonina", "Tiroxina", "GH"], correctIndex: 1, explanation: "A pineal (epífise) produz melatonina a partir de serotonina, sob estímulo de escuridão (via trato retino-hipotalâmico → gânglio cervical superior). Regula ritmos circadianos e sono." },
  { id: 538, topic: "Sistema Endócrino", question: "O sistema porta-hipofisário permite:", options: ["Drenagem venosa direta ao coração", "Transporte de hormônios hipotalâmicos diretamente à adeno-hipófise sem diluição sistêmica", "Filtração do LCR", "Trocas gasosas"], correctIndex: 1, explanation: "O sistema porta conecta capilares da eminência mediana (onde hormônios hipotalâmicos são liberados) aos sinusoides da adeno-hipófise, permitindo regulação hormonal precisa sem diluição na circulação geral." },
  { id: 539, topic: "Sistema Endócrino", question: "O feocromocitoma é um tumor da:", options: ["Tireoide", "Medula da suprarrenal (células cromafins)", "Hipófise", "Paratireoide"], correctIndex: 1, explanation: "O feocromocitoma origina-se das células cromafins da medula suprarrenal, secretando catecolaminas em excesso → hipertensão paroxística, taquicardia, cefaleia, sudorese. 'Regra dos 10' (10% bilaterais, extra-adrenais, malignos)." },
  { id: 540, topic: "Sistema Endócrino", question: "Os tireócitos em atividade intensa (hipertireoidismo) tornam-se:", options: ["Pavimentosos com coloide abundante", "Cilíndricos altos com coloide escasso e vacuolizado", "Impossíveis de identificar", "Achatados sem alteração do coloide"], correctIndex: 1, explanation: "No hipertireoidismo, tireócitos tornam-se colunares altos (muita síntese e secreção), o coloide diminui e apresenta vacúolos de reabsorção (lacunas de reabsorção) na periferia do folículo." },
  { id: 541, topic: "Sistema Endócrino", question: "A doença de Addison (insuficiência suprarrenal primária) resulta em:", options: ["Hiperplasia do córtex", "Destruição do córtex suprarrenal com deficiência de cortisol e aldosterona", "Tumor da medula", "Hipersecreção de cortisol"], correctIndex: 1, explanation: "A doença de Addison é causada por destruição autoimune (mais comum), infecciosa ou outras causas do córtex suprarrenal → déficit de cortisol (fraqueza, hipoglicemia) e aldosterona (hipotensão, hipercalemia)." },
  { id: 542, topic: "Sistema Endócrino", question: "As células lactotrofas da adeno-hipófise secretam:", options: ["GH", "Prolactina", "TSH", "LH"], correctIndex: 1, explanation: "Os lactotrofos são células acidófilas que secretam prolactina, essencial para a lactação. Sua secreção é tonicamente inibida pela dopamina hipotalâmica. Prolactinomas são os adenomas hipofisários mais comuns." },
  { id: 543, topic: "Sistema Endócrino", question: "O glucagon é produzido pelas células:", options: ["Beta", "Alfa das ilhotas de Langerhans", "Delta", "PP"], correctIndex: 1, explanation: "As células α estão na periferia das ilhotas e secretam glucagon, que aumenta a glicemia por glicogenólise e gliconeogênese hepáticas. Ação oposta à insulina." },
  { id: 544, topic: "Sistema Endócrino", question: "A somatostatina das ilhotas pancreáticas é produzida pelas células:", options: ["α", "β", "δ", "PP"], correctIndex: 2, explanation: "As células δ secretam somatostatina, que inibe localmente a secreção de insulina e glucagon (efeito parácrino), além de inibir secreções gastrointestinais. Também produzida no hipotálamo e trato GI." },
  { id: 545, topic: "Sistema Endócrino", question: "O hormônio antidiurético (ADH) é produzido nos núcleos:", options: ["Paraventricular apenas", "Supraóptico e paraventricular do hipotálamo", "Hipofisários anteriores", "Tálamo"], correctIndex: 1, explanation: "O ADH é sintetizado nos neurônios magnocelulares dos núcleos supraóptico (principal) e paraventricular do hipotálamo, transportado pelos axônios e armazenado/liberado pela neuro-hipófise." },
  { id: 546, topic: "Sistema Endócrino", question: "A síndrome de Cushing é causada por:", options: ["Deficiência de cortisol", "Excesso crônico de cortisol", "Deficiência de aldosterona", "Excesso de melatonina"], correctIndex: 1, explanation: "A síndrome de Cushing resulta de hipercortisolismo crônico: exógeno (iatrogênico, mais comum) ou endógeno (adenoma hipofisário/ACTH, adenoma suprarrenal, ectópico). Obesidade central, estrias, hiperglicemia, osteoporose." },
  { id: 547, topic: "Sistema Endócrino", question: "A acromegalia é causada por excesso de:", options: ["Prolactina", "GH na vida adulta", "ACTH", "TSH"], correctIndex: 1, explanation: "A acromegalia resulta de excesso de GH após fechamento das epífises (geralmente adenoma somatotrofo). Causa crescimento acral (mãos, pés, mandíbula), visceromegalia, diabetes e hipertensão." },
  { id: 548, topic: "Sistema Endócrino", question: "O hipotireoidismo congênito (cretinismo) causa:", options: ["Crescimento excessivo", "Retardo do desenvolvimento físico e neurológico", "Hipertireoidismo neonatal", "Sem consequências"], correctIndex: 1, explanation: "A deficiência de hormônios tireoidianos no período perinatal causa retardo mental irreversível, baixa estatura, fácies mixedematosa. O teste do pezinho detecta TSH elevado para tratamento precoce." },
  { id: 549, topic: "Sistema Endócrino", question: "Os corpos de Herring na neuro-hipófise são:", options: ["Células gliais", "Dilatações axonais contendo neurosecreção (ocitocina/ADH) acumulada", "Vasos sanguíneos", "Folículos"], correctIndex: 1, explanation: "Os corpos de Herring são dilatações nos axônios do trato hipotálamo-hipofisário onde grânulos de neurosecreção (ocitocina/ADH) se acumulam antes da liberação. Visíveis em HE como estruturas eosinofílicas." },
  { id: 550, topic: "Sistema Endócrino", question: "Os pituícitos são:", options: ["Neurônios secretores", "Células gliais de sustentação da neuro-hipófise", "Células endócrinas", "Macrófagos"], correctIndex: 1, explanation: "Os pituícitos são células gliais (semelhantes a astrócitos) que sustentam os axônios na neuro-hipófise. São as células mais abundantes da pars nervosa e regulam a liberação hormonal." },

  // =============================================
  // SISTEMA LINFÁTICO E IMUNOLÓGICO (551-575)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 551, topic: "Sistema Linfático e Imunológico", question: "Os órgãos linfáticos primários (centrais) são:", options: ["Linfonodos e baço", "Timo e medula óssea", "Tonsilas e placas de Peyer", "Baço e linfonodos"], correctIndex: 1, explanation: "Órgãos linfáticos primários: medula óssea (maturação de linfócitos B e produção de todas as células sanguíneas) e timo (maturação de linfócitos T). Nos secundários (linfonodos, baço, MALT) ocorre a resposta imune." },
  { id: 552, topic: "Sistema Linfático e Imunológico", question: "O timo é o local de maturação de:", options: ["Linfócitos B", "Linfócitos T", "Neutrófilos", "Monócitos"], correctIndex: 1, explanation: "No timo, progenitores T da medula óssea sofrem seleção positiva (córtex, reconhecem MHC próprio) e negativa (medula, eliminam autorreativos). Involui após puberdade, substituído por tecido adiposo." },
  { id: 553, topic: "Sistema Linfático e Imunológico", question: "Os corpúsculos de Hassall são encontrados na:", options: ["Córtex do timo", "Medula do timo", "Linfonodos", "Baço"], correctIndex: 1, explanation: "Os corpúsculos de Hassall são estruturas concêntricas de células epiteliais queratinizadas na medula tímica. Produzem TSLP (linfopoietina estromal tímica), envolvida na diferenciação de células T regulatórias." },
  { id: 554, topic: "Sistema Linfático e Imunológico", question: "Os linfonodos filtram:", options: ["Sangue arterial", "Linfa (fluido intersticial drenado)", "Urina", "Bile"], correctIndex: 1, explanation: "Os linfonodos são filtros da linfa: vasos linfáticos aferentes trazem linfa → seios subcapsular → cortical → medular → vasos eferentes (hilo). Antígenos são capturados e apresentados, ativando resposta imune." },
  { id: 555, topic: "Sistema Linfático e Imunológico", question: "O córtex externo do linfonodo contém:", options: ["Apenas zona T", "Folículos linfoides (linfócitos B), primários (sem centro germinativo) ou secundários (com centro germinativo)", "Apenas seios medulares", "Cordões de plasmócitos"], correctIndex: 1, explanation: "O córtex externo é a zona B: contém folículos primários (linfócitos B em repouso) e secundários (com centro germinativo ativo após estimulação antigênica → proliferação B, seleção, troca de classe)." },
  { id: 556, topic: "Sistema Linfático e Imunológico", question: "A zona paracortical do linfonodo é predominantemente ocupada por:", options: ["Linfócitos B", "Linfócitos T e células dendríticas interdigitantes", "Macrófagos apenas", "Células NK"], correctIndex: 1, explanation: "O paracórtex é a zona T: linfócitos T e células dendríticas interdigitantes (apresentação de antígeno). Contém vênulas de endotélio alto (HEV) por onde linfócitos circulantes entram no linfonodo." },
  { id: 557, topic: "Sistema Linfático e Imunológico", question: "As vênulas de endotélio alto (HEV) são encontradas no:", options: ["Córtex externo", "Paracórtex do linfonodo", "Seio subcapsular", "Baço"], correctIndex: 1, explanation: "As HEV são vênulas pós-capilares com endotélio cúbico alto no paracórtex. Expressam adressinas que permitem diapedese de linfócitos do sangue para o parênquima do linfonodo." },
  { id: 558, topic: "Sistema Linfático e Imunológico", question: "A polpa branca do baço é composta por:", options: ["Sinusoides e cordões de Billroth", "Bainha linfática periarteriolar (PALS, zona T) e folículos linfoides (zona B)", "Apenas eritrócitos", "Tecido conjuntivo denso"], correctIndex: 1, explanation: "A polpa branca: PALS (linfócitos T ao redor das artérias centrais) e folículos linfoides (B, na periferia). A zona marginal separa polpa branca da vermelha, onde APCs capturam antígenos sanguíneos." },
  { id: 559, topic: "Sistema Linfático e Imunológico", question: "A polpa vermelha do baço é responsável por:", options: ["Produção de anticorpos exclusivamente", "Filtração do sangue, remoção de eritrócitos senescentes e reserva de monócitos", "Maturação de linfócitos T", "Produção de plaquetas"], correctIndex: 1, explanation: "A polpa vermelha (cordões esplênicos de Billroth + sinusoides) filtra sangue, remove eritrócitos velhos/defeituosos por macrófagos, armazena plaquetas e monócitos, e permite hematopoiese em situações patológicas." },
  { id: 560, topic: "Sistema Linfático e Imunológico", question: "As tonsilas palatinas são revestidas por:", options: ["Epitélio simples cilíndrico", "Epitélio estratificado pavimentoso não-queratinizado com criptas profundas", "Epitélio respiratório", "Epitélio de transição"], correctIndex: 1, explanation: "As tonsilas palatinas possuem epitélio estratificado pavimentoso não-queratinizado invaginado formando criptas profundas. O tecido linfoide subjacente tem folículos com centros germinativos. Não possuem cápsula completa nem vasos aferentes." },
  { id: 561, topic: "Sistema Linfático e Imunológico", question: "A tonsila faríngea (adenoide) é revestida por:", options: ["Epitélio estratificado pavimentoso", "Epitélio pseudoestratificado cilíndrico ciliado (respiratório)", "Epitélio simples cúbico", "Epitélio de transição"], correctIndex: 1, explanation: "A tonsila faríngea localiza-se na parede posterior da nasofaringe e é revestida por epitélio respiratório. Sua hipertrofia (adenoide) causa obstrução nasal e respiração bucal em crianças." },
  { id: 562, topic: "Sistema Linfático e Imunológico", question: "O MALT (tecido linfático associado a mucosas) inclui:", options: ["Apenas o timo", "Placas de Peyer, tonsilas, BALT e tecido linfoide de mucosas diversas", "Apenas o baço", "Apenas linfonodos"], correctIndex: 1, explanation: "O MALT inclui: GALT (placas de Peyer, apêndice, tonsilas), BALT (brônquios), NALT (nasofaringe) e tecido linfoide de mucosas urinária e genital. Primeira linha de defesa imune adaptativa nas mucosas." },
  { id: 563, topic: "Sistema Linfático e Imunológico", question: "Os centros germinativos dos folículos linfoides são locais de:", options: ["Maturação de linfócitos T", "Proliferação de linfócitos B, hipermutação somática e seleção de células produtoras de anticorpos de alta afinidade", "Eritropoiese", "Maturação de monócitos"], correctIndex: 1, explanation: "Nos centros germinativos: linfócitos B ativados proliferam (centroblastos), sofrem hipermutação somática das imunoglobulinas, seleção por afinidade (FDC apresentam antígeno), troca de classe e diferenciam-se em plasmócitos ou células B de memória." },
  { id: 564, topic: "Sistema Linfático e Imunológico", question: "As células dendríticas foliculares (FDC) estão localizadas:", options: ["No timo", "Nos centros germinativos dos folículos linfoides", "Na polpa vermelha do baço", "Nos sinusoides hepáticos"], correctIndex: 1, explanation: "As FDC estão nos centros germinativos, retêm complexos antígeno-anticorpo em sua superfície por longos períodos, apresentando-os aos linfócitos B para seleção por afinidade (não são APCs clássicas)." },
  { id: 565, topic: "Sistema Linfático e Imunológico", question: "A barreira hematotímica é importante para:", options: ["Filtração da linfa", "Proteger os timócitos em desenvolvimento da exposição a antígenos sistêmicos", "Produção de eritrócitos", "Contração muscular"], correctIndex: 1, explanation: "A barreira hematotímica no córtex tímico (endotélio contínuo + lâmina basal + células epiteliais reticulares) impede que antígenos circulantes entrem no córtex e interfiram na seleção positiva dos timócitos." },
  { id: 566, topic: "Sistema Linfático e Imunológico", question: "A involução tímica após a puberdade resulta em:", options: ["Aumento de linfócitos T", "Substituição progressiva do parênquima por tecido adiposo, com diminuição da produção de novos linfócitos T", "Hiperplasia linfoide", "Fibrose sem alteração funcional"], correctIndex: 1, explanation: "A involução tímica fisiológica leva à substituição do parênquima por gordura, reduzindo a produção de linfócitos T naive. A imunidade é mantida pela expansão periférica do pool existente de células T." },
  { id: 567, topic: "Sistema Linfático e Imunológico", question: "O baço é o maior órgão linfoide:", options: ["Primário", "Secundário", "Terciário", "Central"], correctIndex: 1, explanation: "O baço é o maior órgão linfoide secundário. Filtra sangue (polpa vermelha), gera resposta imune a antígenos sanguíneos (polpa branca) e serve como reservatório de monócitos e plaquetas." },
  { id: 568, topic: "Sistema Linfático e Imunológico", question: "A esplenectomia aumenta o risco de infecção por:", options: ["Vírus apenas", "Bactérias encapsuladas (Streptococcus pneumoniae, Haemophilus influenzae, Neisseria meningitidis)", "Fungos apenas", "Nenhum microrganismo"], correctIndex: 1, explanation: "Sem baço, há deficiência na opsonização e clearance de bactérias encapsuladas (IgM, via alternativa do complemento, tuftsin). Risco de sepse fulminante pós-esplenectomia (OPSI). Vacinação preventiva é essencial." },
  { id: 569, topic: "Sistema Linfático e Imunológico", question: "Os plasmócitos são células diferenciadas que:", options: ["Fagocitam bactérias", "Produzem e secretam anticorpos (imunoglobulinas)", "Apresentam antígenos", "Destroem células infectadas"], correctIndex: 1, explanation: "Os plasmócitos são o estágio final de diferenciação dos linfócitos B. Possuem RER abundante (basofilia), núcleo excêntrico com cromatina em roda de carroça e zona de Golgi clara (arcoplasma). Produzem anticorpos." },
  { id: 570, topic: "Sistema Linfático e Imunológico", question: "As células NK (natural killer) atuam:", options: ["Produzindo anticorpos", "Destruindo células infectadas por vírus e células tumorais sem necessidade de sensibilização prévia", "Apresentando antígenos", "Produzindo histamina"], correctIndex: 1, explanation: "As células NK são linfócitos da imunidade inata que reconhecem e destroem células com MHC-I reduzido (infectadas, tumorais) através de grânulos com perforinas e granzimas, sem necessidade de ativação prévia." },
  { id: 571, topic: "Sistema Linfático e Imunológico", question: "A IgA secretora é produzida principalmente no:", options: ["Sangue", "MALT (tecido linfoide de mucosas), sendo transportada pelo componente secretor", "Timo", "Medula óssea"], correctIndex: 1, explanation: "A IgA dimérica é produzida por plasmócitos no MALT, liga-se ao receptor polimérico de Ig (pIgR) na membrana basolateral do epitélio, é transcitosada e liberada como IgA secretora (sIgA) com o componente secretor protetor." },
  { id: 572, topic: "Sistema Linfático e Imunológico", question: "Os linfonodos sentinelas são importantes porque:", options: ["São os maiores linfonodos", "São os primeiros linfonodos a receber drenagem linfática de um tumor, indicando metástase", "Produzem mais anticorpos", "São exclusivos do pescoço"], correctIndex: 1, explanation: "O linfonodo sentinela é o primeiro a receber drenagem linfática de um tumor primário. Sua biópsia (com corante vital ou radioisótopo) determina se há metástase, guiando a extensão da linfadenectomia." },
  { id: 573, topic: "Sistema Linfático e Imunológico", question: "A seleção negativa no timo elimina:", options: ["Linfócitos B autorreativos", "Timócitos que reagem fortemente contra antígenos próprios (prevenção de autoimunidade)", "Eritrócitos", "Neutrófilos"], correctIndex: 1, explanation: "Na medula tímica, células epiteliais medulares (expressando AIRE → antígenos teciduais) e dendríticas apresentam autoantígenos. Timócitos que reagem fortemente sofrem apoptose (seleção negativa → tolerância central)." },
  { id: 574, topic: "Sistema Linfático e Imunológico", question: "O ducto torácico drena a linfa para:", options: ["Veia cava inferior", "Junção da veia jugular interna esquerda com a veia subclávia esquerda", "Artéria aorta", "Veia porta"], correctIndex: 1, explanation: "O ducto torácico é o maior vaso linfático, drenando linfa de todo o corpo (exceto quadrante superior direito, drenado pelo ducto linfático direito) para o ângulo venoso jugulo-subclávio esquerdo." },
  { id: 575, topic: "Sistema Linfático e Imunológico", question: "O gene AIRE (autoimmune regulator) é expresso em:", options: ["Linfonodos", "Células epiteliais medulares do timo", "Baço", "Medula óssea"], correctIndex: 1, explanation: "O AIRE promove expressão ectópica de antígenos tecido-específicos (insulina, tireoglobulina etc.) pelas células epiteliais medulares tímicas, permitindo seleção negativa de timócitos autorreativos. Mutações causam APECED (síndrome autoimune poliendocrinopatia)." },

  // =============================================
  // SISTEMA REPRODUTOR MASCULINO (576-600)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 576, topic: "Sistema Reprodutor Masculino", question: "O epitélio seminífero dos túbulos seminíferos contém:", options: ["Apenas células de Sertoli", "Células de Sertoli e células da linhagem espermatogênica em diferentes estágios", "Apenas espermatozoides", "Células de Leydig"], correctIndex: 1, explanation: "O epitélio seminífero contém células de Sertoli (suporte, barreira hematotesticular, nutrição) e células germinativas em progressão: espermatogônias → espermatócitos I → espermatócitos II → espermátides → espermatozoides." },
  { id: 577, topic: "Sistema Reprodutor Masculino", question: "As células de Leydig estão localizadas:", options: ["No epitélio seminífero", "No tecido intersticial entre os túbulos seminíferos", "No epidídimo", "Na próstata"], correctIndex: 1, explanation: "As células de Leydig são células endócrinas intersticiais que produzem testosterona sob estímulo do LH. São grandes, poliédricas, acidófilas, com REL abundante e cristais de Reinke." },
  { id: 578, topic: "Sistema Reprodutor Masculino", question: "A barreira hematotesticular é formada por:", options: ["Endotélio capilar apenas", "Junções tight (zônulas de oclusão) entre células de Sertoli adjacentes", "Cápsula albugínea", "Células de Leydig"], correctIndex: 1, explanation: "As tight junctions entre células de Sertoli dividem o epitélio em compartimento basal (espermatogônias) e adluminal (espermatócitos/espermátides), protegendo células germinativas haploides do sistema imune." },
  { id: 579, topic: "Sistema Reprodutor Masculino", question: "As células de Sertoli têm todas as seguintes funções, EXCETO:", options: ["Sustentação e nutrição das células germinativas", "Fagocitose de corpos residuais", "Produção de testosterona", "Secreção de ABP (androgen-binding protein) e inibina"], correctIndex: 2, explanation: "As células de Sertoli sustentam, nutrem e protegem as células germinativas, secretam ABP, inibina, AMH e fluido. A testosterona é produzida pelas células de Leydig (intersticiais), não pelas de Sertoli." },
  { id: 580, topic: "Sistema Reprodutor Masculino", question: "A espermiogênese é o processo de:", options: ["Multiplicação das espermatogônias", "Diferenciação de espermátides redondas em espermatozoides maduros (sem divisão celular)", "Meiose dos espermatócitos", "Mitose das células de Sertoli"], correctIndex: 1, explanation: "A espermiogênese transforma espermátides (haploides, redondas) em espermatozoides: formação do acrossoma (Golgi), condensação nuclear, desenvolvimento do flagelo (centríolo), perda citoplasmática. Sem divisão celular." },
  { id: 581, topic: "Sistema Reprodutor Masculino", question: "O epidídimo é revestido por:", options: ["Epitélio simples cúbico", "Epitélio pseudoestratificado cilíndrico com estereocílios", "Epitélio de transição", "Epitélio estratificado pavimentoso"], correctIndex: 1, explanation: "O epidídimo possui epitélio pseudoestratificado com estereocílios (microvilosidades longas) que aumentam a superfície de absorção. Local de maturação, armazenamento e transporte dos espermatozoides." },
  { id: 582, topic: "Sistema Reprodutor Masculino", question: "A próstata é composta por:", options: ["Apenas músculo liso", "Glândulas tubuloalveolares ramificadas, estroma fibromuscular e secreção prostática", "Apenas tecido conjuntivo", "Epitélio de transição"], correctIndex: 1, explanation: "A próstata possui 30-50 glândulas tubuloalveolares com epitélio simples cilíndrico/pseudoestratificado, imersas em estroma fibromuscular. Secreta PSA, fosfatase ácida e zinco. Concreções prostáticas (corpora amylacea) são comuns." },
  { id: 583, topic: "Sistema Reprodutor Masculino", question: "A vesícula seminal é caracterizada por:", options: ["Produção de espermatozoides", "Mucosa pregueada com epitélio pseudoestratificado, secretando frutose e prostaglandinas", "Armazenamento de urina", "Produção de testosterona"], correctIndex: 1, explanation: "As vesículas seminais secretam ~70% do volume do sêmen: fluido alcalino rico em frutose (energia para espermatozoides), prostaglandinas (motilidade uterina) e semenogelinas (coagulação do sêmen)." },
  { id: 584, topic: "Sistema Reprodutor Masculino", question: "A túnica albugínea do testículo é:", options: ["Mucosa", "Cápsula de tecido conjuntivo denso fibroso que envolve o testículo", "Epitélio seminífero", "Camada muscular"], correctIndex: 1, explanation: "A albugínea é uma cápsula espessa de tecido conjuntivo denso que envolve o testículo. Emite septos internos dividindo-o em ~250 lóbulos, cada um com 1-4 túbulos seminíferos contorcidos." },
  { id: 585, topic: "Sistema Reprodutor Masculino", question: "O ducto deferente possui parede muscular:", options: ["Fina com uma camada", "Muito espessa com três camadas de músculo liso (interna longitudinal, média circular, externa longitudinal)", "Sem músculo liso", "Com músculo estriado"], correctIndex: 1, explanation: "O ducto deferente tem parede muscular muito espessa (três camadas de músculo liso), lúmen estreito e epitélio pseudoestratificado com estereocílios. A contração vigorosa durante a ejaculação propele os espermatozoides." },
  { id: 586, topic: "Sistema Reprodutor Masculino", question: "A hiperplasia prostática benigna (HPB) ocorre mais comumente na:", options: ["Zona periférica", "Zona de transição (periuretral)", "Zona central", "Cápsula"], correctIndex: 1, explanation: "A HPB desenvolve-se na zona de transição (periuretral), causando compressão da uretra prostática → sintomas obstrutivos (hesitação, jato fraco, noctúria). O carcinoma prostático origina-se predominantemente na zona periférica." },
  { id: 587, topic: "Sistema Reprodutor Masculino", question: "O acrossoma do espermatozoide contém:", options: ["DNA", "Enzimas hidrolíticas (hialuronidase, acrosina) necessárias para a penetração na zona pelúcida", "Mitocôndrias", "Flagelina"], correctIndex: 1, explanation: "O acrossoma é uma vesícula derivada do Golgi que recobre o núcleo do espermatozoide. Contém hialuronidase, acrosina e outras proteases liberadas na reação acrossômica para penetrar a zona pelúcida do ovócito." },
  { id: 588, topic: "Sistema Reprodutor Masculino", question: "As glândulas bulbouretrais (de Cowper) secretam:", options: ["Espermatozoides", "Muco pré-ejaculatório que lubrifica a uretra e neutraliza acidez urinária residual", "Testosterona", "Frutose"], correctIndex: 1, explanation: "As glândulas de Cowper são glândulas tubuloalveolares mucosas na membrana perineal, secretando muco pré-ejaculatório que lubrifica a uretra peniana e neutraliza a acidez da urina residual." },
  { id: 589, topic: "Sistema Reprodutor Masculino", question: "A temperatura ideal para a espermatogênese é:", options: ["37°C", "34-35°C (2-3°C abaixo da temperatura corporal)", "40°C", "30°C"], correctIndex: 1, explanation: "A espermatogênese requer temperatura ~2-3°C abaixo da corporal, garantida pela posição escrotal, plexo pampiniforme (troca de calor contracorrente), músculo cremaster e dartos. Criptorquidia causa infertilidade." },
  { id: 590, topic: "Sistema Reprodutor Masculino", question: "Os túbulos retos conectam:", options: ["Epidídimo ao ducto deferente", "Túbulos seminíferos à rede testicular (rete testis)", "Próstata à uretra", "Vesículas seminais ao ducto ejaculatório"], correctIndex: 1, explanation: "Os túbulos retos (revestidos por células de Sertoli → epitélio simples cúbico) conectam os túbulos seminíferos contorcidos à rete testis. A rete testis, por sua vez, conecta-se ao epidídimo via dúctulos eferentes." },
  { id: 591, topic: "Sistema Reprodutor Masculino", question: "Os dúctulos eferentes são caracterizados por:", options: ["Epitélio uniforme", "Epitélio com alternância de células ciliadas altas e células não-ciliadas baixas (aspecto em festão)", "Epitélio de transição", "Epitélio estratificado pavimentoso"], correctIndex: 1, explanation: "Os dúctulos eferentes possuem epitélio pseudoestratificado com alternância de células ciliadas (altas, movem espermatozoides) e não-ciliadas absortivas (baixas), dando aspecto em festão (ondulado) ao lúmen." },
  { id: 592, topic: "Sistema Reprodutor Masculino", question: "A FSH atua principalmente nas:", options: ["Células de Leydig", "Células de Sertoli, estimulando a espermatogênese e secreção de ABP e inibina", "Células prostáticas", "Vesículas seminais"], correctIndex: 1, explanation: "A FSH liga-se aos receptores nas células de Sertoli, estimulando produção de ABP (mantém testosterona alta no túbulo), inibina (feedback negativo sobre FSH) e fatores que apoiam a espermatogênese." },
  { id: 593, topic: "Sistema Reprodutor Masculino", question: "O LH estimula as células de Leydig a produzir:", options: ["Inibina", "Testosterona", "FSH", "Estrogênio apenas"], correctIndex: 1, explanation: "O LH (hormônio luteinizante) liga-se aos receptores das células de Leydig, ativando a esteroidogênese: colesterol → pregnenolona → testosterona. A testosterona em altas concentrações locais é essencial para a espermatogênese." },
  { id: 594, topic: "Sistema Reprodutor Masculino", question: "O pênis possui três corpos eréteis:", options: ["Dois corpos esponjosos e um cavernoso", "Dois corpos cavernosos e um corpo esponjoso (que envolve a uretra)", "Três corpos cavernosos", "Três corpos esponjosos"], correctIndex: 1, explanation: "O pênis possui dois corpos cavernosos (dorsais, envolvidos pela túnica albugínea espessa) e um corpo esponjoso (ventral, envolve a uretra peniana, glande na extremidade). Ereção por ingurgitamento sanguíneo dos espaços sinusoidais." },
  { id: 595, topic: "Sistema Reprodutor Masculino", question: "A capacitação dos espermatozoides ocorre:", options: ["No testículo", "No trato reprodutor feminino", "No epidídimo", "Na próstata"], correctIndex: 1, explanation: "A capacitação é uma série de modificações bioquímicas que os espermatozoides sofrem no trato feminino (útero/tuba): remoção de proteínas de superfície, hiperativação da motilidade e preparação para a reação acrossômica." },
  { id: 596, topic: "Sistema Reprodutor Masculino", question: "Os cristais de Reinke são encontrados nas:", options: ["Células de Sertoli", "Células de Leydig", "Espermatogônias", "Células prostáticas"], correctIndex: 1, explanation: "Os cristais de Reinke são inclusões citoplasmáticas cristaloides específicas das células de Leydig, compostas por proteínas. Sua função é desconhecida. Aumentam com a idade e são úteis para identificação histológica." },
  { id: 597, topic: "Sistema Reprodutor Masculino", question: "A meiose I dos espermatócitos primários resulta em:", options: ["Células diploides", "Espermatócitos secundários haploides (n)", "Espermatozoides maduros", "Espermatogônias tipo B"], correctIndex: 1, explanation: "A meiose I (reducional) do espermatócito primário (2n, 4c) gera dois espermatócitos secundários (n, 2c). A meiose II (equacional) divide cada um em duas espermátides (n, c). Total: 4 espermátides por espermatócito I." },
  { id: 598, topic: "Sistema Reprodutor Masculino", question: "A rete testis está localizada:", options: ["Na albugínea lateral", "No mediastino do testículo (espessamento da albugínea no polo posterior)", "Na cabeça do epidídimo", "Na próstata"], correctIndex: 1, explanation: "A rete testis é uma rede de canais anastomosados no mediastino testicular, revestidos por epitélio simples cúbico a cilíndrico baixo. Conecta túbulos retos aos dúctulos eferentes." },
  { id: 599, topic: "Sistema Reprodutor Masculino", question: "As corpora amylacea na próstata são:", options: ["Espermatozoides", "Concreções laminadas de glicoproteínas no lúmen glandular, aumentam com a idade", "Células tumorais", "Fibras musculares"], correctIndex: 1, explanation: "Os corpora amylacea são concreções eosinofílicas laminadas no lúmen das glândulas prostáticas, formados por precipitação de secreção. Aumentam com a idade e podem calcificar. São achados normais." },
  { id: 600, topic: "Sistema Reprodutor Masculino", question: "A vasectomia interrompe o transporte de espermatozoides por secção do:", options: ["Epidídimo", "Ducto deferente", "Ducto ejaculatório", "Uretra"], correctIndex: 1, explanation: "A vasectomia é a secção bilateral do ducto deferente, impedindo a passagem dos espermatozoides do epidídimo para o ducto ejaculatório. O sêmen continua sendo produzido (vesículas seminais e próstata) mas sem espermatozoides." },

  // =============================================
  // SISTEMA REPRODUTOR FEMININO (601-625)
  // Fontes: Junqueira & Carneiro, 16ª ed.; Ross & Pawlina, 8th ed.; UpToDate
  // =============================================
  { id: 601, topic: "Sistema Reprodutor Feminino", question: "O córtex ovariano contém:", options: ["Apenas corpo lúteo", "Folículos ovarianos em diferentes estágios de desenvolvimento", "Apenas óvulos maduros", "Apenas estroma"], correctIndex: 1, explanation: "O córtex ovariano contém folículos em estágios variados: primordiais, primários, secundários (antrais) e maduros (de Graaf), além de corpos lúteos, corpos albicans e folículos atrésicos." },
  { id: 602, topic: "Sistema Reprodutor Feminino", question: "O folículo primordial é composto por:", options: ["Ovócito com várias camadas de células granulosas", "Ovócito I circundado por uma camada de células foliculares pavimentosas", "Ovócito II com zona pelúcida", "Antro preenchido por líquido"], correctIndex: 1, explanation: "O folículo primordial possui um ovócito primário (parado em diplóteno da meiose I) circundado por uma única camada de células foliculares pavimentosas. Formado durante a vida fetal, constitui a reserva ovariana." },
  { id: 603, topic: "Sistema Reprodutor Feminino", question: "A zona pelúcida aparece em qual estágio folicular?", options: ["Folículo primordial", "Folículo primário (entre ovócito e células da granulosa)", "Corpo lúteo", "Corpo albicans"], correctIndex: 1, explanation: "A zona pelúcida (glicoproteínas ZP1-4) surge no folículo primário, entre o ovócito e as células da granulosa (agora cúbicas). ZP3 é o receptor espécie-específico para ligação do espermatozoide e indução da reação acrossômica." },
  { id: 604, topic: "Sistema Reprodutor Feminino", question: "O antro folicular é uma característica do:", options: ["Folículo primordial", "Folículo primário", "Folículo secundário (antral)", "Corpo lúteo"], correctIndex: 2, explanation: "O folículo secundário (antral) desenvolve uma cavidade preenchida por líquido folicular (antro). As células da granulosa diferenciam-se em cumulus oophorus (rodeiam o ovócito) e granulosa mural." },
  { id: 605, topic: "Sistema Reprodutor Feminino", question: "O corpo lúteo é formado após:", options: ["A menstruação", "A ovulação, a partir das células da granulosa e da teca interna", "A fecundação apenas", "A menopausa"], correctIndex: 1, explanation: "Após a ovulação, o folículo colapsa e as células da granulosa (luteínicas granulosas → progesterona) e da teca interna (luteínicas tecais → andrógenos) formam o corpo lúteo. Secreta progesterona e estrogênio." },
  { id: 606, topic: "Sistema Reprodutor Feminino", question: "O corpo albicans é:", options: ["O folículo dominante", "A cicatriz de tecido conjuntivo resultante da degeneração do corpo lúteo", "O ovócito degenerado", "O antro folicular"], correctIndex: 1, explanation: "O corpo albicans é a cicatriz fibrosa/hialina que resta após a involução do corpo lúteo (luteólise). Se não houver gravidez, o corpo lúteo degenera em ~14 dias; se houver, é mantido pelo hCG até ~12 semanas." },
  { id: 607, topic: "Sistema Reprodutor Feminino", question: "A tuba uterina (trompa de Falópio) é revestida por:", options: ["Epitélio estratificado pavimentoso", "Epitélio simples cilíndrico com células ciliadas e secretoras (peg cells)", "Epitélio de transição", "Epitélio pseudoestratificado com estereocílios"], correctIndex: 1, explanation: "A tuba uterina possui epitélio simples cilíndrico com células ciliadas (movem o ovócito em direção ao útero) e células secretoras/peg cells (nutrem ovócito e espermatozoides). Mucosa altamente pregueada, especialmente na ampola." },
  { id: 608, topic: "Sistema Reprodutor Feminino", question: "A fecundação normalmente ocorre na:", options: ["Cavidade uterina", "Ampola da tuba uterina", "Istmo da tuba uterina", "Ovário"], correctIndex: 1, explanation: "A fecundação ocorre na ampola da tuba uterina, a porção mais larga e com pregas mucosas mais complexas. O embrião em clivagem é transportado para o útero em ~3-4 dias pelos cílios e peristaltismo tubário." },
  { id: 609, topic: "Sistema Reprodutor Feminino", question: "O endométrio é composto por:", options: ["Apenas epitélio de superfície", "Epitélio simples cilíndrico, glândulas endometriais e estroma endometrial com vasos espiralados", "Apenas músculo liso", "Epitélio estratificado pavimentoso"], correctIndex: 1, explanation: "O endométrio possui: epitélio simples cilíndrico de superfície, glândulas tubulares simples (produzem glicogênio e muco), estroma rico em células conjuntivas deciduais e artérias espiraladas (sensíveis a hormônios)." },
  { id: 610, topic: "Sistema Reprodutor Feminino", question: "As camadas do endométrio são:", options: ["Apenas camada basal", "Camada funcional (superficial, descama na menstruação) e camada basal (profunda, regenera o endométrio)", "Apenas camada funcional", "Camada muscular e glandular"], correctIndex: 1, explanation: "A camada funcional (2/3 superiores) descama na menstruação (necrose por vasoconstrição das artérias espiraladas). A camada basal (1/3 inferior, irrigada por artérias retas) contém a porção profunda das glândulas que regenera o endométrio." },
  { id: 611, topic: "Sistema Reprodutor Feminino", question: "O miométrio é composto por:", options: ["Tecido conjuntivo denso", "Espessas camadas de músculo liso (a camada mais espessa da parede uterina)", "Epitélio glandular", "Cartilagem"], correctIndex: 1, explanation: "O miométrio é a camada mais espessa do útero, composta por feixes de músculo liso em várias direções (4 camadas), vasos sanguíneos e tecido conjuntivo. Hipertrofia e hiperplasia durante a gravidez." },
  { id: 612, topic: "Sistema Reprodutor Feminino", question: "O colo uterino (cérvix) possui duas regiões com epitélios distintos:", options: ["Ambas com epitélio cúbico", "Ectocérvix (estratificado pavimentoso) e endocérvix (simples cilíndrico mucossecretor)", "Ambas com epitélio cilíndrico", "Ambas com epitélio de transição"], correctIndex: 1, explanation: "O ectocérvix é revestido por epitélio estratificado pavimentoso não-queratinizado. O endocérvix possui epitélio simples cilíndrico mucossecretor. A junção escamocolunar (JEC) é o local mais vulnerável à displasia/neoplasia cervical." },
  { id: 613, topic: "Sistema Reprodutor Feminino", question: "A zona de transformação do colo uterino é clinicamente importante porque:", options: ["É a região mais espessa", "É o local onde ocorre metaplasia escamosa e a maioria dos carcinomas cervicais se origina", "É o local de implantação embrionária", "Produz muco cervical"], correctIndex: 1, explanation: "A zona de transformação é a região onde epitélio colunar é substituído por epitélio escamoso metaplásico. É o alvo do HPV e onde se originam a maioria das displasias e carcinomas cervicais. Alvo do Papanicolaou." },
  { id: 614, topic: "Sistema Reprodutor Feminino", question: "A vagina é revestida por:", options: ["Epitélio simples cilíndrico", "Epitélio estratificado pavimentoso não-queratinizado, sem glândulas", "Epitélio de transição", "Epitélio pseudoestratificado"], correctIndex: 1, explanation: "A vagina possui epitélio estratificado pavimentoso não-queratinizado (espesso, responsivo a estrogênio, com glicogênio → lactobacilos → pH ácido). Não possui glândulas; a lubrificação é por transudato e secreção cervical." },
  { id: 615, topic: "Sistema Reprodutor Feminino", question: "A glândula mamária em lactação é classificada como:", options: ["Tubular simples", "Tubuloalveolar composta apócrina", "Acinosa simples", "Holocrina"], correctIndex: 1, explanation: "A glândula mamária é tubuloalveolar composta com secreção apócrina (lipídios) e merócrina (proteínas, lactose). Na lactação, os alvéolos se expandem com células secretoras e células mioepiteliais (ejeção do leite)." },
  { id: 616, topic: "Sistema Reprodutor Feminino", question: "A prolactina estimula:", options: ["A ovulação", "A produção de leite pelos alvéolos mamários", "A contração uterina", "A reabsorção óssea"], correctIndex: 1, explanation: "A prolactina (adeno-hipófise) estimula a síntese de leite nos alvéolos mamários. A ocitocina (neuro-hipófise) estimula a contração das células mioepiteliais, causando ejeção do leite (reflexo de descida)." },
  { id: 617, topic: "Sistema Reprodutor Feminino", question: "Na fase proliferativa do ciclo endometrial:", options: ["O endométrio descama", "As glândulas são retas e o estroma prolifera sob ação do estrogênio", "As glândulas são tortuosas e secretoras", "Ocorre decidualização"], correctIndex: 1, explanation: "Na fase proliferativa (folicular, dias ~5-14), o estrogênio do folículo ovariano estimula proliferação do epitélio, glândulas (retas, mitoses), estroma e vasos. O endométrio espessa de ~1mm para ~3-5mm." },
  { id: 618, topic: "Sistema Reprodutor Feminino", question: "Na fase secretora do ciclo endometrial:", options: ["O endométrio é fino", "As glândulas tornam-se tortuosas, secretam glicogênio, e as artérias espiraladas se desenvolvem sob ação da progesterona", "Ocorre menstruação", "Há atrofia do estroma"], correctIndex: 1, explanation: "Na fase secretora (luteal, dias ~15-28), a progesterona do corpo lúteo estimula glândulas (tortuosas, secreção de glicogênio e glicoproteínas), edema estromal, desenvolvimento de artérias espiraladas e decidualização." },
  { id: 619, topic: "Sistema Reprodutor Feminino", question: "A menstruação é causada por:", options: ["Excesso de progesterona", "Queda dos níveis de progesterona e estrogênio por involução do corpo lúteo → vasoconstrição das artérias espiraladas → necrose e descamação da camada funcional", "Aumento de FSH", "Infecção"], correctIndex: 1, explanation: "Sem gravidez, o corpo lúteo involui → queda de progesterona/estrogênio → vasoconstrição das artérias espiraladas → isquemia → necrose e descamação da camada funcional do endométrio = menstruação (dias 1-5)." },
  { id: 620, topic: "Sistema Reprodutor Feminino", question: "As células da teca interna do folículo ovariano produzem:", options: ["Progesterona", "Andrógenos (convertidos em estrogênio pelas células da granulosa pela aromatase)", "Ocitocina", "Inibina"], correctIndex: 1, explanation: "A teca interna (vascularizada, células poliédricas com REL) produz andrógenos sob estímulo de LH. Esses andrógenos são convertidos em estrogênio (estradiol) pela aromatase nas células da granulosa (estimuladas por FSH)." },
  { id: 621, topic: "Sistema Reprodutor Feminino", question: "A placenta é composta por:", options: ["Apenas tecido materno", "Componente fetal (córion viloso) e componente materno (decídua basal)", "Apenas tecido fetal", "Cartilagem"], correctIndex: 1, explanation: "A placenta possui componente fetal (vilosidades coriônicas com vasos fetais, trofoblasto citotrofoblasto/sinciciotrofoblasto) e materno (decídua basal). A barreira placentária permite trocas materno-fetais." },
  { id: 622, topic: "Sistema Reprodutor Feminino", question: "O sinciciotrofoblasto é:", options: ["Uma camada de células individuais", "Uma camada multinucleada contínua sem limites celulares que cobre as vilosidades coriônicas", "Tecido conjuntivo fetal", "Endotélio materno"], correctIndex: 1, explanation: "O sinciciotrofoblasto é um sincício multinucleado (sem membranas celulares individuais) que reveste externamente as vilosidades. É a principal barreira de troca, produz hCG, hPL, progesterona e estrogênio." },
  { id: 623, topic: "Sistema Reprodutor Feminino", question: "A atresia folicular é:", options: ["Maturação folicular", "Degeneração e reabsorção de folículos ovarianos que não ovularam", "Ovulação", "Formação do corpo lúteo"], correctIndex: 1, explanation: "A maioria dos folículos (~99,9%) sofre atresia em diferentes estágios de desenvolvimento. Dos ~1-2 milhões de folículos ao nascimento, apenas ~400 ovulam durante a vida reprodutiva. A atresia envolve apoptose do ovócito e células foliculares." },
  { id: 624, topic: "Sistema Reprodutor Feminino", question: "O exame de Papanicolaou (citologia cervicovaginal) tem como objetivo:", options: ["Detectar infecções urinárias", "Rastreamento de displasia e carcinoma cervical através da análise citológica de células esfoliadas", "Avaliar fertilidade", "Diagnosticar endometriose"], correctIndex: 1, explanation: "O Papanicolaou coleta células da ectocérvix e JEC/endocérvix para detecção de atipias celulares (LSIL, HSIL, carcinoma). Rastreamento eficaz que reduziu drasticamente a mortalidade por carcinoma cervical." },
  { id: 625, topic: "Sistema Reprodutor Feminino", question: "A endometriose é definida como:", options: ["Infecção do endométrio", "Presença de tecido endometrial (glândulas e estroma) fora da cavidade uterina", "Hiperplasia endometrial", "Atrofia endometrial"], correctIndex: 1, explanation: "A endometriose é a presença ectópica de glândulas e estroma endometriais (ovários, peritônio, ligamentos) que respondem a hormônios → sangramento cíclico, inflamação, aderências, dor pélvica e infertilidade." },
];
